function normalizeMilstdUniqueId(value = "") {
  const match = String(value || "").trim().match(/^(\d{8})/);
  return match ? match[1] : "";
}

function getPreferredMilstdSymbolEntryByBaseUniqueId(baseUniqueId = "", affiliation = "friendly") {
  const normalized = normalizeTacticalAffiliation(affiliation);
  const bucket = MILSTD_SYMBOL_VARIANTS_BY_BASE_UNIQUE_ID.get(String(baseUniqueId || "").trim());
  if (!bucket) return null;
  return bucket.byAffiliation.get(normalized)
    || bucket.byAffiliation.get("friendly")
    || bucket.byAffiliation.get("unknown")
    || bucket.defaultEntry
    || bucket.entries[0]
    || null;
}

function cleanMilstdUnitLabel(label = "") {
  return String(label || "")
    .replace(/\s*:\s*(Friend|Hostile|Neutral|Unknown)\s*$/i, "")
    .replace(/\s*:\s*Original\s*$/i, "")
    .trim();
}

function milstdUnitEntryAllowsEchelon(entry = null) {
  if (!entry) return true;
  const familyKey = String(entry.familyKey || "");
  const category = String(entry.category || "");
  const searchText = String(entry.searchText || "");
  if (familyKey === "space" || familyKey === "cyberspace") return false;
  if (searchText.includes("land equipment") || searchText.includes("full_octagon")) return false;
  if (category.toLowerCase().includes("equipment")) return false;
  return true;
}

function buildMilstdUnitCatalog() {
  const byUniqueId = new Map();
  for (const entry of MILSTD_SYMBOL_CATALOG) {
    if (String(entry?.objectClass || "") !== "unit") continue;
    if (shouldRenderStandaloneMilstd(entry)) continue;
    if (!hasRenderableMilstdAssetPath(entry)) continue;
    const baseUniqueId = normalizeMilstdUniqueId(entry?.uniqueId || entry?.id || "");
    if (!baseUniqueId) continue;
    const label = cleanMilstdUnitLabel(entry.label || baseUniqueId);
    if (!label) continue;
    const current = byUniqueId.get(baseUniqueId);
    const candidate = {
      id: baseUniqueId,
      label,
      group: `${entry.familyLabel || "Other"} - ${entry.category || "Uncategorized"}`,
      category: entry.category || "Uncategorized",
      familyKey: entry.familyKey || "other",
      familyLabel: entry.familyLabel || "Other",
      domain: normalizeTacticalDomain(entry.domain || "ground"),
      objectClass: entry.objectClass || "unit",
      milstdCatalogId: entry.id,
      symbolUniqueId: baseUniqueId,
      legacySidc: entry.legacySidc || "",
      echelonAllowed: milstdUnitEntryAllowsEchelon(entry),
    };
    if (!current || /friend/i.test(entry.label || "") || !/friend/i.test(current.milstdCatalogId || "")) {
      byUniqueId.set(baseUniqueId, candidate);
    }
  }
  return [...byUniqueId.values()].sort((a, b) => {
    const familyCmp = String(a.familyLabel || "").localeCompare(String(b.familyLabel || ""));
    if (familyCmp !== 0) return familyCmp;
    const groupCmp = String(a.group || "").localeCompare(String(b.group || ""));
    if (groupCmp !== 0) return groupCmp;
    return String(a.label || "").localeCompare(String(b.label || ""));
  });
}

function getMilstdSymbolCatalogEntry(value = null) {
  if (!value) return null;
  if (typeof value === "string") {
    const text = value.trim();
    const legacySidc = isMilstdLegacySidc(text) ? text.toUpperCase() : "";
    const sidc20 = isMilstdSidc20(text) ? text : "";
    const baseUniqueId = sidc20 ? extractMilstdUniqueIdFromSidc(sidc20) : normalizeMilstdUniqueId(text);
    return MILSTD_SYMBOL_BY_ID.get(text)
      || MILSTD_SYMBOL_BY_UNIQUE_ID.get(text)
      || (legacySidc ? MILSTD_SYMBOL_BY_LEGACY_SIDC.get(legacySidc) : null)
      || (sidc20 ? getPreferredMilstdSymbolEntryByBaseUniqueId(baseUniqueId, deriveTacticalAffiliationFromMilstdSidc(sidc20, "friendly")) : null)
      || getPreferredMilstdSymbolEntryByBaseUniqueId(baseUniqueId)
      || null;
  }
  const detail = value?.detail && typeof value.detail === "object" ? value.detail : {};
  const explicitSidc = String(value?.sidc || detail?.milsymId || "").trim();
  const id = String(value?.id || detail.milsymCatalogId || "").trim();
  const sidc20 = isMilstdSidc20(explicitSidc) ? explicitSidc : "";
  const uniqueId = String(
    value?.uniqueId
    || value?.symbolUniqueId
    || value?.catalogId
    || value?.unitType
    || detail.milsymUniqueId
    || extractMilstdUniqueIdFromSidc(explicitSidc)
    || ""
  ).trim();
  const baseUniqueId = normalizeMilstdUniqueId(uniqueId || id || extractMilstdUniqueIdFromSidc(explicitSidc));
  const legacySidc = String(
    value?.legacySidc
    || value?.sidcLegacy
    || detail.milsymLegacyId
    || (isMilstdLegacySidc(explicitSidc) ? explicitSidc : "")
    || ""
  ).trim().toUpperCase();
  return (id ? MILSTD_SYMBOL_BY_ID.get(id) : null)
    || (uniqueId ? MILSTD_SYMBOL_BY_UNIQUE_ID.get(uniqueId) : null)
    || (legacySidc ? MILSTD_SYMBOL_BY_LEGACY_SIDC.get(legacySidc) : null)
    || (sidc20 ? getPreferredMilstdSymbolEntryByBaseUniqueId(baseUniqueId, deriveTacticalAffiliationFromMilstdSidc(sidc20, value?.affiliation || detail?.affiliation || "friendly")) : null)
    || getPreferredMilstdSymbolEntryByBaseUniqueId(baseUniqueId, value?.affiliation || detail?.affiliation || "friendly")
    || null;
}

function isMilstdLegacySidc(value = "") {
  return /^[A-Z0-9_*\-]{15}$/i.test(String(value || "").trim());
}

function isMilstdSidc20(value = "") {
  return /^\d{20}$/.test(String(value || "").trim());
}

function extractMilstdUniqueIdFromSidc(value = "") {
  const text = String(value || "").trim();
  if (isMilstdSidc20(text)) {
    return `${text.slice(4, 6)}${text.slice(10, 16)}`;
  }
  const match = getMilstdSymbolCatalogEntry(text);
  return normalizeMilstdUniqueId(match?.uniqueId || match?.id || "");
}

function buildMilstdSidc(uniqueId = "", affiliation = "friendly", size = "") {
  const normalizedUniqueId = normalizeMilstdUniqueId(uniqueId);
  if (!/^\d{8}$/.test(normalizedUniqueId)) {
    return "";
  }
  const standardIdentity = MILSTD_STANDARD_IDENTITY_CODES[normalizeTacticalAffiliation(affiliation)] || MILSTD_STANDARD_IDENTITY_CODES.unknown;
  const echelonCode = MILSTD_ECHELON_CODES[String(size || "").trim()] || "00";
  const amplifierGroup = echelonCode.charAt(0) || "0";
  const amplifier = echelonCode.charAt(1) || "0";
  return `100${standardIdentity}${normalizedUniqueId.slice(0, 2)}00${amplifierGroup}${amplifier}${normalizedUniqueId.slice(2)}0000`;
}

function deriveTacticalAffiliationFromMilstdSidc(value = "", fallback = "friendly") {
  const text = String(value || "").trim();
  if (isMilstdSidc20(text)) {
    return MILSTD_STANDARD_IDENTITY_BY_CODE[text.charAt(3)] || normalizeTacticalAffiliation(fallback);
  }
  const legacy = text.toUpperCase();
  if (legacy.startsWith("S")) {
    const code = legacy.charAt(1);
    if (code === "F") return "friendly";
    if (code === "H") return "hostile";
    if (code === "N") return "neutral";
    if (code === "U") return "unknown";
  }
  return normalizeTacticalAffiliation(fallback);
}

function getCotAffiliationCode(affiliation = "friendly") {
  const aff = normalizeTacticalAffiliation(affiliation);
  if (aff === "friendly") return "f";
  if (aff === "hostile") return "h";
  if (aff === "neutral") return "n";
  return "u";
}

function buildCotTypeFromMilstdLegacySidc(legacySidc = "", affiliation = "friendly") {
  const legacy = String(legacySidc || "").trim().toUpperCase();
  if (!isMilstdLegacySidc(legacy) || !legacy.startsWith("S")) {
    return "";
  }
  const dimension = legacy.charAt(2);
  if (!/^[A-Z0-9]$/.test(dimension) || dimension === "Z") {
    return "";
  }
  const functionCode = legacy.slice(4, 10).replace(/[\-*]+$/g, "");
  const functionParts = functionCode
    .split("")
    .filter((part) => /^[A-Z0-9]$/.test(part));
  if (!functionParts.length) {
    return "";
  }
  return `a-${getCotAffiliationCode(affiliation)}-${[dimension, ...functionParts].join("-")}`;
}

function getMilstdSymbolDefaultCotType(entry, affiliation = "friendly") {
  const aff = normalizeTacticalAffiliation(affiliation);
  if (!entry) {
    return buildDefaultCotTypeForTacticalObject("unit", aff, "ground");
  }
  if (entry.familyKey === "control_measures") return "b-m-p-c";
  if (String(entry.familyKey || "").startsWith("metoc")) return "b-i-w";
  if (entry.objectClass === "marker") return buildDefaultCotTypeForTacticalObject("marker", aff, entry.domain || "ground");
  const legacyCotType = buildCotTypeFromMilstdLegacySidc(entry.legacySidc || "", aff);
  if (legacyCotType) return legacyCotType;
  return buildDefaultCotTypeForTacticalObject("unit", aff, entry.domain || "ground");
}

function buildMilstdDetail(detail = {}, entry, affiliation = "friendly", size = "") {
  const next = detail && typeof detail === "object" ? { ...detail } : {};
  const catalogEntry = entry || getMilstdSymbolCatalogEntry(next);
  const explicitSidc = String(next.milsymId || "").trim();
  const uniqueId = normalizeMilstdUniqueId(
    next.milsymUniqueId
    || extractMilstdUniqueIdFromSidc(explicitSidc)
    || catalogEntry?.uniqueId
    || catalogEntry?.id
    || ""
  );
  const sidc = isMilstdSidc20(explicitSidc)
    ? explicitSidc
    : (buildMilstdSidc(uniqueId, affiliation, size) || explicitSidc);
  if (catalogEntry?.id) next.milsymCatalogId = catalogEntry.id;
  if (uniqueId) next.milsymUniqueId = uniqueId;
  if (catalogEntry?.legacySidc) next.milsymLegacyId = catalogEntry.legacySidc;
  if (!next.milsymLegacyId && isMilstdLegacySidc(explicitSidc)) next.milsymLegacyId = explicitSidc.toUpperCase();
  if (catalogEntry?.label) next.milsymLabel = catalogEntry.label;
  if (catalogEntry?.familyKey) next.milsymFamilyKey = catalogEntry.familyKey;
  if (catalogEntry?.familyLabel) next.milsymFamilyLabel = catalogEntry.familyLabel;
  if (sidc) next.milsymId = sidc;
  return next;
}

function shouldRenderStandaloneMilstd(entry) {
  if (!entry) return false;
  return entry.familyKey === "control_measures" || String(entry.familyKey || "").startsWith("metoc");
}

function normalizeMilstdAssetPath(path = "") {
  const text = String(path || "").trim();
  if (!text) return "";
  const normalized = text.replace(/\\/g, "/");
  if (normalized.startsWith(".cache/joint-military-symbology-xml/svg/")) {
    return normalized.replace(".cache/joint-military-symbology-xml/svg/", "images/milstd/Catalog/");
  }
  return normalized;
}

function getRenderableMilstdAssetPath(entry, affiliation = "") {
  if (!entry) return "";
  const variants = entry.variantPaths && typeof entry.variantPaths === "object" ? entry.variantPaths : {};
  const normalizedAffiliation = affiliation ? normalizeTacticalAffiliation(affiliation) : "";
  return normalizeMilstdAssetPath(
    (normalizedAffiliation ? variants[normalizedAffiliation] : "")
    || entry.defaultPath
    || variants.friendly
    || variants.unknown
    || variants.neutral
    || variants.hostile
    || Object.values(variants).find((path) => String(path || "").trim())
    || ""
  );
}

function hasRenderableMilstdAssetPath(entry, affiliation = "") {
  return Boolean(getRenderableMilstdAssetPath(entry, affiliation));
}

function getMilstdMainPathForAffiliation(entry, affiliation = "friendly") {
  if (!entry) return "";
  const normalized = normalizeTacticalAffiliation(affiliation);
  const baseUniqueId = normalizeMilstdUniqueId(entry?.uniqueId || entry?.id || "");
  const preferredEntry = getPreferredMilstdSymbolEntryByBaseUniqueId(baseUniqueId, normalized) || entry;
  return getRenderableMilstdAssetPath(preferredEntry, normalized)
    || getRenderableMilstdAssetPath(entry, normalized);
}

function getMilstdFramePathFromSidc(sidc = "") {
  if (!isMilstdSidc20(sidc)) return "";
  const text = String(sidc).trim();
  return `images/milstd/Frames/${text.slice(2, 3)}_${text.slice(3, 6)}_${text.slice(6, 7)}.svg`;
}

function getMilstdEchelonPathFromSidc(sidc = "") {
  if (!isMilstdSidc20(sidc)) return "";
  const text = String(sidc).trim();
  const ampGroup = text.charAt(8);
  const amp = text.charAt(9);
  if (!["1", "2"].includes(ampGroup) || amp === "0") return "";
  return `images/milstd/Echelon/${text.charAt(3)}${ampGroup}${amp}.svg`;
}

function getMilstdSymbolInfo(value = {}) {
  const detail = value?.detail && typeof value.detail === "object" ? value.detail : {};
  const explicitSidc = String(value?.sidc || detail.milsymId || "").trim();
  const entry = getMilstdSymbolCatalogEntry({
    ...value,
    detail,
    uniqueId: detail.milsymUniqueId || value?.symbolUniqueId || "",
  });
  const affiliation = explicitSidc
    ? deriveTacticalAffiliationFromMilstdSidc(explicitSidc, value?.affiliation || "friendly")
    : normalizeTacticalAffiliation(value?.affiliation || "friendly");
  const sidc = isMilstdSidc20(explicitSidc)
    ? explicitSidc
    : buildMilstdSidc(detail.milsymUniqueId || entry?.uniqueId || entry?.id || "", affiliation, value?.size || "");
  return {
    entry,
    affiliation,
    sidc,
    uniqueId: normalizeMilstdUniqueId(detail.milsymUniqueId || entry?.uniqueId || entry?.id || extractMilstdUniqueIdFromSidc(sidc) || ""),
  };
}

function getMilstdLayerSpec(value = {}) {
  const symbolInfo = getMilstdSymbolInfo(value);
  if (symbolInfo.entry && symbolInfo.sidc) {
    const standalone = shouldRenderStandaloneMilstd(symbolInfo.entry);
    return {
      domain: normalizeTacticalDomain(symbolInfo.entry.domain || value?.domain || "ground"),
      framePath: standalone ? "" : getMilstdFramePathFromSidc(symbolInfo.sidc),
      mainPath: getMilstdMainPathForAffiliation(symbolInfo.entry, symbolInfo.affiliation),
      modifierPaths: [],
      echelonPath: standalone ? "" : getMilstdEchelonPathFromSidc(symbolInfo.sidc),
      fallbackText: "",
    };
  }

  const unit = value && typeof value === "object" ? value : {};
  const framePath = resolveMilstdFramePath(unit);
  if (unit?.frameOnly) {
    return {
      domain: resolveMilstdDomain(unit),
      framePath,
      mainPath: "",
      modifierPaths: [],
      echelonPath: "",
      fallbackText: "",
    };
  }
  const mainPath = resolveMilstdMainPath(unit) || "";
  const modifierPaths = resolveMilstdModifierPaths(unit);
  return {
    domain: resolveMilstdDomain(unit),
    framePath,
    mainPath,
    modifierPaths,
    echelonPath: MILSTD_ECHELON_PATHS[unit.size] || "",
    fallbackText: !mainPath && !modifierPaths.length ? getMilstdFallbackText(unit) : "",
  };
}

function getMilstdPaletteFamilies() {
  const grouped = MILSTD_SYMBOL_CATALOG.reduce((map, entry) => {
    const key = String(entry?.familyKey || "other");
    if (!map.has(key)) {
      map.set(key, {
        key,
        label: entry?.familyLabel || "Other",
        domain: entry?.domain || "ground",
        count: 0,
      });
    }
    map.get(key).count += 1;
    return map;
  }, new Map());
  return [...grouped.values()].sort((a, b) => {
    const ai = MILSTD_FAMILY_SORT.indexOf(a.key);
    const bi = MILSTD_FAMILY_SORT.indexOf(b.key);
    return (ai >= 0 ? ai : 999) - (bi >= 0 ? bi : 999) || a.label.localeCompare(b.label);
  });
}

function getMilstdPaletteCategories(familyKey = "") {
  const grouped = MILSTD_SYMBOL_CATALOG
    .filter((entry) => !familyKey || entry.familyKey === familyKey)
    .reduce((map, entry) => {
      const key = `${entry.familyKey}::${entry.category}`;
      const bucket = map.get(key) || {
        id: key,
        familyKey: entry.familyKey,
        label: entry.category,
        domain: entry.domain,
        entries: [],
        preview: entry,
      };
      bucket.entries.push(entry);
      map.set(key, bucket);
      return map;
    }, new Map());
  return [...grouped.values()].sort((a, b) => a.label.localeCompare(b.label));
}

function getCotTypeTail(cotType = "") {
  const parts = String(cotType || "").trim().split("-").filter(Boolean);
  if (parts.length < 3) {
    return "";
  }
  return parts.slice(2).join("-").toUpperCase();
}

function isGenericCotTrackType(cotType = "") {
  return ["G", "A", "S", "U", "P"].includes(getCotTypeTail(cotType));
}

function getDoctrinalCatalogEntryById(catalogId = "") {
  const normalizedId = String(catalogId || "").trim();
  if (!normalizedId) return null;
  const exact = TACTICAL_UNIT_CATALOG_BY_ID.get(normalizedId);
  if (exact) return exact;
  const aliasTarget = LEGACY_TACTICAL_UNIT_SYMBOL_ALIASES[normalizedId];
  if (aliasTarget) {
    return TACTICAL_UNIT_CATALOG_BY_ID.get(aliasTarget) || null;
  }
  return LEGACY_TACTICAL_UNIT_CATALOG_BY_ID.get(normalizedId) || null;
}

function getDoctrinalCatalogEntryByCotType(cotType = "") {
  const tail = getCotTypeTail(cotType);
  if (!tail) return null;
  return LEGACY_TACTICAL_UNIT_CATALOG_BY_TAIL.find((entry) => tail === entry.cotTail || tail.startsWith(`${entry.cotTail}-`)) || null;
}

function getDoctrinalCatalogEntry(value = {}) {
  const catalogId = typeof value === "string"
    ? value
    : (value?.catalogId || value?.type || value?.unitType || "");
  return getDoctrinalCatalogEntryById(catalogId) || getDoctrinalCatalogEntryByCotType(value?.cotType || "");
}

function buildCatalogCotType(catalogId = "", affiliation = "friendly") {
  const entry = getDoctrinalCatalogEntryById(catalogId);
  if (!entry) return "";
  const aff = normalizeTacticalAffiliation(affiliation);
  if (entry.cotTail) {
    const affCode = aff === "friendly" ? "f" : aff === "hostile" ? "h" : aff === "neutral" ? "n" : "u";
    return `a-${affCode}-${entry.cotTail}`;
  }
  return getMilstdSymbolDefaultCotType(getMilstdSymbolCatalogEntry(entry.milstdCatalogId || entry.symbolUniqueId || entry.id), aff);
}

function buildUnitTypeSelectMarkup({ includeBlank = false, includeExtended = false } = {}) {
  const grouped = TACTICAL_UNIT_CATALOG
    .filter((entry) => includeExtended || !entry.tacticalOnly)
    .reduce((map, entry) => {
    const bucket = map.get(entry.group) || [];
    bucket.push(entry);
    map.set(entry.group, bucket);
    return map;
  }, new Map());
  const optgroups = [...grouped.entries()].map(([groupLabel, entries]) => `
    <optgroup label="${escapeHtml(groupLabel)}">
      ${entries.map((entry) => `<option value="${escapeHtml(entry.id)}">${escapeHtml(entry.label)}</option>`).join("")}
    </optgroup>
  `).join("");
  return `${includeBlank ? '<option value="">Select MIL-STD symbol</option>' : ""}${optgroups}`;
}

function populateDoctrinalUnitTypeSelect(selectEl, { includeBlank = false, includeExtended = false } = {}) {
  if (!selectEl) return;
  const current = selectEl.value;
  selectEl.innerHTML = buildUnitTypeSelectMarkup({ includeBlank, includeExtended });
  if (current && selectEl.querySelector(`option[value="${current}"]`)) {
    selectEl.value = current;
  }
}

function catalogAllowsEchelon(catalogId = "") {
  const entry = getDoctrinalCatalogEntryById(catalogId);
  return entry?.echelonAllowed !== false;
}

function deriveTacticalUnitTypeFromCotType(cotType = "", fallbackDomain = "") {
  const match = getDoctrinalCatalogEntryByCotType(cotType);
  if (match?.id) {
    return normalizeToUnitType(match.id);
  }
  return deriveTacticalUnitTypeFromDomain(fallbackDomain || deriveTacticalDomainFromCotType(cotType));
}

function buildTakSchema2525UserIconPath(cotType = "") {
  const normalized = String(cotType || "").trim();
  const parts = normalized.split("-").filter(Boolean);
  if (parts.length < 3 || parts[0].toLowerCase() !== "a") {
    return "";
  }
  const affiliationPath = `a-${parts[1].toLowerCase()}`;
  return `COT_MAPPING_2525B/${affiliationPath}/${normalized}`;
}

function normalizeTakSchemaDetail(value = {}, fallback = {}) {
  const source = value && typeof value === "object" ? value : {};
  const flatFallback = fallback && typeof fallback === "object" ? fallback : {};
  const contact = source.contact && typeof source.contact === "object" ? { ...source.contact } : {};
  if (!contact.callsign && flatFallback.callsign) contact.callsign = String(flatFallback.callsign).trim();
  if (!contact.endpoint && flatFallback.endpoint) contact.endpoint = String(flatFallback.endpoint).trim();

  const group = source.group && typeof source.group === "object" ? { ...source.group } : {};
  if (!group.name && flatFallback.team) group.name = String(flatFallback.team).trim();
  if (!group.role && flatFallback.role) group.role = String(flatFallback.role).trim();

  const track = source.track && typeof source.track === "object" ? { ...source.track } : {};
  if (track.course == null && flatFallback.course != null) track.course = String(flatFallback.course);
  if (track.speed == null && flatFallback.speed != null) track.speed = String(flatFallback.speed);
  if (track.slope == null && flatFallback.slope != null) track.slope = String(flatFallback.slope);

  const remarks = source.remarks && typeof source.remarks === "object" ? { ...source.remarks } : {};
  if (!remarks.text && flatFallback.remarks) remarks.text = String(flatFallback.remarks);
  if (!remarks.source && flatFallback.source) remarks.source = String(flatFallback.source);
  if (!remarks.sourceID && flatFallback.sourceID) remarks.sourceID = String(flatFallback.sourceID);
  if (!remarks.time && flatFallback.time) remarks.time = String(flatFallback.time);
  if (!remarks.to && flatFallback.to) remarks.to = String(flatFallback.to);

  const usericon = source.usericon && typeof source.usericon === "object" ? { ...source.usericon } : {};
  if (!usericon.iconsetpath && flatFallback.usericonPath) usericon.iconsetpath = String(flatFallback.usericonPath).trim();

  const milsym = source.milsym && typeof source.milsym === "object" ? { ...source.milsym } : {};
  if (!milsym.id && flatFallback.milsymId) milsym.id = String(flatFallback.milsymId).trim();

  const links = Array.isArray(source.links)
    ? source.links.filter((entry) => entry && typeof entry === "object").map((entry) => ({ ...entry }))
    : [];
  const takv = source.takv && typeof source.takv === "object" ? { ...source.takv } : null;

  return {
    contact: Object.keys(contact).length ? contact : null,
    group: Object.keys(group).length ? group : null,
    track: Object.keys(track).length ? track : null,
    remarks: Object.keys(remarks).length ? remarks : null,
    usericon: Object.keys(usericon).length ? usericon : null,
    milsym: Object.keys(milsym).length ? milsym : null,
    links,
    takv,
  };
}

function buildTakSchemaDetailXml({
  contact = null,
  group = null,
  track = null,
  remarks = null,
  usericon = null,
  milsym = null,
  links = [],
  takv = null,
} = {}) {
  const normalized = normalizeTakSchemaDetail({ contact, group, track, remarks, usericon, milsym, links, takv });
  return [
    normalized.contact?.callsign
      ? `<contact${normalized.contact.callsign ? ` callsign="${escapeHtml(normalized.contact.callsign)}"` : ""}${normalized.contact.endpoint ? ` endpoint="${escapeHtml(normalized.contact.endpoint)}"` : ""}${normalized.contact.emailAddress ? ` emailAddress="${escapeHtml(normalized.contact.emailAddress)}"` : ""}${normalized.contact.phone ? ` phone="${escapeHtml(normalized.contact.phone)}"` : ""}${normalized.contact.xmppUsername ? ` xmppUsername="${escapeHtml(normalized.contact.xmppUsername)}"` : ""}/>`
      : "",
    normalized.group
      ? `<__group name="${escapeHtml(normalized.group.name || state.takIdentity.team || "Cyan")}" role="${escapeHtml(normalized.group.role || state.takIdentity.role || "Team Member")}"/>`
      : "",
    normalized.track
      ? `<track${normalized.track.course != null ? ` course="${escapeHtml(normalized.track.course)}"` : ` course="0"`}${normalized.track.speed != null ? ` speed="${escapeHtml(normalized.track.speed)}"` : ` speed="0"`}${normalized.track.slope != null ? ` slope="${escapeHtml(normalized.track.slope)}"` : ""}/>`
      : "",
    normalized.milsym?.id ? `<__milsym id="${escapeHtml(normalized.milsym.id)}"/>` : "",
    normalized.usericon?.iconsetpath ? `<usericon iconsetpath="${escapeHtml(normalized.usericon.iconsetpath)}"/>` : "",
    ...normalized.links.map((link) => {
      const attrs = [
        link.uid ? ` uid="${escapeHtml(link.uid)}"` : "",
        link.type ? ` type="${escapeHtml(link.type)}"` : "",
        link.relation ? ` relation="${escapeHtml(link.relation)}"` : "",
        link.parent_callsign ? ` parent_callsign="${escapeHtml(link.parent_callsign)}"` : "",
        link.production_time ? ` production_time="${escapeHtml(link.production_time)}"` : "",
        link.callsign ? ` callsign="${escapeHtml(link.callsign)}"` : "",
        link.remarks ? ` remarks="${escapeHtml(link.remarks)}"` : "",
        link.point ? ` point="${escapeHtml(link.point)}"` : "",
      ].join("");
      return attrs ? `<link${attrs}/>` : "";
    }),
    normalized.takv
      ? `<takv${normalized.takv.os ? ` os="${escapeHtml(normalized.takv.os)}"` : ""}${normalized.takv.device ? ` device="${escapeHtml(normalized.takv.device)}"` : ""}${normalized.takv.platform ? ` platform="${escapeHtml(normalized.takv.platform)}"` : ""}${normalized.takv.version ? ` version="${escapeHtml(normalized.takv.version)}"` : ""}/>`
      : "",
    normalized.remarks
      ? `<remarks${normalized.remarks.source ? ` source="${escapeHtml(normalized.remarks.source)}"` : ""}${normalized.remarks.sourceID ? ` sourceID="${escapeHtml(normalized.remarks.sourceID)}"` : ""}${normalized.remarks.time ? ` time="${escapeHtml(normalized.remarks.time)}"` : ""}${normalized.remarks.to ? ` to="${escapeHtml(normalized.remarks.to)}"` : ""}>${escapeHtml(normalized.remarks.text || "")}</remarks>`
      : "",
  ].filter(Boolean).join("");
}

function deriveTacticalUnitTypeFromDomain(domain = "ground") {
  return DEFAULT_MILSTD_UNIT_BY_DOMAIN[normalizeTacticalDomain(domain || "ground")] || DEFAULT_MILSTD_UNIT_ID;
}

function buildDefaultCotTypeForTacticalObject(objectClass, affiliation = "friendly", domain = "ground") {
  const aff = normalizeTacticalAffiliation(affiliation);
  const affCode = aff === "friendly" ? "f" : aff === "hostile" ? "h" : aff === "neutral" ? "n" : "u";
  const domainCode = domain === "air" ? "A" : domain === "sea_surface" ? "S" : domain === "subsurface" ? "U" : domain === "space" ? "P" : "G";
  if (objectClass === "route") return "b-m-r";
  if (objectClass === "geofence") return "b-m-p-c";
  if (objectClass === "drawing" || objectClass === "shape") return "u-d-f";
  return `a-${affCode}-${domainCode}-U-C`;
}

function normalizeTacticalObject(raw = {}) {
  const geometryType = String(raw.geometryType || "Point");
  const rawDetail = raw.detail && typeof raw.detail === "object" ? { ...raw.detail } : {};
  const explicitSidc = String(raw.sidc || rawDetail.milsymId || "").trim();
  const explicitSymbolUniqueId = normalizeMilstdUniqueId(
    raw.symbolUniqueId
    || rawDetail.milsymUniqueId
    || extractMilstdUniqueIdFromSidc(explicitSidc)
    || ""
  );
  const milstdEntry = getMilstdSymbolCatalogEntry({
    ...raw,
    detail: rawDetail,
    sidc: explicitSidc,
    uniqueId: explicitSymbolUniqueId || raw.symbolUniqueId || raw.catalogId || raw.unitType || "",
  });
  const milstdAffiliation = explicitSidc
    ? deriveTacticalAffiliationFromMilstdSidc(explicitSidc, raw.affiliation || "friendly")
    : normalizeTacticalAffiliation(raw.affiliation || "friendly");
  const objectClass = TACTICAL_OBJECT_CLASSES.includes(raw.objectClass)
    ? raw.objectClass
    : (milstdEntry?.objectClass || "unit");
  const catalogEntry = getDoctrinalCatalogEntry(raw);
  const domain = normalizeTacticalDomain(raw.domain || milstdEntry?.domain || catalogEntry?.domain || deriveTacticalDomainFromCotType(raw.cotType));
  const unitType = normalizeToUnitType(
    raw.unitType
    || raw.catalogId
    || explicitSymbolUniqueId
    || catalogEntry?.id
    || milstdEntry?.uniqueId
    || deriveTacticalUnitTypeFromCotType(raw.cotType, domain)
  );
  const size = objectClass !== "unit"
    ? (typeof raw.size === "string" ? raw.size : "")
    : (typeof raw.size === "string"
        ? raw.size
        : (catalogAllowsEchelon(unitType) ? "battalion" : ""));
  const affiliation = normalizeTacticalAffiliation(raw.affiliation || milstdAffiliation || deriveTacticalAffiliationFromCotType(raw.cotType));
  const coordinates = normalizeTacticalCoordinates(geometryType, raw.coordinates);
  const detail = buildMilstdDetail(rawDetail, milstdEntry, affiliation, size);
  if (!detail.milsymId && raw.cotType && (!detail.usericonPath || String(detail.usericonPath).startsWith("COT_MAPPING_2525B/"))) {
    const usericonPath = buildTakSchema2525UserIconPath(raw.cotType);
    if (usericonPath) {
      detail.usericonPath = usericonPath;
    }
  }
  const sidc = String(explicitSidc || detail.milsymId || "").trim();
  const symbolUniqueId = normalizeMilstdUniqueId(
    explicitSymbolUniqueId
    || detail.milsymUniqueId
    || milstdEntry?.uniqueId
    || unitType
    || ""
  );
  const defaultCotType = milstdEntry
    ? getMilstdSymbolDefaultCotType(milstdEntry, affiliation)
    : buildDefaultCotTypeForTacticalObject(objectClass, affiliation, domain);
  return {
    id: raw.id || generateId(),
    uid: String(raw.uid || raw.id || generateId()).trim(),
    source: raw.source || "manual",
    objectClass,
    geometryType,
    shapeKind: raw.shapeKind || (geometryType === "LineString" ? "route" : geometryType === "Polygon" ? "polygon" : "point"),
    coordinates,
    cotType: String(
      raw.cotType
      || (objectClass === "unit" ? buildCatalogCotType(unitType, affiliation) : "")
      || defaultCotType
    ).trim(),
    sidc,
    catalogId: objectClass === "unit" ? unitType : "",
    domain,
    affiliation,
    size,
    unitType,
    symbolUniqueId: objectClass === "unit" ? symbolUniqueId : "",
    name: String(raw.name || raw.label || detail.milsymLabel || buildDefaultToUnitLabel(size, unitType)).trim(),
    designator: String(raw.designator || raw.callsign || "").trim(),
    remarks: String(raw.remarks || "").trim(),
    detail,
    staleAt: String(raw.staleAt || "").trim(),
    provider: String(raw.provider || "").trim(),
    readOnly: Boolean(raw.readOnly),
    linkedPlanUnitId: Number.isFinite(Number(raw.linkedPlanUnitId)) ? Number(raw.linkedPlanUnitId) : null,
    linkedAssetIds: Array.isArray(raw.linkedAssetIds) ? raw.linkedAssetIds.map(String) : [],
    showLabel: raw.showLabel !== false,
    streamToTak: typeof raw.streamToTak === "boolean"
      ? raw.streamToTak
      : (!Boolean(raw.readOnly) && getDefaultTakStreamingEnabled()),
    style: raw.style && typeof raw.style === "object" ? { ...raw.style } : null,
    lastModified: raw.lastModified || nowIso(),
  };
}

function serializeTacticalObject(object) {
  const normalized = normalizeTacticalObject(object);
  return {
    id: normalized.id,
    uid: normalized.uid,
    source: normalized.source,
    objectClass: normalized.objectClass,
    geometryType: normalized.geometryType,
    shapeKind: normalized.shapeKind,
    coordinates: normalized.coordinates,
    cotType: normalized.cotType,
    sidc: normalized.sidc,
    catalogId: normalized.catalogId,
    domain: normalized.domain,
    affiliation: normalized.affiliation,
    size: normalized.size,
    unitType: normalized.unitType,
    name: normalized.name,
    designator: normalized.designator,
    remarks: normalized.remarks,
    detail: normalized.detail,
    staleAt: normalized.staleAt,
    provider: normalized.provider,
    readOnly: normalized.readOnly,
    linkedPlanUnitId: normalized.linkedPlanUnitId,
    linkedAssetIds: normalized.linkedAssetIds,
    showLabel: normalized.showLabel,
    streamToTak: normalized.streamToTak,
    style: normalized.style,
    lastModified: normalized.lastModified,
  };
}

function getTacticalObjectById(id) {
  return state.tacticalObjects.find((entry) => entry.id === id) ?? null;
}

function getTakLiveObjectByUid(uid) {
  return state.takRuntime.objectsByUid.get(String(uid || "")) ?? null;
}

function isUnitTacticalObject(object) {
  return String(object?.objectClass || "") === "unit";
}

function getLinkedPlanUnitForTacticalObject(object) {
  if (!Number.isFinite(Number(object?.linkedPlanUnitId))) {
    return null;
  }
  return _toState.units.find((unit) => unit.id === Number(object.linkedPlanUnitId)) ?? null;
}

function getTacticalDisplayUnit(object) {
  const linked = getLinkedPlanUnitForTacticalObject(object);
  const normalizedLinked = linked ? normalizePlanUnit(linked) : null;
  const detail = object?.detail && typeof object.detail === "object" ? { ...object.detail } : {};
  const explicitSidc = String(object?.sidc || detail.milsymId || "").trim();
  const resolvedSymbolUniqueId = normalizeMilstdUniqueId(
    object?.symbolUniqueId
    || detail.milsymUniqueId
    || extractMilstdUniqueIdFromSidc(explicitSidc)
    || ""
  );
  const resolvedType = normalizeToUnitType(
    object?.catalogId
    || resolvedSymbolUniqueId
    || deriveTacticalUnitTypeFromCotType(object?.cotType, object?.domain)
    || object?.unitType
  );
  return normalizeToUnit({
    id: normalizedLinked?.id ?? object?.linkedPlanUnitId ?? 0,
    label: normalizedLinked?.label || object?.name || "Tactical Unit",
    designator: normalizedLinked?.designator || object?.designator || "",
    affiliation: normalizeTacticalAffiliation(normalizedLinked?.affiliation || object?.affiliation || "friendly"),
    type: normalizedLinked?.catalogId || normalizedLinked?.type || resolvedSymbolUniqueId || resolvedType || "infantry",
    catalogId: normalizedLinked?.catalogId || resolvedSymbolUniqueId || resolvedType || "infantry",
    cotType: normalizedLinked?.cotType || object?.cotType || buildCatalogCotType(resolvedType, normalizedLinked?.affiliation || object?.affiliation || "friendly"),
    size: normalizedLinked?.size ?? object?.size ?? (object?.objectClass === "unit" && catalogAllowsEchelon(resolvedType) ? "battalion" : ""),
    sidc: explicitSidc,
    symbolUniqueId: resolvedSymbolUniqueId,
    detail,
    frameOnly: isGenericCotTrackType(object?.cotType),
  });
}

function formatTacticalGeometrySummary(object) {
  const coords = object?.coordinates;
  if (object?.geometryType === "Point" && Array.isArray(coords) && coords.length >= 2) {
    return `${Number(coords[0]).toFixed(6)}, ${Number(coords[1]).toFixed(6)}`;
  }
  if (object?.geometryType === "LineString") {
    return `${Array.isArray(coords) ? coords.length : 0} route point(s)`;
  }
  const isCircle = object?.shapeKind === "circle" && Number.isFinite(Number(object?.detail?.radiusM));
  if (isCircle) {
    return `Circle â€¢ ${formatDistance(Number(object.detail.radiusM))}`;
  }
  return `${Array.isArray(coords) ? coords.length : 0} vertex/vertices`;
}

// Wire a modal backdrop element to close only when the click both starts and
// ends on the backdrop â€” prevents text-selection drags inside the modal from
// accidentally dismissing it.
function addModalBackdropClose(el, closeFn) {
  if (!el || !closeFn) return;
  let mousedownOnBackdrop = false;
  el.addEventListener("mousedown", (e) => {
    mousedownOnBackdrop = e.target === el;
  });
  el.addEventListener("click", (e) => {
    if (mousedownOnBackdrop && e.target === el) closeFn();
    mousedownOnBackdrop = false;
  });
}

function generateId() {
  if (typeof crypto !== "undefined") {
    if (typeof crypto.randomUUID === "function") {
      return crypto.randomUUID();
    }
    if (typeof crypto.getRandomValues === "function") {
      const bytes = crypto.getRandomValues(new Uint8Array(16));
      bytes[6] = (bytes[6] & 0x0f) | 0x40;
      bytes[8] = (bytes[8] & 0x3f) | 0x80;
      const hex = Array.from(bytes, (byte) => byte.toString(16).padStart(2, "0"));
      return `${hex.slice(0, 4).join("")}-${hex.slice(4, 6).join("")}-${hex.slice(6, 8).join("")}-${hex.slice(8, 10).join("")}-${hex.slice(10, 16).join("")}`;
    }
  }

  return `id-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
}

