async function ensureEmitterLibraryLoaded() {
  if (EMITTER_LIBRARY !== EMPTY_EMITTER_LIBRARY) {
    return EMITTER_LIBRARY;
  }
  if (!emitterLibraryLoadPromise) {
    emitterLibraryLoadPromise = import("./src/emitter-library.js").then(({ EMITTER_LIBRARY: loadedLibrary }) => {
      EMITTER_LIBRARY = loadedLibrary;
      return EMITTER_LIBRARY;
    });
  }
  return emitterLibraryLoadPromise;
}

function isRadarEmitterType(emitterType = "") {
  return RADAR_EMITTER_TYPES.has(String(emitterType || "").trim());
}

function inferRadarScanType(mode = "") {
  const normalized = String(mode || "").trim().toLowerCase();
  if (!normalized) return "";
  if (normalized.includes("passive")) return "Passive";
  if (normalized.includes("illum")) return "Illumination";
  if (normalized.includes("track")) return "Track";
  if (normalized.includes("sector")) return "Sector Search";
  if (normalized.includes("3d")) return "3D Search";
  if (normalized.includes("acquisition")) return "Acquisition Search";
  if (normalized.includes("aesa")) return "AESA Search";
  return "360 Search";
}

function getRadarProfileDefaults(emitterType = "", { program = null, fallbackMode = "" } = {}) {
  const preset = RADAR_PROFILE_PRESETS[emitterType] || {};
  const mode = String(
    preset.mode
    || program?.rf?.waveform
    || program?.label
    || fallbackMode
    || "",
  ).trim();
  return {
    mode,
    pulseWidthUs: preset.pulseWidthUs ?? null,
    prfHz: preset.prfHz ?? null,
    scanType: String(preset.scanType || inferRadarScanType(mode)).trim(),
  };
}

function wattsToDbm(w) { return 10 * Math.log10(w * 1000); }
function dbmToWatts(dbm) { return Math.pow(10, dbm / 10) / 1000; }
function fsplDb(freqMHz, distM) {
  return 20 * Math.log10(distM) + 20 * Math.log10(freqMHz * 1e6) - 147.55;
}
function computeLinkBudget(profile) {
  const txDbm = wattsToDbm(profile.tx.powerW);
  const gainDbi = profile.antenna.gainDbi;
  const cableLossDb = profile.antenna.cableLossDb;
  const systemLossDb = profile.antenna.systemLossDb;
  const eirpDbm = txDbm + gainDbi - cableLossDb - (systemLossDb - cableLossDb);
  const rxSensDbm = profile.rx.sensitivityDbm;
  const freqMHz = profile.rf.frequencyMHz;
  const fspl10km = fsplDb(freqMHz, 10000);
  const rxPower10km = eirpDbm - fspl10km + gainDbi;
  const margin10km = rxPower10km - rxSensDbm;
  // Max range where margin = 0: solve eirp - fspl + gain = rxSens
  // fspl = 20log(d) + 20log(f) - 147.55 â†’ d = 10^((eirp+gain-rxSens+147.55 - 20log(f))/20)
  const maxRangeM = Math.pow(10, (eirpDbm + gainDbi - rxSensDbm + 147.55 - 20 * Math.log10(freqMHz * 1e6)) / 20);
  return { txDbm, eirpDbm, fspl10km, rxPower10km, margin10km, maxRangeM };
}

