      diffractionEnabled: asset?.diffractionEnabled ?? ext.diffractionEnabled,
      nvisEnabled: asset?.nvisEnabled ?? ext.nvisEnabled,
      ionoModel: asset?.ionoModel ?? ext.ionoModel,
