    cableLossDb: normalized.antenna.cableLossDb,
    receiverSensitivityDbm: normalized.rx.sensitivityDbm,
    noiseFigDb: normalized.rx.noiseFigDb,
    requiredSnrDb: normalized.rx.requiredSnrDb,
    acrDb: normalized.rx.acrDb,
