function closeSimulationProgress() {
  state.simulationProgress.active = false;
  state.simulationProgress.requestId = null;
  state.simulationProgress.percent = 0;
  state.simulationProgress.workerDispatched = false;
  state.simulationProgress.cancelRequested = false;
  dom.simulationProgressCancelBtn?.removeAttribute("disabled");
  dom.simulationProgressModal?.classList.add("hidden");
  updateModalBodyState();
}

function updateSimulationTerrainPrepProgress(fraction, stage, detail = "") {
  if (!state.simulationProgress.active) {
    return;
  }
  const scaledPercent = 8 + clamp(fraction ?? 0, 0, 1) * 24;
  updateSimulationProgress(scaledPercent, stage, detail || `${Math.round(scaledPercent)}%`);
}

function isSimulationCanceled(requestId) {
  return state.canceledSimulationRequestIds.has(requestId);
}

function throwIfSimulationCanceled(requestId) {
  if (requestId && isSimulationCanceled(requestId)) {
    throw new Error("SIMULATION_CANCELED");
  }
}

function createSimulationWorker() {
  return new Worker(new URL("./simulation-worker.js", import.meta.url), { type: "module" });
}

function attachSimulationWorkerListener() {
  state.worker.addEventListener("message", onWorkerMessage);
}

function hydrateWorkerTerrainCaches() {
  const terrains = [
    ...state.terrains,
    ...state.ionTerrainCache.values(),
  ];
  terrains.forEach((terrain) => {
    cacheTerrainInWorker(terrain).catch(() => {});
  });
}

function recreateSimulationWorker() {
  try {
    state.worker?.terminate();
  } catch {}
  state.terrainReadyIds.clear();
  state.terrainCacheResolvers.forEach((resolve) => resolve());
  state.terrainCacheResolvers.clear();
  state.worker = createSimulationWorker();
  attachSimulationWorkerListener();
  hydrateWorkerTerrainCaches();
}

function cancelSimulationProgress() {
  if (!state.simulationProgress.active || !state.simulationProgress.requestId) {
    return;
  }
  const requestId = state.simulationProgress.requestId;
  state.canceledSimulationRequestIds.add(requestId);
  state.simulationProgress.cancelRequested = true;
  dom.simulationProgressCancelBtn?.setAttribute("disabled", "true");
  updateSimulationProgress(
    state.simulationProgress.percent,
    "Canceling simulation...",
    "Canceling",
  );
  if (state.simulationProgress.workerDispatched) {
    state.worker?.postMessage({
      type: "simulation:cancel",
      payload: { requestId },
    });
  }
  closeSimulationProgress();
  setStatus("Coverage generation canceled.");
}

function simulationUsesTerrainModel(propagationModel) {
  return propagationModel === "itu-p526"
    || propagationModel === "itu-hybrid"
    || propagationModel === "itu-buildings-weather";
}

function simulationUsesAtmosphericModel(propagationModel) {
  return propagationModel === "itu-hybrid" || propagationModel === "itu-buildings-weather";
}

function simulationUsesBuildingModel(propagationModel) {
  return propagationModel === "itu-buildings-weather";
}


async function apiFetch(path, options = {}) {
  const headers = new Headers(options.headers ?? {});
  headers.set("Content-Type", headers.get("Content-Type") ?? "application/json");
  if (state.session.token) {
    headers.set("Authorization", `Bearer ${state.session.token}`);
  }

  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), 10000);
  let response;
  try {
    response = await fetch(`${API_BASE_URL}${path}`, {
      ...options,
      headers,
      signal: options.signal ?? controller.signal,
    });
  } catch (err) {
    clearTimeout(timeoutId);
    if (err.name === "AbortError") throw new Error("Request timed out.");
    throw err;
  }
  clearTimeout(timeoutId);

  if (response.status === 204) {
    return null;
  }

  const payload = await response.json().catch(() => ({}));
  if (!response.ok) {
    throw new Error(payload.error ?? payload.message ?? `API request failed (${response.status}).`);
  }

  return payload;
}

let _takCertPasswordPrompt = null;

function createEmptyTakProfileDraft() {
  return {
    id: "",
    label: "",
    serverHost: "",
    tlsServerName: "",
    serverPort: 8089,
    transport: "ssl",
    enrollForClientCert: false,
    useAuthentication: false,
    username: "",
    hasAuthSecret: false,
    hasClientCert: false,
    hasClientCertPassword: false,
    hasCaCert: false,
    hasCaCertPassword: false,
    clientCertFileName: "",
    caCertFileName: "",
    clientCertUpdatedAt: "",
    caCertUpdatedAt: "",
    lastTestedAt: "",
    lastTestStatus: "",
    _authSecretDraft: "",
    _deleteAuthSecret: false,
    _clientCertDataDraft: "",
    _clientCertFileNameDraft: "",
    _clientCertPasswordDraft: "",
    _deleteClientCert: false,
    _caCertDataDraft: "",
    _caCertFileNameDraft: "",
    _caCertPasswordDraft: "",
    _deleteCaCert: false,
  };
}

function sanitizeTakProfileSummary(profile) {
  const base = createEmptyTakProfileDraft();
  if (!profile || typeof profile !== "object") {
    return base;
  }
  return {
    ...base,
    id: typeof profile.id === "string" ? profile.id : "",
    label: typeof profile.label === "string" ? profile.label : "",
    serverHost: typeof profile.serverHost === "string" ? profile.serverHost : "",
    tlsServerName: typeof profile.tlsServerName === "string" ? profile.tlsServerName : "",
    serverPort: Number.isFinite(Number(profile.serverPort)) ? Number(profile.serverPort) : 8089,
    transport: typeof profile.transport === "string" && profile.transport ? profile.transport : "ssl",
    enrollForClientCert: Boolean(profile.enrollForClientCert),
    useAuthentication: Boolean(profile.useAuthentication),
    username: typeof profile.username === "string" ? profile.username : "",
    hasAuthSecret: Boolean(profile.hasAuthSecret),
    hasClientCert: Boolean(profile.hasClientCert),
    hasClientCertPassword: Boolean(profile.hasClientCertPassword),
    hasCaCert: Boolean(profile.hasCaCert),
    hasCaCertPassword: Boolean(profile.hasCaCertPassword),
    clientCertFileName: typeof profile.clientCertFileName === "string" ? profile.clientCertFileName : "",
    caCertFileName: typeof profile.caCertFileName === "string" ? profile.caCertFileName : "",
    clientCertUpdatedAt: typeof profile.clientCertUpdatedAt === "string" ? profile.clientCertUpdatedAt : "",
    caCertUpdatedAt: typeof profile.caCertUpdatedAt === "string" ? profile.caCertUpdatedAt : "",
    lastTestedAt: typeof profile.lastTestedAt === "string" ? profile.lastTestedAt : "",
    lastTestStatus: typeof profile.lastTestStatus === "string" ? profile.lastTestStatus : "",
  };
}

function getTakProfile(profileId = state.takSettings.activeProfileId) {
  return state.takSettings.profiles.find((profile) => profile.id === profileId) ?? null;
}

function getTakProjectBinding(projectId = state.session.activeProjectId) {
  if (!projectId) {
    return null;
  }
  return state.takSettings.projectAssignments.get(projectId) ?? null;
}

function getTakProfileForProject(projectId = state.session.activeProjectId) {
  const profileId = getTakProjectBinding(projectId);
  return profileId ? getTakProfile(profileId) : null;
}

function isTakEnabledForProject(projectId = state.session.activeProjectId) {
  return Boolean(getTakProfileForProject(projectId));
}

function isTakLiveImportedItem(item) {
  return Boolean(item?.tak?.source === "tak-live-pli");
}

function buildTacticalContentId(id) {
  return `tactical:${id}`;
}

function buildTakLiveContentId(uid) {
  return `taklive:${uid}`;
}

function getTakLiveRenderableObjects() {
  return [...state.takRuntime.objectsByUid.values()];
}

function ensureTakLiveFolder(objectClass = "unit") {
  const takFolderId = createOrGetNestedMapContentFolder("TAK", null, { collapsed: false });
  const folderName = TACTICAL_LIVE_FOLDER_NAMES[objectClass] || "Live Units";
  return createOrGetNestedMapContentFolder(folderName, takFolderId, { collapsed: false });
}

function getTacticalAffiliationColor(affiliation = "friendly") {
  if (affiliation === "hostile") return "#ff8080";
  if (affiliation === "neutral") return "#aaffaa";
  if (affiliation === "friendly") return "#80c8ff";
  return "#fef08a";
}

function getTacticalShapeStyle(object) {
  const color = getTacticalAffiliationColor(normalizeTacticalAffiliation(object?.affiliation));
  const base = object?.style && typeof object.style === "object" ? object.style : {};
  return normalizeImportedShapeStyle(object?.geometryType || "Polygon", {
    color: base.color || color,
    fillColor: base.fillColor || color,
    fillOpacity: Number.isFinite(Number(base.fillOpacity))
      ? Number(base.fillOpacity)
      : object?.objectClass === "geofence" ? 0.08 : 0.14,
    weight: Number.isFinite(Number(base.weight)) ? Number(base.weight) : 2,
    lineStyle: base.lineStyle || (object?.objectClass === "route" ? "dashed" : "solid"),
  });
}

function getTacticalMarkerSize() {
  return state.settings?.tacticalMarkerSize ?? 60;
}

function buildTacticalPointIcon(object) {
  const unit = getTacticalDisplayUnit(object);
  const sz = getTacticalMarkerSize();
  const half = sz / 2;
  const tooltipOffset = -(half + 8);
  const html = `<div class="tactical-map-icon tactical-map-icon--labelled" style="width:${sz}px;height:${sz}px;">${renderToUnitIcon(unit)}</div>`;
  return L.divIcon({
    className: "tactical-leaflet-icon",
    html,
    iconSize: [sz, sz],
    iconAnchor: [half, half],
    popupAnchor: [0, -20],
  });
}

function renderTacticalPopup(object, { live = false, panel = "summary", emitterId = "" } = {}) {
  const selectedEmitterId = String(emitterId || "").trim();
  const linkedEmitters = !live && isUnitTacticalObject(object)
    ? getLinkedEmitterAssetsForTacticalObject(object)
    : [];
  const lines = [];
  if (object?.cotType) lines.push(`CoT: ${object.cotType}`);
  if (object?.objectClass) lines.push(`Class: ${object.objectClass}`);
  if (object?.designator) lines.push(`Designator: ${object.designator}`);
  if (object?.remarks) lines.push(`Remarks: ${object.remarks}`);
  if (live && object?.detail?.team) lines.push(`Team: ${object.detail.team}`);
  if (live && object?.detail?.role) lines.push(`Role: ${object.detail.role}`);
  if (live && object?.detail?.lastSeenAt) lines.push(`Last seen: ${formatTakTimestamp(object.detail.lastSeenAt)}`);
  if (object?.staleAt) lines.push(`Stale: ${formatTakTimestamp(object.staleAt)}`);
  const detailEmitter = selectedEmitterId
    ? linkedEmitters.find((asset) => String(asset.id) === selectedEmitterId) || null
    : null;
  let actionHtml = "";

  if (linkedEmitters.length && object?.id) {
    if (panel === "emitters") {
      actionHtml = `
        <div class="tactical-popup-actions">
          <div class="tactical-popup-subtitle">Linked Emitters</div>
          <div class="tactical-popup-emitter-list">
            ${linkedEmitters.map((asset) => {
              const label = asset.emitterLabel || asset.name || "Emitter";
              const waveform = asset.waveform || asset.ext?.waveform || "";
              const freq = Number.isFinite(Number(asset.frequencyMHz))
                ? `${Number(asset.frequencyMHz).toFixed(3)} MHz`
                : "No frequency";
              const detail = [waveform, freq].filter(Boolean).join(" | ");
              return `
                <button class="ghost-button small tactical-popup-emitter-row" type="button"
                  data-tactical-popup-action="show-emitter-detail"
                  data-tactical-id="${escapeHtml(object.id)}"
                  data-emitter-id="${escapeHtml(asset.id)}">
                  <span class="tactical-popup-emitter-name">${escapeHtml(label)}</span>
                  <span class="tactical-popup-emitter-meta">${escapeHtml(detail)}</span>
                </button>
              `;
            }).join("")}
          </div>
          <button class="ghost-button small" type="button"
            data-tactical-popup-action="show-summary"
            data-tactical-id="${escapeHtml(object.id)}">Back</button>
        </div>
      `;
    } else if (panel === "emitter-detail" && detailEmitter) {
      const label = detailEmitter.emitterLabel || detailEmitter.name || "Emitter";
      const waveform = detailEmitter.waveform || detailEmitter.ext?.waveform || "";
      const profile = detailEmitter.profileName || detailEmitter.profileId || "";
      const anchored = hasAssetMapLocation(detailEmitter) ? "" : "Using linked unit position";
      const details = [
        waveform,
        Number.isFinite(Number(detailEmitter.frequencyMHz)) ? `${Number(detailEmitter.frequencyMHz).toFixed(3)} MHz` : "",
        Number.isFinite(Number(detailEmitter.powerW)) ? `${Number(detailEmitter.powerW)} W` : "",
        profile ? `Profile ${profile}` : "",
        anchored,
      ].filter(Boolean);
      actionHtml = `
        <div class="tactical-popup-actions">
          <div class="tactical-popup-subtitle">${escapeHtml(label)}</div>
          <div class="tactical-popup-detail">${details.map((line) => `<div>${escapeHtml(line)}</div>`).join("")}</div>
          <div class="tactical-popup-button-row">
            <button class="ghost-button small" type="button"
              data-tactical-popup-action="show-emitters"
              data-tactical-id="${escapeHtml(object.id)}">Back</button>
            <button class="primary-button small" type="button"
              data-tactical-popup-action="simulate-emitter"
              data-tactical-id="${escapeHtml(object.id)}"
              data-emitter-id="${escapeHtml(detailEmitter.id)}">Simulate</button>
          </div>
        </div>
      `;
    } else {
      actionHtml = `
        <div class="tactical-popup-actions">
          <button class="ghost-button small" type="button"
            data-tactical-popup-action="show-emitters"
            data-tactical-id="${escapeHtml(object.id)}">Emitters (${linkedEmitters.length})</button>
        </div>
      `;
    }
  }
  return `
    <strong>${escapeHtml(object?.name || object?.uid || "Tactical Item")}</strong><br>
    ${escapeHtml(object?.designator || object?.uid || "")}
    ${lines.length ? `<br>${lines.map((line) => escapeHtml(line)).join("<br>")}` : ""}
    ${actionHtml}
  `;
}

function applyTacticalLabel(object, layer) {
  if (!layer?.bindTooltip) return;
  layer.unbindTooltip?.();
  const contentId = object?.uid && object?.source === "tak-live"
    ? buildTakLiveContentId(object.uid)
    : object?.id
      ? buildTacticalContentId(object.id)
      : null;
  if (!object?.showLabel || !object?.name || (contentId && isContentLabelEffectivelyHidden(contentId))) return;
  layer.bindTooltip(object.name, {
    permanent: true,
    direction: isTacticalPointGeometry(object.geometryType) ? "top" : "center",
    className: `tactical-map-label${isTacticalPointGeometry(object.geometryType) ? " tactical-map-label--point" : ""}`,
    offset: isTacticalPointGeometry(object.geometryType) ? [0, -(getTacticalMarkerSize() / 2 + 8)] : [0, 0],
    interactive: false,
  });
}

function applyAssetLabel(asset) {
  const marker = state.assetMarkers.get(asset?.id);
  if (!marker?.bindTooltip) return;
  marker.unbindTooltip?.();
  if (!asset?.name || isContentLabelEffectivelyHidden(`asset:${asset.id}`)) return;
  marker.bindTooltip(asset.name, {
    permanent: true,
    direction: "top",
    className: "shape-map-label shape-map-label--point",
    offset: [0, -16],
    interactive: false,
  });
}

function openMapContentMenuForLeafletEvent(event, contentId) {
  const nativeEvent = event?.originalEvent || event;
  if (!nativeEvent) return;
  L.DomEvent.stopPropagation(event);
  openMapContentsMenu(nativeEvent, contentId);
}

function getLinkedEmitterAssetsForTacticalObject(object) {
  const directAssetIds = new Set((object?.linkedAssetIds || []).map((id) => String(id)));
  const linkedPlanUnitId = Number.isFinite(Number(object?.linkedPlanUnitId))
    ? Number(object.linkedPlanUnitId)
    : null;
  const linked = state.assets.filter((asset) => (
    directAssetIds.has(String(asset.id))
    || (linkedPlanUnitId !== null && Number(asset.toUnitId) === linkedPlanUnitId)
  ));
  return [...new Map(linked.map((asset) => [String(asset.id), asset])).values()].sort((a, b) => {
    const nameA = String(a?.emitterLabel || a?.name || "");
    const nameB = String(b?.emitterLabel || b?.name || "");
    return nameA.localeCompare(nameB) || (Number(a?.frequencyMHz) || 0) - (Number(b?.frequencyMHz) || 0);
  });
}

function getMappedTacticalAnchorForAsset(asset) {
  if (!Number.isFinite(Number(asset?.toUnitId))) {
    return null;
  }
  const object = getTacticalObjectByPlanUnitId(Number(asset.toUnitId));
  if (!object || !isTacticalPointGeometry(object.geometryType)) {
    return null;
  }
  return object;
}

function getAssetEffectiveMapPosition(asset) {
  if (hasAssetMapLocation(asset)) {
    return {
      lat: Number(asset.lat),
      lon: Number(asset.lon),
      tacticalObject: null,
    };
  }
  const tacticalObject = getMappedTacticalAnchorForAsset(asset);
  if (!tacticalObject || !Array.isArray(tacticalObject.coordinates) || tacticalObject.coordinates.length < 2) {
    return null;
  }
  return {
    lat: Number(tacticalObject.coordinates[0]),
    lon: Number(tacticalObject.coordinates[1]),
    tacticalObject,
  };
}

function openTacticalPopupPanel(tacticalId, panel = "summary", emitterId = "") {
  const object = getTacticalObjectById(tacticalId);
  const layer = object ? state.tacticalLayers.get(object.id) : null;
  if (!object || !layer) {
    return;
  }
  layer.setPopupContent(renderTacticalPopup(object, { panel, emitterId }));
  layer.openPopup();
}

function openLinkedEmitterPopupForAsset(asset) {
  if (!asset) {
    return;
  }
  const marker = state.assetMarkers.get(asset.id);
  if (marker) {
    state.map.setView(marker.getLatLng(), Math.max(state.map.getZoom(), 15));
    marker.openPopup();
    return;
  }
  const effective = getAssetEffectiveMapPosition(asset);
  const tacticalObject = effective?.tacticalObject || null;
  const layer = tacticalObject ? state.tacticalLayers.get(tacticalObject.id) : null;
  if (!effective || !tacticalObject || !layer) {
    return;
  }
  state.map.setView([effective.lat, effective.lon], Math.max(state.map.getZoom(), 15));
  layer.setPopupContent(renderTacticalPopup(tacticalObject, { panel: "emitter-detail", emitterId: asset.id }));
  layer.openPopup();
}

function createTacticalLeafletLayer(object, contentId, { live = false } = {}) {
  const tactical = normalizeTacticalObject(object);
  if (!state.map) return null;
  if (tactical.geometryType === "Point") {
    const layer = L.marker([Number(tactical.coordinates[0]), Number(tactical.coordinates[1])], {
      icon: buildTacticalPointIcon(tactical),
      draggable: false,
      pane: getMapContentPaneName(contentId),
    });
    layer.bindPopup(renderTacticalPopup(tactical, { live }));
    layer.on("click", () => focusMapContent(contentId));
    if (!live) {
      layer.on("contextmenu", (event) => {
        const linkedEmitters = getLinkedEmitterAssetsForTacticalObject(tactical);
        if (linkedEmitters.length) {
          event.originalEvent?.preventDefault?.();
          L.DomEvent.stopPropagation(event);
          layer.setPopupContent(renderTacticalPopup(tactical, { panel: "summary" }));
          layer.openPopup(event.latlng);
          return;
        }
        openMapContentMenuForLeafletEvent(event, contentId);
      });
    }
    applyTacticalLabel(tactical, layer);
    return layer;
  }

  const layer = createImportedLayer({
    contentId,
    geometryType: tactical.geometryType,
    coordinates: tactical.coordinates,
    shapeStyle: getTacticalShapeStyle(tactical),
    draggable: false,
  });
  layer.bindPopup(renderTacticalPopup(tactical, { live }));
  layer.on("click", () => focusMapContent(contentId));
  if (!live) {
    layer.on("contextmenu", (event) => openMapContentMenuForLeafletEvent(event, contentId));
  }
  applyTacticalLabel(tactical, layer);
  return layer;
}

function renderTacticalObjectLayer(object) {
  if (!state.map) return null;
  const tactical = normalizeTacticalObject(object);
  const existing = state.tacticalLayers.get(tactical.id);
  existing?.remove?.();
  const contentId = buildTacticalContentId(tactical.id);
  const layer = createTacticalLeafletLayer(tactical, contentId, { live: false });
  if (!layer) return null;
  state.tacticalLayers.set(tactical.id, layer);
  if (!isContentEffectivelyHidden(contentId)) {
    layer.addTo(state.map);
  }
  return layer;
}

function refreshAllTacticalLayers() {
  (state.tacticalObjects || []).forEach((obj) => renderTacticalObjectLayer(obj));
  state.takRuntime?.objectsByUid?.forEach((obj) => renderTakLiveLayer(obj));
}

function removeTacticalObjectLayer(objectId) {
  const layer = state.tacticalLayers.get(objectId);
  layer?.remove?.();
  state.tacticalLayers.delete(objectId);
}

function renderTakLiveLayer(object) {
  if (!state.map) return null;
  const selfUid = buildTakGpsUid();
  const contentId = buildTakLiveContentId(object.uid);
  const existing = state.takRuntime.layersByUid.get(object.uid);
  existing?.remove?.();
  const layer = createTacticalLeafletLayer(object, contentId, { live: true });
  if (!layer) return null;
  // Right-click on a live PLI track opens a chat with that contact (skip self)
  if (object.uid !== selfUid) {
    layer.on("contextmenu", (e) => {
      L.DomEvent.stopPropagation(e);
      const callsign = escapeHtml(object.name || object.designator || object.uid);
      showTakContactContextMenu(e.originalEvent || e, object.uid, callsign);
    });
  }
  state.takRuntime.layersByUid.set(object.uid, layer);
  if (!isContentEffectivelyHidden(contentId)) {
    layer.addTo(state.map);
  }
  return layer;
}

function removeTakLiveRuntimeObject(uid) {
  const contentId = buildTakLiveContentId(uid);
  state.takRuntime.layersByUid.get(uid)?.remove?.();
  state.takRuntime.layersByUid.delete(uid);
  state.takRuntime.objectsByUid.delete(uid);
  state.mapContentAssignments.delete(contentId);
  state.mapContentOrder = state.mapContentOrder.filter((entryId) => entryId !== contentId);
  state.hiddenContentIds.delete(contentId);
  state.hiddenLabelContentIds.delete(contentId);
}

function buildTakLiveObject(contact, profile) {
  const cotType = String(contact?.cotType || "");
  const schemaDetail = normalizeTakSchemaDetail(contact?.detail, {
    callsign: contact?.callsign,
    milsymId: contact?.sidc,
  });
  const sidc = String(contact?.sidc || schemaDetail?.milsym?.id || "").trim();
  const symbolUniqueId = normalizeMilstdUniqueId(contact?.symbolUniqueId || extractMilstdUniqueIdFromSidc(sidc) || "");
  const domain = deriveTacticalDomainFromCotType(cotType);
  const objectClass = String(cotType || "").toLowerCase().startsWith("a-") || sidc || symbolUniqueId ? "unit" : "track";
  const affiliation = sidc
    ? deriveTacticalAffiliationFromMilstdSidc(sidc, deriveTacticalAffiliationFromCotType(cotType))
    : deriveTacticalAffiliationFromCotType(cotType);
  const detail = {
    team: schemaDetail?.group?.name || "",
    role: schemaDetail?.group?.role || "",
    lastSeenAt: contact?.lastSeenAt || "",
    usericonPath: schemaDetail?.usericon?.iconsetpath || buildTakSchema2525UserIconPath(cotType),
    milsymId: sidc,
    milsymUniqueId: symbolUniqueId,
    takSchema: schemaDetail,
  };
  return normalizeTacticalObject({
    id: `live-${contact.uid}`,
    uid: contact.uid,
    source: "tak-live",
    objectClass,
    geometryType: "Point",
    coordinates: [Number(contact.lat), Number(contact.lon)],
    cotType,
    domain,
    affiliation,
    unitType: symbolUniqueId || deriveTacticalUnitTypeFromCotType(cotType, domain),
    symbolUniqueId,
    sidc,
    size: "team",
    name: schemaDetail?.contact?.callsign || contact.uid,
    designator: schemaDetail?.contact?.callsign || "",
    remarks: schemaDetail?.remarks?.text || "",
    detail,
    staleAt: contact.stale || "",
    provider: profile?.label || "TAK",
    readOnly: true,
    showLabel: true,
  });
}

function upsertTakLiveContact(contact, profile) {
  if (!Number.isFinite(Number(contact?.lat)) || !Number.isFinite(Number(contact?.lon)) || !contact?.uid) {
    return null;
  }
  const object = buildTakLiveObject(contact, profile);
  state.takRuntime.objectsByUid.set(object.uid, object);
  state.takRuntime.lastEventAt = nowIso();
  const folderId = ensureTakLiveFolder(object.objectClass);
  const contentId = buildTakLiveContentId(object.uid);
  setMapContentFolderId(contentId, folderId);
  if (!state.mapContentOrder.includes(contentId)) {
    state.mapContentOrder.push(contentId);
  }
  renderTakLiveLayer(object);
  return object;
}

function removeTakLiveContactsNotIn(seenUids = new Set()) {
  [...state.takRuntime.objectsByUid.keys()].forEach((uid) => {
    if (!seenUids.has(uid)) {
      removeTakLiveRuntimeObject(uid);
    }
  });
}

function clearTakLiveContacts() {
  [...state.takRuntime.objectsByUid.keys()].forEach((uid) => removeTakLiveRuntimeObject(uid));
  renderMapContents();
  syncCesiumEntities();
  renderTakContactsOverlay();
}

function createTakDebugEntry(direction, summary, detail = "", level = "info", at = nowIso()) {
  return {
    at,
    direction,
    summary: String(summary || "").slice(0, 240),
    detail: String(detail || "").slice(0, 1600),
    level,
  };
}

function pushClientTakDebug(direction, summary, detail = "", level = "info") {
  state.takRuntime.clientDebugEvents.push(createTakDebugEntry(direction, summary, detail, level));
  if (state.takRuntime.clientDebugEvents.length > 80) {
    state.takRuntime.clientDebugEvents.splice(0, state.takRuntime.clientDebugEvents.length - 80);
  }
  renderMapTakDebugPanel();
}

function getCombinedTakDebugEvents() {
  const merged = [
    ...(Array.isArray(state.takRuntime.debugEvents) ? state.takRuntime.debugEvents : []),
    ...(Array.isArray(state.takRuntime.clientDebugEvents) ? state.takRuntime.clientDebugEvents : []),
  ];
  return merged
    .filter((entry) => entry && (entry.summary || entry.detail))
    .sort((a, b) => String(a.at || "").localeCompare(String(b.at || "")))
    .slice(-120);
}

function stopTakLivePolling({ clearContacts = false } = {}) {
  if (state.takLive.pollTimerId) {
    window.clearTimeout(state.takLive.pollTimerId);
    state.takLive.pollTimerId = null;
  }
  if (state.takRuntime.gpsPublishTimerId) {
    window.clearTimeout(state.takRuntime.gpsPublishTimerId);
    state.takRuntime.gpsPublishTimerId = null;
  }
  state.takLive.projectId = null;
  state.takLive.status = "idle";
  state.takLive.message = "";
  state.takLive.lastPollAt = "";
  state.takRuntime.projectId = null;
  state.takRuntime.status = "idle";
  state.takRuntime.message = "";
  state.takRuntime.profileId = "";
  state.takRuntime.connectTarget = "";
  state.takRuntime.verifyAs = "";
  state.takRuntime.lastPollAt = "";
  state.takRuntime.lastConnectedAt = "";
  state.takRuntime.lastOutboundAt = "";
  state.takRuntime.lastContactCount = 0;
  state.takRuntime.gpsPublishInFlight = false;
  state.takRuntime.gpsLastPublishStatus = "idle";
  state.takRuntime.gpsLastPublishMessage = "";
  state.takRuntime.gpsLastSentFixKey = "";
  state.takRuntime.debugEvents = [];
  state.takRuntime.clientDebugEvents = [];
  if (clearContacts) {
    clearTakLiveContacts();
  }
  renderMapTakDebugPanel();
}

async function pollTakLiveContacts({ immediate = false } = {}) {
  if (!state.session.token || !state.session.activeProjectId || !isTakEnabledForProject(state.session.activeProjectId)) {
    stopTakLivePolling({ clearContacts: true });
    return;
  }

  const currentProjectId = state.session.activeProjectId;
  state.takLive.projectId = currentProjectId;
  if (!immediate) {
    await new Promise((resolve) => window.setTimeout(resolve, 0));
  }

  try {
    const payload = await apiFetch(`/projects/${currentProjectId}/tak-contacts`);
    if (state.session.activeProjectId !== currentProjectId) {
      return;
    }

    state.takLive.status = payload.status || (payload.linked ? "connected" : "unlinked");
    state.takLive.message = payload.message || "";
    state.takLive.lastPollAt = nowIso();
    state.takRuntime.status = state.takLive.status;
    state.takRuntime.message = state.takLive.message;
    state.takRuntime.connectTarget = payload.connectTarget || "";
    state.takRuntime.verifyAs = payload.verifyAs || "";
    state.takRuntime.lastPollAt = state.takLive.lastPollAt;
    state.takRuntime.lastConnectedAt = payload.connectedAt || "";
    state.takRuntime.lastOutboundAt = payload.lastOutboundAt || "";
    state.takRuntime.lastContactCount = Number(payload.contactCount ?? (Array.isArray(payload.contacts) ? payload.contacts.length : 0)) || 0;
    state.takRuntime.debugEvents = Array.isArray(payload.debugEvents) ? payload.debugEvents : [];

    if (!payload.linked) {
      clearTakLiveContacts();
    } else {
      const profile = payload.profile ?? getTakProfileForProject(currentProjectId);
      state.takRuntime.profileId = profile?.id || "";
      state.takRuntime.projectId = currentProjectId;
      const selfUid = buildTakGpsUid(currentProjectId);
      const seen = new Set();
      (Array.isArray(payload.contacts) ? payload.contacts : []).forEach((contact) => {
        if (!contact?.uid || contact.uid === selfUid) return;
        seen.add(contact.uid);
        upsertTakLiveContact(contact, profile);
      });
      removeTakLiveContactsNotIn(seen);
      renderMapContents();
      syncCesiumEntities();
    }
    // Process any incoming GeoChat messages returned by the poll
    if (Array.isArray(payload.chatMessages)) {
      for (const msg of payload.chatMessages) {
        if (msg?.senderUid && msg?.text) {
          await handleIncomingTakChatMessage(msg);
        }
      }
    }
    renderMapTakDebugPanel();
    updateTakTriggeredStatusDisplay();
    renderTakContactsOverlay();
  } catch (error) {
    state.takLive.status = "error";
    state.takLive.message = error.message;
    state.takRuntime.status = "error";
    state.takRuntime.message = error.message;
    pushClientTakDebug("status", "TAK poll failed", error.message, "error");
    updateTakTriggeredStatusDisplay();
    renderTakContactsOverlay();
  } finally {
    if (state.session.token && state.session.activeProjectId === currentProjectId && isTakEnabledForProject(currentProjectId)) {
      state.takLive.pollTimerId = window.setTimeout(() => {
        pollTakLiveContacts().catch(() => {});
      }, 5000);
    }
  }
}

// â”€â”€ TAK Triggered Prompting â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

function renderTakTriggerChips() {
  if (!dom.takTriggerChips) return;
  const prefixes = state.settings.takTriggerPrefixes || ["/ai"];
  dom.takTriggerChips.innerHTML = prefixes.map((p, i) => `
    <span class="tak-trigger-chip">
      <span class="tak-trigger-chip-text">${escapeHtml(p)}</span>
      <button type="button" class="tak-trigger-chip-remove" data-index="${i}" aria-label="Remove ${escapeHtml(p)}">&#10005;</button>
    </span>
  `).join("");
  dom.takTriggerChips.querySelectorAll(".tak-trigger-chip-remove").forEach((btn) => {
    btn.addEventListener("click", () => {
      const idx = Number(btn.dataset.index);
      state.settings.takTriggerPrefixes = state.settings.takTriggerPrefixes.filter((_, i) => i !== idx);
      if (!state.settings.takTriggerPrefixes.length) state.settings.takTriggerPrefixes = ["/ai"];
      renderTakTriggerChips();
      persistSettings();
    });
  });
}

function addTakTriggerPrefix(raw) {
  const prefix = raw.trim().toLowerCase().replace(/\s+/g, "");
  if (!prefix) return;
  const existing = state.settings.takTriggerPrefixes || [];
  if (existing.includes(prefix)) return;
  state.settings.takTriggerPrefixes = [...existing, prefix];
  renderTakTriggerChips();
  persistSettings();
}

function syncTakTriggeredPromptingUi() {
  const enabled = Boolean(state.settings.takTriggeredPromptingEnabled);
  dom.takTriggeredPromptingSection?.classList.toggle("tak-triggered-disabled", !enabled);
  dom.takTriggeredPromptingSection?.querySelectorAll("input, textarea, button").forEach((el) => {
    if (el.id === "takTriggerAddBtn" || el.classList.contains("tak-trigger-chip-remove")) {
      el.disabled = !enabled;
    } else if (el.tagName !== "BUTTON" || el.id !== "takTriggeredPromptingToggle") {
      el.disabled = !enabled;
    }
  });
  updateTakTriggeredStatusDisplay();
}

function updateTakTriggeredStatusDisplay() {
  if (!dom.takTriggeredStatusText) return;
  const enabled = Boolean(state.settings.takTriggeredPromptingEnabled);
  if (!enabled) {
    dom.takTriggeredStatusText.textContent = "Disabled.";
    dom.takTriggeredStatusText.dataset.level = "idle";
    return;
  }
  const takStatus = state.takRuntime.status;
  if (takStatus === "connected") {
    dom.takTriggeredStatusText.textContent = "Active â€” listening for TAK GeoChat triggers.";
    dom.takTriggeredStatusText.dataset.level = "ok";
  } else if (takStatus === "error") {
    dom.takTriggeredStatusText.textContent = "TAK connection error â€” triggers will not fire.";
    dom.takTriggeredStatusText.dataset.level = "error";
  } else {
    dom.takTriggeredStatusText.textContent = "Waiting for TAK connectionâ€¦";
    dom.takTriggeredStatusText.dataset.level = "idle";
  }
  if (dom.takTriggeredCountReceived) dom.takTriggeredCountReceived.textContent = String(state.takRuntime.triggeredPromptCountReceived);
  if (dom.takTriggeredCountReplied) dom.takTriggeredCountReplied.textContent = String(state.takRuntime.triggeredPromptCountReplied);
  if (dom.takTriggeredCountFailed) dom.takTriggeredCountFailed.textContent = String(state.takRuntime.triggeredPromptCountFailed);
}

// â”€â”€ TAK Contacts Overlay & Chat â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

function getTakChatThread(uid, callsign) {
  if (!state.takChat.threads.has(uid)) {
    state.takChat.threads.set(uid, { uid, callsign: callsign || uid, messages: [], unread: 0 });
  }
  const t = state.takChat.threads.get(uid);
  if (callsign && callsign !== uid) t.callsign = callsign;
  return t;
}

function takChatAddMessage(uid, callsign, { role, text, isAiRelay = false }) {
  const thread = getTakChatThread(uid, callsign);
  thread.messages.push({ role, text, ts: Date.now(), isAiRelay });
  const isActive = state.takChat.activeUid === uid && state.takChat.panelOpen;
  if (!isActive) {
    thread.unread++;
    state.takChat.totalUnread++;
  }
  renderTakContactsOverlay();
  if (state.takChat.activeUid === uid) renderTakChatMessages();
}

function renderTakContactsOverlay() {
  if (!dom.takContactsOverlay) return;

  // Show overlay only when TAK is connected
  const connected = state.takRuntime.status === "connected";
  dom.takContactsOverlay.classList.toggle("hidden", !connected);

  // Status dot color
  if (dom.takContactsStatusDot) {
    dom.takContactsStatusDot.dataset.status = connected ? "connected" : "idle";
  }

  // Unread badge
  const unread = state.takChat.totalUnread;
  if (dom.takContactsUnread) {
    dom.takContactsUnread.textContent = unread > 99 ? "99+" : String(unread);
    dom.takContactsUnread.classList.toggle("hidden", unread === 0);
  }

  // Chevron direction
  if (dom.takContactsChevron) {
    dom.takContactsChevron.setAttribute("aria-expanded", state.takChat.panelOpen ? "true" : "false");
    dom.takContactsChevron.classList.toggle("open", state.takChat.panelOpen);
  }

  // Panel visibility
  if (dom.takContactsPanel) {
    dom.takContactsPanel.classList.toggle("hidden", !state.takChat.panelOpen || state.takChat.activeUid !== null);
  }
  if (dom.takChatWindow) {
    dom.takChatWindow.classList.toggle("hidden", !state.takChat.panelOpen || state.takChat.activeUid === null);
  }

  renderTakContactsList();
}

function renderTakContactsList() {
  if (!dom.takContactsList) return;
  const selfUid = buildTakGpsUid();
  const contacts = [...state.takRuntime.objectsByUid.values()].filter((c) => c.uid !== selfUid);
  if (dom.takContactsPanelCount) {
    dom.takContactsPanelCount.textContent = `${contacts.length} online`;
  }
  if (!contacts.length) {
    dom.takContactsList.innerHTML = '<div class="tak-contacts-empty">No contacts connected.</div>';
    return;
  }
  dom.takContactsList.innerHTML = contacts.map((c) => {
    const uid = c.uid;
    const name = escapeHtml(c.name || c.designator || uid);
    const thread = state.takChat.threads.get(uid);
    const unread = thread?.unread || 0;
    const lastMsg = thread?.messages[thread.messages.length - 1];
    const preview = lastMsg ? escapeHtml(lastMsg.text.slice(0, 40)) : "";
    const aff = c.affiliation || "unknown";
    return `<button class="tak-contact-row" data-uid="${escapeHtml(uid)}" type="button">
      <span class="tak-contact-avatar tak-contact-avatar--${escapeHtml(aff)}">${escapeHtml((c.name || uid).charAt(0).toUpperCase())}</span>
      <span class="tak-contact-info">
        <span class="tak-contact-name">${name}</span>
        ${preview ? `<span class="tak-contact-preview">${preview}${lastMsg.text.length > 40 ? "â€¦" : ""}</span>` : ""}
      </span>
      ${unread > 0 ? `<span class="tak-contact-unread-pip">${unread}</span>` : ""}
    </button>`;
  }).join("");

  dom.takContactsList.querySelectorAll(".tak-contact-row").forEach((btn) => {
    btn.addEventListener("click", (e) => { e.stopPropagation(); openTakChat(btn.dataset.uid); });
  });
}

function openTakChat(uid) {
  const contact = state.takRuntime.objectsByUid.get(uid);
  if (!contact) return;
  state.takChat.panelOpen = true;
  state.takChat.activeUid = uid;
  const thread = getTakChatThread(uid, contact.name || contact.designator || uid);
  state.takChat.totalUnread = Math.max(0, state.takChat.totalUnread - thread.unread);
  thread.unread = 0;
  if (dom.takChatContactName) dom.takChatContactName.textContent = thread.callsign;
  renderTakChatMessages();
  renderTakContactsOverlay();
  requestAnimationFrame(() => dom.takChatInput?.focus());
}

// Called from map right-click context menu on a live PLI track
function openTakChatFromMap(uid) {
  openTakChat(uid);
}

function showTakContactContextMenu(nativeEvent, uid, callsign) {
  // Remove any existing TAK contact context menu
  document.getElementById("_takContactCtxMenu")?.remove();
  const contentId = buildTakLiveContentId(uid);
  const hiddenBySelf = state.hiddenLabelContentIds.has(contentId);
  const hiddenByAncestorFolderId = getContentLabelHiddenAncestorFolderId(contentId);
  const labelDisabled = Boolean(hiddenByAncestorFolderId) && !hiddenBySelf;
  const labelActionText = hiddenByAncestorFolderId && !hiddenBySelf
    ? "Label Hidden by Folder"
    : hiddenBySelf
      ? "Show Label"
      : "Hide Label";
  const menu = document.createElement("div");
  menu.id = "_takContactCtxMenu";
  menu.className = "tak-contact-ctx-menu";
  menu.innerHTML = `<button class="tak-contact-ctx-item" type="button" data-tak-contact-action="message">
    <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>
    Message <strong>${callsign}</strong>
  </button>
  <button class="tak-contact-ctx-item" type="button" data-tak-contact-action="labels"${labelDisabled ? " disabled" : ""}>
    <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M4 7h16"/><path d="M4 12h11"/><path d="M4 17h8"/></svg>
    ${escapeHtml(labelActionText)}
  </button>`;
  const x = nativeEvent?.clientX ?? 0;
  const y = nativeEvent?.clientY ?? 0;
  menu.style.cssText = `position:fixed;left:${x}px;top:${y}px;z-index:9999`;
  document.body.appendChild(menu);
  menu.querySelector('[data-tak-contact-action="message"]').addEventListener("click", (e) => {
    e.stopPropagation();
    menu.remove();
    openTakChatFromMap(uid);
  });
  menu.querySelector('[data-tak-contact-action="labels"]')?.addEventListener("click", (e) => {
    e.stopPropagation();
    menu.remove();
    toggleMapContentLabels(contentId);
  });
  // Dismiss on any outside click
  const dismiss = (e) => { if (!menu.contains(e.target)) { menu.remove(); document.removeEventListener("click", dismiss, true); } };
  setTimeout(() => document.addEventListener("click", dismiss, true), 0);
}

function closeTakChat() {
  state.takChat.activeUid = null;
  renderTakContactsOverlay();
}

function renderTakChatMessages() {
  if (!dom.takChatMessages) return;
  const uid = state.takChat.activeUid;
  if (!uid) { dom.takChatMessages.innerHTML = ""; return; }
  const thread = state.takChat.threads.get(uid);
  if (!thread || !thread.messages.length) {
    dom.takChatMessages.innerHTML = '<div class="tak-chat-empty">No messages yet. Say hello!</div>';
    return;
  }
  dom.takChatMessages.innerHTML = thread.messages.map((m) => {
    const ts = new Date(m.ts).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
    if (m.role === "outbound") {
      // RF SIM user sent this
      return `<div class="tak-msg tak-msg--out">
        <div class="tak-msg-header"><span>You</span><span class="tak-msg-ts">${ts}</span></div>
        <div class="tak-msg-bubble">${escapeHtml(m.text)}</div>
      </div>`;
    }
    if (m.isAiRelay) {
      // AI-generated reply sent to the TAK contact on the user's behalf
      return `<div class="tak-msg tak-msg--ai">
        <div class="tak-msg-header"><span class="tak-msg-ai-label">AI</span><span class="tak-msg-ts">${ts}</span></div>
        <div class="tak-msg-bubble">${escapeHtml(m.text)}</div>
      </div>`;
    }
    // Inbound from TAK contact
    const name = escapeHtml(thread.callsign);
    return `<div class="tak-msg tak-msg--in">
      <div class="tak-msg-header"><span>${name}</span><span class="tak-msg-ts">${ts}</span></div>
      <div class="tak-msg-bubble">${escapeHtml(m.text)}</div>
    </div>`;
  }).join("");
  dom.takChatMessages.scrollTop = dom.takChatMessages.scrollHeight;
}

async function sendTakChatMessage(uid, text) {
  const contact = state.takRuntime.objectsByUid.get(uid);
  if (!contact || !text.trim()) return;
  const callsign = contact.name || contact.designator || uid;
  // Optimistically append outbound message
  takChatAddMessage(uid, callsign, { role: "outbound", text });
  try {
    await sendTakChatReply({ toUid: uid, toCallsign: callsign, text });
  } catch (err) {
    pushClientTakDebug("outbound", "TAK chat send failed", err.message, "error");
  }
}

function initTakContactsOverlay() {
  if (!dom.takContactsOverlay) return;

  // Toggle panel on chevron or pill click
  dom.takContactsChevron?.addEventListener("click", (e) => {
    e.stopPropagation();
    state.takChat.panelOpen = !state.takChat.panelOpen;
    if (!state.takChat.panelOpen) state.takChat.activeUid = null;
    renderTakContactsOverlay();
  });
  dom.takContactsPill?.addEventListener("click", (e) => {
    if (e.target === dom.takContactsChevron || dom.takContactsChevron?.contains(e.target)) return;
    state.takChat.panelOpen = !state.takChat.panelOpen;
    if (!state.takChat.panelOpen) state.takChat.activeUid = null;
    renderTakContactsOverlay();
  });

  // Back button: close chat, show contact list
  dom.takChatBack?.addEventListener("click", closeTakChat);

  // Close button: collapse everything
  dom.takChatCloseBtn?.addEventListener("click", () => {
    state.takChat.panelOpen = false;
    state.takChat.activeUid = null;
    renderTakContactsOverlay();
  });

  // Send message form
  dom.takChatForm?.addEventListener("submit", async (e) => {
    e.preventDefault();
    const text = dom.takChatInput?.value.trim();
    if (!text || !state.takChat.activeUid) return;
    dom.takChatInput.value = "";
    await sendTakChatMessage(state.takChat.activeUid, text);
  });

  document.addEventListener("click", (e) => {
    if (!dom.takContactsOverlay?.contains(e.target)) {
      if (state.takChat.panelOpen) {
        state.takChat.panelOpen = false;
        state.takChat.activeUid = null;
        renderTakContactsOverlay();
      }
    }
  });
}

/**
 * Entry point for incoming TAK GeoChat messages.
 * Call this when a GeoChat CoT event is received from the TAK server.
 * @param {{ senderUid: string, senderCallsign: string, text: string, chatroom?: string }} msg
 */
async function handleIncomingTakChatMessage(msg) {
  const uid = msg.senderUid || "";
  const callsign = msg.senderCallsign || uid;
  const text = (msg.text || "").trim();
  if (!text) return;

  pushClientTakDebug("inbound", "TAK GeoChat received", `From ${callsign}: ${text.slice(0, 80)}`, "info");

  // Always add inbound message to the chat thread
  takChatAddMessage(uid, callsign, { role: "inbound", text });

  if (state.settings.takTriggeredNotify) {
    setStatus(`TAK message from ${callsign}: "${text.slice(0, 60)}${text.length > 60 ? "â€¦" : ""}"`);
  }

  // Check for AI trigger prefix
  const prefixes = (state.settings.takTriggerPrefixes || ["/ai"]).map((p) => p.toLowerCase());
  const lc = text.toLowerCase();
  const matchedPrefix = prefixes.find((p) => lc.startsWith(p));

  if (!matchedPrefix || !state.settings.takTriggeredPromptingEnabled) return;

  const prompt = text.slice(matchedPrefix.length).trim();
  if (!prompt) return;

  state.takRuntime.triggeredPromptCountReceived++;
  updateTakTriggeredStatusDisplay();

  if (state.settings.takTriggeredLog) {
    appendAiMessage("system", `[TAK Prompt from ${escapeHtml(callsign)}] ${escapeHtml(prompt)}`);
  }

  try {
    const systemPrefix = (state.settings.takTriggeredSystemPrompt || "").trim();
    const fullPrompt = [systemPrefix, prompt].filter(Boolean).join("\n\n");
    const response = await callAiPlanningAssistantOptimized(fullPrompt, [], [], [], {
      requestClassOverride: AI_REQUEST_CLASS.TAK_TRIGGERED_HEADLESS,
      includeMapContext: Boolean(state.settings.takTriggeredIncludeMapContext),
      onToken: () => {},
    }).then((result) => result?.assistantMessage || "");
    if (!response) throw new Error("No response from AI provider.");

    state.takRuntime.triggeredPromptCountReplied++;

    // Add AI relay message to the chat thread (distinct colour/label)
    takChatAddMessage(uid, callsign, { role: "outbound", text: response, isAiRelay: true });

    if (state.settings.takTriggeredLog) {
      appendAiMessage("assistant", `[TAK Reply to ${escapeHtml(callsign)}] ${escapeHtml(response)}`);
    }
    pushClientTakDebug("outbound", "TAK triggered reply sent", `To ${callsign}: ${response.slice(0, 80)}`, "info");
    await sendTakChatReply({ toUid: uid, toCallsign: callsign, text: response });
  } catch (err) {
    state.takRuntime.triggeredPromptCountFailed++;
    pushClientTakDebug("outbound", "TAK triggered reply failed", err.message, "error");
  } finally {
    updateTakTriggeredStatusDisplay();
  }
}

/**
 * Stub: send a GeoChat reply back to the originating TAK contact.
 * Replace with real CoT/GeoChat publish when the backend supports it.
 */
async function sendTakChatReply({ toUid, toCallsign, text }) {
  const projectId = state.session.activeProjectId;
  const token = state.session.token;
  if (!projectId || !token) throw new Error("No active project or session.");
  const fromCallsign = getTakGpsCallsign();
  const fromUid = buildTakGpsUid(projectId);
  await apiFetch(`/projects/${projectId}/tak-chat`, {
    method: "POST",
    body: JSON.stringify({ toUid, toCallsign, text, fromCallsign, fromUid }),
  });
}

/**
 * Stub: run an AI prompt without updating the main chat UI thread.
 * Wraps the existing AI provider call pattern for headless use.
 */
async function runAiPromptHeadless(prompt) {
  if (!getEffectiveAiConfig()) throw new Error("No AI provider configured.");
  let accumulated = "";
  await callAiPlanningAssistantOptimized(prompt, [], [], [], {
    onToken: (text) => { accumulated = text; },
    requestClassOverride: AI_REQUEST_CLASS.TAK_TRIGGERED_HEADLESS,
  });
  return accumulated.trim();
}

function refreshTakLiveFeed({ immediate = false } = {}) {
  stopTakLivePolling({ clearContacts: !isTakEnabledForProject(state.session.activeProjectId) });
  if (!state.session.token || !state.session.activeProjectId || !isTakEnabledForProject(state.session.activeProjectId)) {
    renderMapTakDebugPanel();
    return;
  }
  void pollTakLiveContacts({ immediate }).catch(() => {});
  queueTakGpsPublish({ immediate: true });
}

const TAK_GPS_PUBLISH_INTERVAL_MS = 8000;

function buildTakGpsUid(projectId = state.session.activeProjectId) {
  const rawIdentity = state.session.user?.username || state.session.user?.email || state.session.user?.fullName || "user";
  const safeIdentity = String(rawIdentity)
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 80) || "user";
  return `rfsim:${projectId || "project"}:${safeIdentity}:gps`;
}

function getTakGpsCallsign() {
  const takCallsign = state.takIdentity?.callsign?.trim();
  if (takCallsign) {
    return takCallsign.slice(0, 120);
  }
  return deriveDefaultTakCallsign();
}

function queueTakGpsPublish({ immediate = false } = {}) {
  if (state.takRuntime.gpsPublishTimerId) {
    window.clearTimeout(state.takRuntime.gpsPublishTimerId);
    state.takRuntime.gpsPublishTimerId = null;
  }
  if (!state.session.token || !state.session.activeProjectId || !isTakEnabledForProject(state.session.activeProjectId) || !state.gps.location) {
    return;
  }
  if (state.takRuntime.gpsPublishInFlight) {
    return;
  }
  const lastPublishMs = state.takRuntime.gpsLastPublishAt ? Date.parse(state.takRuntime.gpsLastPublishAt) : 0;
  const elapsedMs = Number.isFinite(lastPublishMs) ? (Date.now() - lastPublishMs) : Number.POSITIVE_INFINITY;
  const delayMs = immediate ? 0 : Math.max(0, TAK_GPS_PUBLISH_INTERVAL_MS - elapsedMs);
  state.takRuntime.gpsPublishTimerId = window.setTimeout(() => {
    state.takRuntime.gpsPublishTimerId = null;
    void publishTakGpsLocation();
  }, delayMs);
}

async function publishTakGpsLocation() {
  if (state.takRuntime.gpsPublishInFlight || !state.session.token || !state.session.activeProjectId || !isTakEnabledForProject(state.session.activeProjectId) || !state.gps.location) {
    return;
  }

  const fix = state.gps.location;
  const projectId = state.session.activeProjectId;
  const callsign = getTakGpsCallsign();
  const sourceMode = state.gps.mode || "gps";
  const displayTypeMeta = getTakDisplayTypeMeta();
  const payload = {
    lat: Number(fix.lat),
    lon: Number(fix.lon),
    hae: Number.isFinite(Number(fix.altitudeM)) ? Number(fix.altitudeM) : undefined,
    accuracyM: Number.isFinite(Number(fix.accuracyM)) ? Number(fix.accuracyM) : undefined,
    ce: Number.isFinite(Number(fix.accuracyM)) ? Number(fix.accuracyM) : undefined,
    le: Number.isFinite(Number(fix.accuracyM)) ? Number(fix.accuracyM) : undefined,
    callsign,
    uid: buildTakGpsUid(projectId),
    how: sourceMode === "usb" ? "m-p" : "m-g",
    sourceMode,
    team: state.takIdentity.team,
    role: state.takIdentity.role,
    cotType: displayTypeMeta.cotType,
    displayType: displayTypeMeta.label,
  };

  state.takRuntime.gpsPublishInFlight = true;
  pushClientTakDebug("outbound", "Publishing RF SIM GPS PLI", `${callsign} ${payload.lat.toFixed(5)}, ${payload.lon.toFixed(5)} via ${sourceMode}`, "info");

  try {
    const result = await apiFetch(`/projects/${projectId}/tak-location`, {
      method: "POST",
      body: JSON.stringify(payload),
    });
    if (state.session.activeProjectId !== projectId) {
      return;
    }
    state.takRuntime.gpsLastPublishAt = nowIso();
    state.takRuntime.gpsLastPublishStatus = result?.sent ? "sent" : "pending";
    state.takRuntime.gpsLastPublishMessage = result?.message || "GPS PLI published.";
    state.takRuntime.lastOutboundAt = result?.lastOutboundAt || state.takRuntime.gpsLastPublishAt;
    state.takRuntime.debugEvents = Array.isArray(result?.debugEvents) ? result.debugEvents : state.takRuntime.debugEvents;
    state.takRuntime.lastContactCount = Number(result?.contactCount ?? state.takRuntime.lastContactCount) || 0;
    pushClientTakDebug("outbound", "GPS PLI sent", state.takRuntime.gpsLastPublishMessage, "info");
  } catch (error) {
    state.takRuntime.gpsLastPublishAt = nowIso();
    state.takRuntime.gpsLastPublishStatus = "error";
    state.takRuntime.gpsLastPublishMessage = error.message;
    pushClientTakDebug("outbound", "GPS PLI failed", error.message, "error");
  } finally {
    state.takRuntime.gpsPublishInFlight = false;
    renderMapTakDebugPanel();
  }
}

function buildTakTacticalCotEvent(object) {
  const tactical = normalizeTacticalObject(object);
  if (tactical.geometryType !== "Point" || !Array.isArray(tactical.coordinates) || tactical.coordinates.length < 2) {
    return "";
  }
  const [lat, lon] = tactical.coordinates;
  if (!Number.isFinite(Number(lat)) || !Number.isFinite(Number(lon)) || !tactical.cotType) {
    return "";
  }
  const now = new Date();
  const stale = tactical.staleAt ? new Date(tactical.staleAt) : new Date(now.getTime() + 300000);
  const callsign = tactical.designator || tactical.name || tactical.uid;
  const team = tactical.detail?.team || state.takIdentity.team || "Cyan";
  const role = tactical.detail?.role || state.takIdentity.role || "Team Member";
  const milsymId = String(tactical.sidc || tactical.detail?.milsymId || "").trim();
  const usericonPath = milsymId ? "" : (tactical.detail?.usericonPath || buildTakSchema2525UserIconPath(tactical.cotType));
  const remarks = tactical.remarks || tactical.name || "RF SIM Tactical Object";
  const detailNodes = buildTakSchemaDetailXml({
    contact: { callsign },
    group: { name: team, role },
    track: tactical.objectClass === "track" ? { course: "0", speed: "0" } : null,
    milsym: milsymId ? { id: milsymId } : null,
    usericon: usericonPath ? { iconsetpath: usericonPath } : null,
    remarks: { text: remarks },
  });
  return `<event version="2.0" uid="${escapeHtml(tactical.uid)}" type="${escapeHtml(tactical.cotType)}" how="h-g-i-g-o" time="${now.toISOString()}" start="${now.toISOString()}" stale="${stale.toISOString()}"><point lat="${Number(lat).toFixed(6)}" lon="${Number(lon).toFixed(6)}" hae="0.0" ce="25.0" le="35.0"/><detail>${detailNodes}</detail></event>`;
}

function getDefaultTakCotTypeForImportedItem(item) {
  if (item?.geometryType === "Point") return "b-m-p-s-m";
  if (item?.geometryType === "LineString") return "b-m-r";
  return "u-d-f";
}

function getTakStreamTargetForContent(contentId) {
  if (!contentId) {
    return null;
  }
  if (contentId.startsWith("asset:")) {
    const asset = state.assets.find((entry) => `asset:${entry.id}` === contentId);
    return asset ? { kind: "asset", item: asset } : null;
  }
  if (contentId.startsWith("imported:")) {
    const item = state.importedItems.find((entry) => `imported:${entry.id}` === contentId);
    return item ? { kind: "imported", item } : null;
  }
  if (contentId.startsWith("tactical:")) {
    const item = getTacticalObjectById(contentId.slice("tactical:".length));
    return item ? { kind: "tactical", item } : null;
  }
  return null;
}

function isTakStreamingSupportedContent(contentId) {
  const target = getTakStreamTargetForContent(contentId);
  if (!target) {
    return false;
  }
  if (target.kind === "asset") {
    return true;
  }
  if (target.kind === "tactical") {
    return !target.item.readOnly;
  }
  return Boolean(target.item.drawn || target.item.tak);
}

function isTakStreamingEnabledForContent(contentId) {
  if (!isTakStreamingSupportedContent(contentId)) {
    return false;
  }
  const target = getTakStreamTargetForContent(contentId);
  if (!target) {
    return false;
  }
  if (target.kind === "tactical") {
    return target.item.streamToTak ?? getDefaultTakStreamingEnabled();
  }
  return target.item.tak?.streamEnabled ?? getDefaultTakStreamingEnabled();
}

function ensureTakMetadataForAsset(asset) {
  const tak = normalizeTakMetadata(asset?.tak, { defaultStreamEnabled: getDefaultTakStreamingEnabled() }) ?? {};
  tak.uid = tak.uid || `asset-${asset.id}`;
  tak.cotType = tak.cotType || getDefaultTakTypeForForce(asset.force);
  tak.source = tak.source || "rf-sim-asset";
  tak.how = tak.how || "h-g-i-g-o";
  if (typeof tak.streamEnabled !== "boolean") {
    tak.streamEnabled = getDefaultTakStreamingEnabled();
  }
  asset.tak = tak;
  return tak;
}

function ensureTakMetadataForImportedItem(item) {
  const tak = normalizeTakMetadata(item?.tak, { defaultStreamEnabled: getDefaultTakStreamingEnabled() }) ?? {};
  tak.uid = tak.uid || `imported-${item.id}`;
  tak.cotType = tak.cotType || getDefaultTakCotTypeForImportedItem(item);
  tak.source = tak.source || "rf-sim-imported";
  tak.how = tak.how || "h-e";
  if (typeof tak.streamEnabled !== "boolean") {
    tak.streamEnabled = getDefaultTakStreamingEnabled();
  }
  item.tak = tak;
  return tak;
}

function setTakStreamingForContent(contentId, enabled, { publish = true } = {}) {
  if (!isTakStreamingSupportedContent(contentId)) {
    return false;
  }
  const target = getTakStreamTargetForContent(contentId);
  if (!target) {
    return false;
  }
  if (target.kind === "tactical") {
    target.item.streamToTak = enabled;
  } else if (target.kind === "asset") {
    ensureTakMetadataForAsset(target.item).streamEnabled = enabled;
  } else if (target.kind === "imported") {
    ensureTakMetadataForImportedItem(target.item).streamEnabled = enabled;
  }
  renderMapContents();
  saveMapState();
  if (enabled && publish) {
    void publishTakContentById(contentId);
  }
  return true;
}

function toggleTakStreamingForContent(contentId) {
  const nextEnabled = !isTakStreamingEnabledForContent(contentId);
  if (!setTakStreamingForContent(contentId, nextEnabled)) {
    return;
  }
  setStatus(`${getMapContentName(contentId) || "Item"} TAK streaming ${nextEnabled ? "enabled" : "disabled"}.`);
}

function getTakAnchorFromCoordinates(geometryType, coordinates) {
  if (geometryType === "Point" && Array.isArray(coordinates) && coordinates.length >= 2) {
    return [Number(coordinates[0]), Number(coordinates[1])];
  }
  if (!Array.isArray(coordinates) || !coordinates.length) {
    return [NaN, NaN];
  }
  const points = coordinates
    .map((entry) => [Number(entry?.[0]), Number(entry?.[1])])
    .filter(([lat, lon]) => Number.isFinite(lat) && Number.isFinite(lon));
  if (!points.length) {
    return [NaN, NaN];
  }
  const [latSum, lonSum] = points.reduce((acc, [lat, lon]) => [acc[0] + lat, acc[1] + lon], [0, 0]);
  return [latSum / points.length, lonSum / points.length];
}

function buildTakPointCotEvent({
  uid = "",
  cotType = "",
  how = "h-g-i-g-o",
  staleAt = "",
  lat,
  lon,
  detailNodes = "",
}) {
  if (!uid || !cotType || !Number.isFinite(Number(lat)) || !Number.isFinite(Number(lon))) {
    return "";
  }
  const now = new Date();
  const stale = staleAt ? new Date(staleAt) : new Date(now.getTime() + 300000);
  return `<event version="2.0" uid="${escapeHtml(uid)}" type="${escapeHtml(cotType)}" how="${escapeHtml(how)}" time="${now.toISOString()}" start="${now.toISOString()}" stale="${stale.toISOString()}"><point lat="${Number(lat).toFixed(6)}" lon="${Number(lon).toFixed(6)}" hae="0.0" ce="25.0" le="35.0"/><detail>${detailNodes}</detail></event>`;
}

function buildTakAssetCotEvent(asset) {
  const takObject = normalizeAssetToTakObject(asset);
  if (!takObject) {
    return "";
  }
  const tak = ensureTakMetadataForAsset(asset);
  const [lat, lon] = takObject.coordinates;
  return buildTakPointCotEvent({
    uid: takObject.uid,
    cotType: takObject.cotType,
    how: takObject.how,
    staleAt: tak.staleAt,
    lat,
    lon,
    detailNodes: buildTakSchemaDetailXml({
      contact: { callsign: takObject.callsign },
      track: { course: "0", speed: "0" },
      usericon: { iconsetpath: buildTakSchema2525UserIconPath(takObject.cotType) },
      remarks: { text: asset.notes || takObject.detail?.remarks || "RF SIM Asset" },
    }),
  });
}

function buildTakImportedCotEvent(item) {
  const takObject = normalizeImportedItemToTakObject(item);
  if (!takObject) {
    return "";
  }
  const tak = ensureTakMetadataForImportedItem(item);
  const [lat, lon] = getTakAnchorFromCoordinates(takObject.geometryType, takObject.coordinates);
  const coordinatePairs = takObject.geometryType === "Point"
    ? [[Number(takObject.coordinates[0]), Number(takObject.coordinates[1])]]
    : takObject.coordinates
      .map((entry) => [Number(entry?.[0]), Number(entry?.[1])])
      .filter(([entryLat, entryLon]) => Number.isFinite(entryLat) && Number.isFinite(entryLon));
  const extraNodes = coordinatePairs.length > 1
    ? coordinatePairs.map(([entryLat, entryLon]) => ({ point: `${entryLat.toFixed(6)},${entryLon.toFixed(6)}` }))
    : [];
  return buildTakPointCotEvent({
    uid: takObject.uid,
    cotType: takObject.cotType || getDefaultTakCotTypeForImportedItem(item),
    how: takObject.how,
    staleAt: tak.staleAt,
    lat,
    lon,
    detailNodes: buildTakSchemaDetailXml({
      contact: { callsign: takObject.callsign },
      remarks: { text: item.name || "RF SIM Drawing" },
      links: extraNodes,
    }),
  });
}

async function postTakCotEventXml(xml, { summary, sourceMode = "map-content", debugLabel, debugDetail } = {}) {
  if (!xml || !state.session.token || !state.session.activeProjectId || !isTakEnabledForProject(state.session.activeProjectId)) {
    return false;
  }
  const projectId = state.session.activeProjectId;
  if (debugLabel) {
    pushClientTakDebug("outbound", debugLabel, debugDetail || summary || "Publishing CoT", "info");
  }
  try {
    const result = await apiFetch(`/projects/${projectId}/tak-event`, {
      method: "POST",
      body: JSON.stringify({
        xml,
        summary,
        sourceMode,
      }),
    });
    if (state.session.activeProjectId !== projectId) {
      return false;
    }
    state.takRuntime.lastOutboundAt = result?.lastOutboundAt || nowIso();
    state.takRuntime.debugEvents = Array.isArray(result?.debugEvents) ? result.debugEvents : state.takRuntime.debugEvents;
    state.takRuntime.lastContactCount = Number(result?.contactCount ?? state.takRuntime.lastContactCount) || 0;
    if (debugLabel) {
      pushClientTakDebug("outbound", `${debugLabel} sent`, summary || "CoT published to TAK.", "info");
    }
    return true;
  } catch (error) {
    if (debugLabel) {
      pushClientTakDebug("outbound", `${debugLabel} failed`, error.message, "error");
    }
    return false;
  } finally {
    renderMapTakDebugPanel();
  }
}

async function publishTakContentById(contentId) {
  if (!isTakStreamingSupportedContent(contentId) || !isTakStreamingEnabledForContent(contentId)) {
    return false;
  }
  const target = getTakStreamTargetForContent(contentId);
  if (!target) {
    return false;
  }
  if (target.kind === "asset") {
    const xml = buildTakAssetCotEvent(target.item);
    return postTakCotEventXml(xml, {
      summary: `Asset CoT ${target.item.name || target.item.id}`,
      sourceMode: "asset",
      debugLabel: "Publishing asset CoT",
      debugDetail: `${target.item.name || target.item.id} â€¢ ${ensureTakMetadataForAsset(target.item).cotType}`,
    });
  }
  if (target.kind === "imported") {
    const xml = buildTakImportedCotEvent(target.item);
    return postTakCotEventXml(xml, {
      summary: `Map item CoT ${target.item.name || target.item.id}`,
      sourceMode: "drawn-item",
      debugLabel: "Publishing drawn-item CoT",
      debugDetail: `${target.item.name || target.item.id} â€¢ ${ensureTakMetadataForImportedItem(target.item).cotType}`,
    });
  }
  if (target.kind === "tactical") {
    return publishTakTacticalObject(target.item);
  }
  return false;
}

async function publishTakTacticalObject(object) {
  if (!state.session.token || !state.session.activeProjectId || !isTakEnabledForProject(state.session.activeProjectId)) {
    return;
  }
  const tactical = normalizeTacticalObject(object);
  if (tactical.readOnly || tactical.streamToTak === false || tactical.geometryType !== "Point" || !String(tactical.cotType || "").toLowerCase().startsWith("a-")) {
    return;
  }
  const xml = buildTakTacticalCotEvent(tactical);
  if (!xml) {
    return;
  }
  await postTakCotEventXml(xml, {
    summary: `Tactical CoT ${tactical.name || tactical.uid}`,
    sourceMode: "tactical",
    debugLabel: "Publishing tactical CoT",
    debugDetail: `${tactical.cotType} â€¢ ${tactical.name || tactical.uid}`,
  });
  return;
  const projectId = state.session.activeProjectId;
  const summary = `Tactical CoT ${tactical.name || tactical.uid}`;
  pushClientTakDebug("outbound", "Publishing tactical CoT", `${tactical.cotType} â€¢ ${tactical.name || tactical.uid}`, "info");
  try {
    const result = await apiFetch(`/projects/${projectId}/tak-event`, {
      method: "POST",
      body: JSON.stringify({
        xml,
        summary,
        sourceMode: "tactical",
      }),
    });
    if (state.session.activeProjectId !== projectId) {
      return;
    }
    state.takRuntime.lastOutboundAt = result?.lastOutboundAt || nowIso();
    state.takRuntime.debugEvents = Array.isArray(result?.debugEvents) ? result.debugEvents : state.takRuntime.debugEvents;
    state.takRuntime.lastContactCount = Number(result?.contactCount ?? state.takRuntime.lastContactCount) || 0;
    pushClientTakDebug("outbound", "Tactical CoT sent", `${tactical.name || tactical.uid} published to TAK.`, "info");
  } catch (error) {
    pushClientTakDebug("outbound", "Tactical CoT failed", error.message, "error");
  } finally {
    renderMapTakDebugPanel();
  }
}

function setTakDraft(profile) {
  state.takSettings.draft = sanitizeTakProfileSummary(profile);
}

function resetTakDraft() {
  state.takSettings.activeProfileId = "";
  setTakDraft(createEmptyTakProfileDraft());
  state.takSettings.statusMessage = "Save a TAK server profile to assign it to server-backed projects.";
}

function formatTakTimestamp(value) {
  if (!value) return "";
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return "";
  return parsed.toLocaleString();
}

function populateTakIdentityOptions() {
  if (dom.takIdentityTeamSelect && !dom.takIdentityTeamSelect.options.length) {
    dom.takIdentityTeamSelect.innerHTML = TAK_TEAM_OPTIONS
      .map((option) => `<option value="${escapeHtml(option.value)}">${escapeHtml(option.label)}</option>`)
      .join("");
  }
  if (dom.takIdentityDisplayTypeSelect && !dom.takIdentityDisplayTypeSelect.options.length) {
    dom.takIdentityDisplayTypeSelect.innerHTML = TAK_DISPLAY_TYPE_OPTIONS
      .map((option) => `<option value="${escapeHtml(option.value)}">${escapeHtml(option.label)}</option>`)
      .join("");
  }
  if (dom.takIdentityRoleSelect && !dom.takIdentityRoleSelect.options.length) {
    dom.takIdentityRoleSelect.innerHTML = TAK_ROLE_OPTIONS
      .map((option) => `<option value="${escapeHtml(option)}">${escapeHtml(option)}</option>`)
      .join("");
  }
}

function shouldShowTakIdentityButton() {
  return Boolean(state.session.token && state.session.activeProjectId && getTakProfileForProject(state.session.activeProjectId));
}

function syncTakIdentityUi() {
  populateTakIdentityOptions();
  const normalized = normalizeTakIdentity(state.takIdentity);
  state.takIdentity = normalized;
  if (dom.takIdentityBtn) {
    dom.takIdentityBtn.classList.toggle("hidden", !shouldShowTakIdentityButton());
  }
  if (dom.takIdentityBtnValue) {
    dom.takIdentityBtnValue.textContent = normalized.callsign;
  }
  if (dom.takIdentityCallsignInput) {
    dom.takIdentityCallsignInput.value = normalized.callsign;
  }
  if (dom.takIdentityTeamSelect) {
    dom.takIdentityTeamSelect.value = normalized.team;
  }
  if (dom.takIdentityDisplayTypeSelect) {
    dom.takIdentityDisplayTypeSelect.value = normalized.displayType;
  }
  if (dom.takIdentityRoleSelect) {
    dom.takIdentityRoleSelect.value = normalized.role;
  }
}

function openTakIdentityModal() {
  if (!dom.takIdentityModal) {
    return;
  }
  syncTakIdentityUi();
  dom.takIdentityModal.classList.remove("hidden");
  updateModalBodyState();
  dom.takIdentityCallsignInput?.focus();
  dom.takIdentityCallsignInput?.select();
}

function closeTakIdentityModal() {
  dom.takIdentityModal?.classList.add("hidden");
  updateModalBodyState();
}

function saveTakIdentityModal() {
  state.takIdentity = normalizeTakIdentity({
    callsign: dom.takIdentityCallsignInput?.value,
    team: dom.takIdentityTeamSelect?.value,
    displayType: dom.takIdentityDisplayTypeSelect?.value,
    role: dom.takIdentityRoleSelect?.value,
  });
  persistTakIdentitySettings();
  syncTakIdentityUi();
  pushClientTakDebug(
    "status",
    "TAK identity updated",
    `${state.takIdentity.callsign} â€¢ ${state.takIdentity.team} â€¢ ${getTakDisplayTypeMeta().label} â€¢ ${state.takIdentity.role}`,
    "info"
  );
  closeTakIdentityModal();
}

function getDefaultPlanSpawnPosition() {
  const canvas = document.getElementById("toCanvas");
  if (!canvas) {
    return { x: 240, y: 160 };
  }
  return {
    x: Math.max(80, (canvas.clientWidth / 2) - (_toState.panX / Math.max(_toState.zoom, 0.01))),
    y: Math.max(80, (canvas.clientHeight / 2) - (_toState.panY / Math.max(_toState.zoom, 0.01))),
  };
}

function buildPlanUnitContentId(unitId) {
  return `plan-unit:${unitId}`;
}

function getPlanUnitById(unitId) {
  return _toState.units.find((unit) => Number(unit.id) === Number(unitId)) ?? null;
}

function getPlanUnitLinkedEmitters(unitId) {
  return (state.assets || [])
    .filter((asset) => Number(asset?.toUnitId) === Number(unitId))
    .sort((a, b) => {
      const nameA = String(a?.emitterLabel || a?.name || "");
      const nameB = String(b?.emitterLabel || b?.name || "");
      return nameA.localeCompare(nameB) || (Number(a?.frequencyMHz) || 0) - (Number(b?.frequencyMHz) || 0);
    });
}

function getAvailableEmittersForPlanUnitLinking() {
  return (state.assets || [])
    .filter((asset) => !Number.isFinite(Number(asset?.toUnitId)))
    .sort((a, b) => {
      const nameA = String(a?.emitterLabel || a?.name || "");
      const nameB = String(b?.emitterLabel || b?.name || "");
      return nameA.localeCompare(nameB) || (Number(a?.frequencyMHz) || 0) - (Number(b?.frequencyMHz) || 0);
    });
}

function formatPlanUnitEmitterMeta(asset) {
  const waveform = asset?.waveform || asset?.ext?.waveform || "";
  const freq = Number.isFinite(Number(asset?.frequencyMHz)) ? `${Number(asset.frequencyMHz).toFixed(3)} MHz` : "No frequency";
  const power = Number.isFinite(Number(asset?.powerW)) ? `${Number(asset.powerW)} W` : "";
  const profile = asset?.profileName || asset?.profileId || "";
  return [waveform, freq, power, profile].filter(Boolean).join(" | ");
}

function hideToEmitterLinkedContextMenu() {
  dom.toEmitterLinkedContextMenu?.classList.add("hidden");
  dom.toEmitterLinkedList?.querySelectorAll(".is-context-target").forEach((entry) => entry.classList.remove("is-context-target"));
  _toEmitterManagerState.contextAssetId = "";
}

function closeToEmitterManagerModal() {
  _toEmitterManagerState.unitId = null;
  _toEmitterManagerState.chooserOpen = false;
  _toEmitterManagerState.contextAssetId = "";
  hideToEmitterLinkedContextMenu();
  if (dom.toEmitterManagerValidation) {
    dom.toEmitterManagerValidation.textContent = "";
  }
  dom.toEmitterManagerModal?.classList.add("hidden");
  updateModalBodyState();
}

function renderToEmitterManagerModal() {
  const unit = getPlanUnitById(_toEmitterManagerState.unitId);
  if (!unit) {
    closeToEmitterManagerModal();
    return;
  }
  const linkedEmitters = getPlanUnitLinkedEmitters(unit.id);
  const availableEmitters = getAvailableEmittersForPlanUnitLinking();
  if (dom.toEmitterManagerTitle) {
    dom.toEmitterManagerTitle.textContent = `Link / Unlink Emitters`;
  }
  if (dom.toEmitterManagerSubtitle) {
    dom.toEmitterManagerSubtitle.textContent = `${unit.label || unit.designator || `Unit ${unit.id}`} | ${linkedEmitters.length} linked emitter${linkedEmitters.length === 1 ? "" : "s"}`;
  }
  if (dom.toEmitterLinkedCount) {
    dom.toEmitterLinkedCount.textContent = String(linkedEmitters.length);
  }
  if (dom.toEmitterAvailableCount) {
    dom.toEmitterAvailableCount.textContent = String(availableEmitters.length);
  }
  if (dom.toEmitterManagerGrid) {
    dom.toEmitterManagerGrid.classList.toggle("is-chooser-open", _toEmitterManagerState.chooserOpen);
  }
  dom.toEmitterAvailablePanel?.classList.toggle("hidden", !_toEmitterManagerState.chooserOpen);
  dom.toEmitterChooserBackBtn?.classList.toggle("hidden", !_toEmitterManagerState.chooserOpen);
  if (dom.toEmitterLinkExistingBtn) {
    dom.toEmitterLinkExistingBtn.disabled = !availableEmitters.length;
  }
  if (dom.toEmitterLinkedList) {
    dom.toEmitterLinkedList.innerHTML = linkedEmitters.map((asset) => `
      <div class="to-emitter-manager-item" data-asset-id="${escapeHtml(asset.id)}" tabindex="0">
        <div class="to-emitter-manager-item-main">
          <div class="to-emitter-manager-item-name">${escapeHtml(asset.emitterLabel || asset.name || "Emitter")}</div>
          <div class="to-emitter-manager-item-meta">${escapeHtml(formatPlanUnitEmitterMeta(asset))}</div>
        </div>
        <div class="to-emitter-manager-item-action">
          <button class="ghost-button small" type="button" data-to-emitter-action="focus-asset" data-asset-id="${escapeHtml(asset.id)}">Focus</button>
        </div>
      </div>
    `).join("");
  }
  dom.toEmitterLinkedEmpty?.classList.toggle("hidden", linkedEmitters.length > 0);
  if (dom.toEmitterAvailableList) {
    dom.toEmitterAvailableList.innerHTML = availableEmitters.map((asset) => `
      <div class="to-emitter-manager-item" data-asset-id="${escapeHtml(asset.id)}">
        <div class="to-emitter-manager-item-main">
          <div class="to-emitter-manager-item-name">${escapeHtml(asset.emitterLabel || asset.name || "Emitter")}</div>
          <div class="to-emitter-manager-item-meta">${escapeHtml(formatPlanUnitEmitterMeta(asset))}</div>
        </div>
        <div class="to-emitter-manager-item-action">
          <button class="primary-button small" type="button" data-to-emitter-action="link-asset" data-asset-id="${escapeHtml(asset.id)}">Link</button>
        </div>
      </div>
    `).join("");
  }
  dom.toEmitterAvailableEmpty?.classList.toggle("hidden", availableEmitters.length > 0);
  hideToEmitterLinkedContextMenu();
}

function openToEmitterManagerModal(unitId = _toState.selectedUnit) {
  const unit = getPlanUnitById(unitId);
  if (!unit) {
    setStatus("Select a T/O unit first.", true);
    return;
  }
  _toEmitterManagerState.unitId = Number(unit.id);
  _toEmitterManagerState.chooserOpen = false;
  renderToEmitterManagerModal();
  dom.toEmitterManagerModal?.classList.remove("hidden");
  updateModalBodyState();
}

function linkEmitterAssetToPlanUnit(assetId, unitId = _toEmitterManagerState.unitId) {
  const unit = getPlanUnitById(unitId);
  const asset = (state.assets || []).find((entry) => entry.id === assetId) || null;
  if (!unit || !asset) {
    return false;
  }
  asset.toUnitId = Number(unit.id);
  if (_currentEmitterEditId === asset.id) {
    updateEmitterToLinkBadge(unit);
  }
  renderAssets();
  refreshLinkedViews();
  saveMapState();
  setStatus(`Linked ${asset.emitterLabel || asset.name || "Emitter"} to ${unit.label || unit.designator || `Unit ${unit.id}`}.`);
  return true;
}

function findPlanUnitByReference(reference) {
  const normalized = String(reference ?? "").trim();
  if (!normalized) {
    return null;
  }
  const idMatch = normalized.startsWith("plan-unit:")
    ? Number(normalized.slice("plan-unit:".length))
    : Number(normalized);
  if (Number.isFinite(idMatch)) {
    const byId = getPlanUnitById(idMatch);
    if (byId) {
      return byId;
    }
  }
  const lowered = normalized.toLowerCase();
  const direct = _toState.units.find((unit) =>
    String(unit.label || "").trim().toLowerCase() === lowered
    || String(unit.designator || "").trim().toLowerCase() === lowered,
  );
  if (direct) {
    return direct;
  }
  return _toState.units.find((unit) => {
    const haystack = [
      unit.label,
      unit.designator,
      buildDefaultToUnitLabel(unit.size, unit.type),
    ]
      .filter(Boolean)
      .join(" ")
      .toLowerCase();
    return haystack.includes(lowered);
  }) ?? null;
}

function getPlanUnitParentLink(unitId) {
  return _toState.links.find((link) => Number(link.childId) === Number(unitId)) ?? null;
}

function getPlanUnitChildLinks(unitId) {
  return _toState.links.filter((link) => Number(link.parentId) === Number(unitId));
}

function serializePlanUnitForAi(unit) {
  const normalized = normalizePlanUnit(unit);
  const linkedTactical = getTacticalObjectByPlanUnitId(normalized.id);
  const linkedAssets = state.assets
    .filter((asset) => Number(asset.toUnitId) === Number(normalized.id))
    .map((asset) => ({
      id: asset.id,
      contentId: `asset:${asset.id}`,
      name: asset.name,
      force: asset.force,
      emitterType: asset.type,
      frequencyMHz: roundAiNumber(asset.frequencyMHz, 3),
      lat: roundAiNumber(asset.lat),
      lon: roundAiNumber(asset.lon),
    }));
  const domain = normalizeTacticalDomain(linkedTactical?.domain || resolveMilstdDomain(normalized));
  const affiliation = normalizeTacticalAffiliation(linkedTactical?.affiliation || normalized.affiliation);
  const cotType = linkedTactical?.cotType || normalized.cotType || buildCatalogCotType(normalized.catalogId || normalized.type, affiliation) || buildDefaultCotTypeForTacticalObject("unit", affiliation, domain);
  const parentLink = getPlanUnitParentLink(normalized.id);
  const children = getPlanUnitChildLinks(normalized.id)
    .map((link) => getPlanUnitById(link.childId))
    .filter(Boolean);
  return {
    contentId: buildPlanUnitContentId(normalized.id),
    kind: "plan-unit",
    id: normalized.id,
    name: normalized.label || normalized.designator || buildDefaultToUnitLabel(normalized.size, normalized.type),
    label: normalized.label,
    designator: normalized.designator,
    affiliation,
    type: normalized.type,
    catalogId: normalized.catalogId || normalized.type,
    size: normalized.size,
    domain,
    objectClass: "unit",
    cotType,
    sidc: linkedTactical?.sidc || "",
    takSchema: {
      objectClass: "unit",
      domain,
      affiliation,
      unitType: normalized.type,
      size: normalized.size,
      cotType,
      sidc: linkedTactical?.sidc || "",
    },
    hierarchy: {
      parentId: parentLink?.parentId ?? null,
      parentName: parentLink ? (getPlanUnitById(parentLink.parentId)?.label || getPlanUnitById(parentLink.parentId)?.designator || null) : null,
      childIds: children.map((child) => child.id),
      childNames: children.map((child) => child.label || child.designator || `Unit ${child.id}`),
    },
    linkedAssets,
    linkedTactical: linkedTactical ? {
      id: linkedTactical.id,
      contentId: buildTacticalContentId(linkedTactical.id),
      name: linkedTactical.name,
      coordinates: Array.isArray(linkedTactical.coordinates) && linkedTactical.coordinates.length >= 2
        ? {
            lat: roundAiNumber(linkedTactical.coordinates[0]),
            lon: roundAiNumber(linkedTactical.coordinates[1]),
          }
        : null,
    } : null,
  };
}

function getTacticalObjectByPlanUnitId(unitId) {
  return state.tacticalObjects.find((entry) => Number(entry.linkedPlanUnitId) === Number(unitId)) ?? null;
}

function buildPlanUnitPlacementTemplate(unit) {
  const normalized = normalizePlanUnit(unit);
  return {
    id: generateId(),
    objectClass: "unit",
    geometryType: "Point",
    planUnitId: normalized.id,
    catalogId: normalized.catalogId || normalized.type,
    unitType: normalized.type,
    domain: getDoctrinalCatalogEntryById(normalized.catalogId || normalized.type)?.domain || resolveMilstdDomain(normalized),
    affiliation: normalized.affiliation,
    cotType: normalized.cotType || buildCatalogCotType(normalized.catalogId || normalized.type, normalized.affiliation),
    sidc: String(normalized.sidc || normalized.detail?.milsymId || "").trim(),
    symbolUniqueId: normalizeMilstdUniqueId(normalized.catalogId || normalized.type || normalized.detail?.milsymUniqueId || ""),
    detail: normalized.detail && typeof normalized.detail === "object" ? { ...normalized.detail } : {},
    size: normalized.size,
    name: normalized.label,
    designator: normalized.designator,
  };
}

function beginPlanUnitMapPlacement(unitId) {
  const unit = getPlanUnitById(unitId);
  if (!unit) {
    setStatus("Select a T/O unit first.", true);
    return false;
  }
  const linked = getTacticalObjectByPlanUnitId(unit.id);
  if (state.ui?.currentView !== "map") {
    switchView("map");
  }
  if (linked?.geometryType === "Point") {
    startTacticalRelocation(linked.id);
    return true;
  }
  beginTacticalPlacement(buildPlanUnitPlacementTemplate(unit));
  return true;
}

function ensureLinkedPlanUnitForTacticalObject(object) {
  if (!isUnitTacticalObject(object)) {
    return null;
  }
  const existing = getLinkedPlanUnitForTacticalObject(object);
  if (existing) {
    existing.label = object.name || existing.label;
    existing.designator = object.designator || existing.designator;
    existing.affiliation = normalizeTacticalAffiliation(object.affiliation);
    existing.type = normalizeToUnitType(object.catalogId || object.unitType);
    existing.catalogId = existing.type;
    existing.cotType = object.cotType || buildCatalogCotType(existing.catalogId, existing.affiliation);
    existing.sidc = String(object.sidc || object.detail?.milsymId || existing.sidc || "").trim();
    existing.detail = object.detail && typeof object.detail === "object" ? { ...object.detail } : (existing.detail || {});
    existing.size = object.size || existing.size;
    return existing;
  }
  const spawn = getDefaultPlanSpawnPosition();
  const unit = addToUnit({
    label: object.name,
    designator: object.designator,
    affiliation: normalizeTacticalAffiliation(object.affiliation),
    type: normalizeToUnitType(object.catalogId || object.unitType),
    catalogId: normalizeToUnitType(object.catalogId || object.unitType),
    cotType: object.cotType,
    sidc: String(object.sidc || object.detail?.milsymId || "").trim(),
    detail: object.detail && typeof object.detail === "object" ? { ...object.detail } : {},
    size: object.size || "battalion",
    x: spawn.x,
    y: spawn.y,
  });
  object.linkedPlanUnitId = unit.id;
  return unit;
}

function syncTacticalObjectFromPlanUnit(unitId) {
  const object = getTacticalObjectByPlanUnitId(unitId);
  const unit = _toState.units.find((entry) => entry.id === Number(unitId));
  if (!object || !unit) {
    return;
  }
  const normalizedUnit = normalizePlanUnit(unit);
  object.name = unit.label || object.name;
  object.designator = unit.designator || object.designator;
  object.affiliation = normalizeTacticalAffiliation(normalizedUnit.affiliation);
  object.unitType = normalizeToUnitType(normalizedUnit.catalogId || normalizedUnit.type);
  object.catalogId = object.unitType;
  object.size = normalizedUnit.size || object.size;
  object.domain = normalizeTacticalDomain(resolveMilstdDomain(normalizedUnit));
  object.cotType = normalizedUnit.cotType || buildCatalogCotType(object.catalogId, object.affiliation) || buildDefaultCotTypeForTacticalObject(object.objectClass, object.affiliation, object.domain);
  object.symbolUniqueId = normalizeMilstdUniqueId(normalizedUnit.catalogId || normalizedUnit.type || normalizedUnit.detail?.milsymUniqueId || "");
  object.detail = buildMilstdDetail(normalizedUnit.detail, getMilstdSymbolCatalogEntry(object.symbolUniqueId || object.catalogId || object.sidc || ""), object.affiliation, object.size);
  object.sidc = String(normalizedUnit.sidc || object.detail?.milsymId || object.sidc || "").trim();
  object.lastModified = nowIso();
  renderTacticalObjectLayer(object);
  renderMapContents();
  syncCesiumEntities();
}

function syncAllTacticalObjectsFromPlan() {
  state.tacticalObjects = state.tacticalObjects.filter((object) => {
    if (!Number.isFinite(Number(object.linkedPlanUnitId))) {
      return true;
    }
    const unit = _toState.units.find((entry) => entry.id === Number(object.linkedPlanUnitId));
    if (!unit) {
      removeTacticalObjectLayer(object.id);
      state.mapContentAssignments.delete(buildTacticalContentId(object.id));
      state.mapContentOrder = state.mapContentOrder.filter((entryId) => entryId !== buildTacticalContentId(object.id));
      state.hiddenLabelContentIds.delete(buildTacticalContentId(object.id));
      return false;
    }
    return true;
  });
  state.tacticalObjects
    .filter((object) => Number.isFinite(Number(object.linkedPlanUnitId)))
    .forEach((object) => syncTacticalObjectFromPlanUnit(object.linkedPlanUnitId));
}

function updateLinkedAssetsForTacticalUnit(object, linkedAssetIds = []) {
  const nextIds = new Set((linkedAssetIds || []).map(String));
  if (!Number.isFinite(Number(object?.linkedPlanUnitId))) {
    return;
  }
  state.assets.forEach((asset) => {
    if (nextIds.has(String(asset.id))) {
      asset.toUnitId = Number(object.linkedPlanUnitId);
    } else if (Number(asset.toUnitId) === Number(object.linkedPlanUnitId)) {
      asset.toUnitId = null;
    }
  });
  object.linkedAssetIds = [...nextIds];
  renderAssets();
}

function deleteTacticalObject(objectId, { silent = false } = {}) {
  const object = getTacticalObjectById(objectId);
  if (!object) return;
  if (Number.isFinite(Number(object.linkedPlanUnitId))) {
    const linkedAssets = state.assets.filter((asset) => Number(asset.toUnitId) === Number(object.linkedPlanUnitId));
    if (linkedAssets.length) {
      const confirmed = confirm(`Remove ${object.name} and clear ${linkedAssets.length} linked RF emitter${linkedAssets.length === 1 ? "" : "s"} from this unit?`);
      if (!confirmed) {
        return;
      }
      linkedAssets.forEach((asset) => { asset.toUnitId = null; });
      renderAssets();
    }
    _toState.links = _toState.links.filter((link) => link.parentId !== Number(object.linkedPlanUnitId) && link.childId !== Number(object.linkedPlanUnitId));
    _toState.units = _toState.units.filter((unit) => unit.id !== Number(object.linkedPlanUnitId));
    clearToSelection();
    renderToView();
  }
  removeTacticalObjectLayer(object.id);
  state.tacticalObjects = state.tacticalObjects.filter((entry) => entry.id !== object.id);
  const contentId = buildTacticalContentId(object.id);
  state.mapContentAssignments.delete(contentId);
  state.mapContentOrder = state.mapContentOrder.filter((entryId) => entryId !== contentId);
  state.hiddenContentIds.delete(contentId);
  state.hiddenLabelContentIds.delete(contentId);
  renderMapContents();
  syncCesiumEntities();
  saveMapState();
  if (!silent) {
    setStatus(`Removed ${object.name}.`);
  }
}

// Working list of linked asset IDs while the tactical editor is open
let _tacticalEditorLinkedAssetIds = [];

function renderTacticalEditorAssetLinks() {
  if (!dom.tacticalEditorAssetLinks) return;
  const ids = _tacticalEditorLinkedAssetIds;
  if (!ids.length) {
    dom.tacticalEditorAssetLinks.innerHTML = '<div class="tactical-asset-link-empty">No RF emitters linked.</div>';
    return;
  }
  const countHeader = `<div class="tactical-asset-link-count">${ids.length} emitter${ids.length === 1 ? "" : "s"} linked</div>`;
  const rows = ids.map((id) => {
    const asset = state.assets.find((a) => String(a.id) === String(id));
    const label = asset
      ? escapeHtml(asset.name || asset.emitterLabel || asset.unit || asset.id)
      : `<em>Unknown (${escapeHtml(String(id))})</em>`;
    const sub = asset ? escapeHtml(asset.type || "RF Emitter") : "";
    return `<div class="tactical-asset-link-row" data-asset-id="${escapeHtml(String(id))}">
      <span class="tactical-asset-link-name">${label}${sub ? ` <span class="fine-print">(${sub})</span>` : ""}</span>
      <button type="button" class="ghost-button small tactical-asset-unlink-btn" data-asset-id="${escapeHtml(String(id))}" aria-label="Unlink">&#10005;</button>
    </div>`;
  }).join("");
  dom.tacticalEditorAssetLinks.innerHTML = countHeader + rows;
  dom.tacticalEditorAssetLinks.querySelectorAll(".tactical-asset-unlink-btn").forEach((btn) => {
    btn.addEventListener("click", () => {
      const rmId = btn.dataset.assetId;
      _tacticalEditorLinkedAssetIds = _tacticalEditorLinkedAssetIds.filter((i) => String(i) !== String(rmId));
      renderTacticalEditorAssetLinks();
    });
  });
}

function getSelectedTacticalEditorAssetIds() {
  return [..._tacticalEditorLinkedAssetIds].map(String);
}

function syncDoctrinalUnitSelectionFields({ preserveCustomCot = false } = {}) {
  const objectClass = dom.tacticalEditorObjectClass?.value || "unit";
  if (objectClass !== "unit") {
    if (dom.tacticalEditorDomain) dom.tacticalEditorDomain.disabled = false;
    if (dom.tacticalEditorCotType) dom.tacticalEditorCotType.readOnly = false;
    return;
  }
  const affiliation = normalizeTacticalAffiliation(dom.tacticalEditorAffiliation?.value || "friendly");
  const catalogId = normalizeToUnitType(dom.tacticalEditorUnitType?.value || DEFAULT_MILSTD_UNIT_ID);
  const entry = getDoctrinalCatalogEntryById(catalogId);
  const usesEchelon = catalogAllowsEchelon(catalogId);
  if (dom.tacticalEditorDomain) {
    dom.tacticalEditorDomain.value = normalizeTacticalDomain(entry?.domain || deriveTacticalDomainFromCotType(dom.tacticalEditorCotType?.value || ""));
    dom.tacticalEditorDomain.disabled = true;
  }
  if (dom.tacticalEditorCotType) {
    if (!preserveCustomCot || !dom.tacticalEditorCotType.value.trim() || state.tacticalEditor.mode === "create") {
      dom.tacticalEditorCotType.value = buildCatalogCotType(catalogId, affiliation);
    }
    dom.tacticalEditorCotType.readOnly = true;
  }
  if (dom.tacticalEditorUnitSize) {
    if (!usesEchelon) {
      dom.tacticalEditorUnitSize.value = "";
    } else if (!dom.tacticalEditorUnitSize.value) {
      dom.tacticalEditorUnitSize.value = "battalion";
    }
  }
}

function updateTacticalEditorPreview() {
  const workingDetail = state.tacticalEditor.workingCopy?.detail && typeof state.tacticalEditor.workingCopy.detail === "object"
    ? { ...state.tacticalEditor.workingCopy.detail }
    : {};
  const previewAffiliation = normalizeTacticalAffiliation(dom.tacticalEditorAffiliation?.value || "friendly");
  const cotType = (dom.tacticalEditorCotType?.value || "").trim();
  const previewType = normalizeToUnitType(
    dom.tacticalEditorUnitType?.value
    || deriveTacticalUnitTypeFromCotType(cotType, dom.tacticalEditorDomain?.value || "ground")
    || DEFAULT_MILSTD_UNIT_ID
  );
  const previewSize = dom.tacticalEditorUnitSize?.value ?? "";
  const previewUnit = normalizeToUnit({
    id: 0,
    label: dom.tacticalEditorName?.value?.trim() || buildDefaultToUnitLabel(previewSize, previewType),
    designator: dom.tacticalEditorDesignator?.value?.trim() || "",
    affiliation: previewAffiliation,
    type: previewType,
    size: previewSize,
    sidc: buildMilstdSidc(workingDetail.milsymUniqueId || "", previewAffiliation, previewSize) || state.tacticalEditor.workingCopy?.sidc || "",
    detail: buildMilstdDetail(workingDetail, getMilstdSymbolCatalogEntry({ detail: workingDetail }), previewAffiliation, previewSize),
    frameOnly: isGenericCotTrackType(cotType),
  });
  if (dom.tacticalEditorPreview) {
    dom.tacticalEditorPreview.innerHTML = `<div class="tactical-map-icon">${renderToUnitIcon(previewUnit)}</div>`;
  }
  if (dom.tacticalEditorPreviewLabel) {
    const objectClass = dom.tacticalEditorObjectClass?.value || "unit";
    dom.tacticalEditorPreviewLabel.textContent = `${previewUnit.label || "Tactical Item"} â€¢ ${objectClass}${cotType ? ` â€¢ ${cotType}` : ""}`;
  }
}

function syncTacticalEditorUi() {
  const objectClass = dom.tacticalEditorObjectClass?.value || "unit";
  const isUnit = objectClass === "unit";
  const isPoint = state.tacticalEditor.workingCopy?.geometryType === "Point";
  const selectedCatalogId = normalizeToUnitType(dom.tacticalEditorUnitType?.value || DEFAULT_MILSTD_UNIT_ID);
  const usesEchelon = isUnit && catalogAllowsEchelon(selectedCatalogId);
  if (isUnit) syncDoctrinalUnitSelectionFields();
  else if (dom.tacticalEditorCotType && !dom.tacticalEditorCotType.value.trim()) {
    dom.tacticalEditorCotType.value = buildDefaultCotTypeForTacticalObject(
      objectClass,
      dom.tacticalEditorAffiliation?.value || "friendly",
      dom.tacticalEditorDomain?.value || "ground",
    );
  }
  const linkPanel = dom.tacticalEditorAssetLinks?.closest(".tactical-asset-link-panel");
  linkPanel?.classList.toggle("hidden", !isUnit);
  dom.tacticalEditorUnitType?.closest("label")?.classList.toggle("hidden", objectClass === "route" || objectClass === "geofence" || objectClass === "drawing" || objectClass === "shape");
  dom.tacticalEditorUnitSize?.closest("label")?.classList.toggle("hidden", !usesEchelon);
  dom.tacticalEditorLat?.closest("label")?.classList.toggle("hidden", !isPoint);
  dom.tacticalEditorLon?.closest("label")?.classList.toggle("hidden", !isPoint);
  dom.tacticalEditorLocationRow?.classList.toggle("hidden", !isPoint);
  const isEditMode = state.tacticalEditor.mode === "edit";
  dom.tacticalEditorRelocateBtn?.classList.toggle("hidden", !(isPoint && isEditMode));
  updateTacticalEditorPreview();
}

function closeTacticalEditorModal() {
  dom.tacticalEditorModal?.classList.add("hidden");
  updateModalBodyState();
  state.tacticalEditor.mode = null;
  state.tacticalEditor.targetId = null;
  state.tacticalEditor.workingCopy = null;
  _tacticalEditorLinkedAssetIds = [];
  _emitterLinkCallback = null;
}

function openTacticalEditorModal(object, { mode = "create", live = false } = {}) {
  const tactical = normalizeTacticalObject(object);
  state.tacticalEditor.mode = mode;
  state.tacticalEditor.targetId = tactical.id;
  state.tacticalEditor.workingCopy = tactical;
  if (dom.tacticalEditorSubtitle) {
    dom.tacticalEditorSubtitle.textContent = live
      ? "Reviewing a live TAK object. Runtime tracks are read-only."
      : mode === "edit"
        ? "Update the tactical item, shared unit metadata, and map symbology."
        : "Configure the symbology, identity, and map placement.";
  }
  dom.tacticalEditorName.value = tactical.name || "";
  dom.tacticalEditorDesignator.value = tactical.designator || "";
  dom.tacticalEditorObjectClass.value = tactical.objectClass || "unit";
  dom.tacticalEditorAffiliation.value = normalizeTacticalAffiliation(tactical.affiliation);
  dom.tacticalEditorDomain.value = normalizeTacticalDomain(tactical.domain);
  dom.tacticalEditorUnitType.value = normalizeToUnitType(tactical.catalogId || tactical.unitType);
  dom.tacticalEditorUnitSize.value = typeof tactical.size === "string"
    ? tactical.size
    : (catalogAllowsEchelon(dom.tacticalEditorUnitType.value) ? "battalion" : "");
  dom.tacticalEditorCotType.value = tactical.cotType || "";
  const isPoint = tactical.geometryType === "Point";
  const lat = isPoint ? Number(tactical.coordinates[0] ?? 0) : null;
  const lon = isPoint ? Number(tactical.coordinates[1] ?? 0) : null;
  dom.tacticalEditorLat.value = isPoint ? lat.toFixed(6) : "";
  dom.tacticalEditorLon.value = isPoint ? lon.toFixed(6) : "";
  if (dom.tacticalEditorLocationDisplay) {
    if (isPoint && Number.isFinite(lat) && Number.isFinite(lon)) {
      const coordSys = state.settings.coordinateSystem;
      dom.tacticalEditorLocationDisplay.value = formatCoordinate(lat, lon, coordSys);
      if (dom.tacticalEditorLocationLabel) {
        dom.tacticalEditorLocationLabel.textContent = coordinateSystemStatusLabel(coordSys);
      }
    } else {
      dom.tacticalEditorLocationDisplay.value = "";
    }
  }
  dom.tacticalEditorGeometrySummary.value = formatTacticalGeometrySummary(tactical);
  dom.tacticalEditorValidation.textContent = live ? "Live TAK items are rendered read-only. Use Promote later if you want persistence." : "";
  _tacticalEditorLinkedAssetIds = (tactical.linkedAssetIds || []).map(String);
  renderTacticalEditorAssetLinks();
  syncTacticalEditorUi();
  dom.tacticalEditorModal?.classList.remove("hidden");
  updateModalBodyState();
  dom.tacticalEditorName?.focus();
  dom.tacticalEditorName?.select();
}

function beginTacticalPlacement(template) {
  if (!template) return;
  state.pendingTacticalPlacement = template;
  closeTacticalPaletteModal();
  if (template.drawMode) {
    setAssetPlacementMode(false);
    setTacticalPlacementMode(false);
    startDrawing(template.drawMode);
    setStatus(`Draw the ${template.name.toLowerCase()} geometry on the map.`);
    return;
  }
  setAssetPlacementMode(false);
  setTacticalPlacementMode(true);
  setStatus(`Click ${state.view3dEnabled ? "the scene" : "the map"} to place ${template.name}.`);
}

function createTacticalDraftFromPlacement(template, geometryType, coordinates, extra = {}) {
  const objectClass = template.objectClass || "unit";
  const planUnit = Number.isFinite(Number(template.planUnitId)) ? getPlanUnitById(template.planUnitId) : null;
  const normalizedPlanUnit = planUnit ? normalizePlanUnit(planUnit) : null;
  const catalogEntry = getDoctrinalCatalogEntry(template);
  const domain = normalizeTacticalDomain(template.domain || normalizedPlanUnit?.catalogId && getDoctrinalCatalogEntryById(normalizedPlanUnit.catalogId)?.domain || catalogEntry?.domain || deriveTacticalDomainFromCotType(template.cotType));
  const unitType = normalizeToUnitType(template.catalogId || template.unitType || normalizedPlanUnit?.catalogId || deriveTacticalUnitTypeFromDomain(domain));
  const size = objectClass === "unit"
    ? (Object.prototype.hasOwnProperty.call(template, "size")
        ? template.size
        : (normalizedPlanUnit?.size ?? (catalogAllowsEchelon(unitType) ? "battalion" : "")))
    : "";
  const affiliation = template.affiliation || normalizedPlanUnit?.affiliation || "friendly";
  const name = template.name || normalizedPlanUnit?.label || buildDefaultToUnitLabel(size, unitType);
  return normalizeTacticalObject({
    source: "manual",
    objectClass,
    geometryType,
    shapeKind: extra.shapeKind || template.shapeKind || (geometryType === "LineString" ? "route" : geometryType === "Polygon" ? "polygon" : "point"),
    coordinates,
    cotType: template.cotType || normalizedPlanUnit?.cotType || buildCatalogCotType(unitType, affiliation) || buildDefaultCotTypeForTacticalObject(objectClass, affiliation, domain),
    sidc: template.sidc || "",
    catalogId: objectClass === "unit" ? unitType : "",
    domain,
    affiliation,
    unitType,
    size,
    name,
    designator: template.designator || normalizedPlanUnit?.designator || "",
    remarks: "",
    linkedPlanUnitId: normalizedPlanUnit?.id ?? null,
    detail: extra.isCircle
      ? {
          ...(template.detail || {}),
          ...(extra.detail || {}),
          radiusM: Number(extra.radiusM) || 0,
          center: extra.center ? { lat: Number(extra.center.lat), lng: Number(extra.center.lng) } : null,
        }
      : {
          ...(template.detail || {}),
          ...(extra.detail || {}),
        },
    linkedAssetIds: [],
    showLabel: true,
  });
}

function finalizePendingTacticalPlacement(geometryType, coordinates, extra = {}) {
  const template = state.pendingTacticalPlacement;
  state.pendingTacticalPlacement = null;
  setTacticalPlacementMode(false);
  if (!template) {
    return false;
  }
  const draft = createTacticalDraftFromPlacement(template, geometryType, coordinates, extra);
  openTacticalEditorModal(draft, { mode: "create" });
  return true;
}

function saveTacticalEditor() {
  if (!state.tacticalEditor.workingCopy) {
    closeTacticalEditorModal();
    return;
  }
  const original = state.tacticalEditor.workingCopy;
  const geometryType = original.geometryType;
  const coordinates = geometryType === "Point"
    ? [Number(dom.tacticalEditorLat.value), Number(dom.tacticalEditorLon.value)]
    : original.coordinates;
  if (geometryType === "Point" && (!Number.isFinite(coordinates[0]) || !Number.isFinite(coordinates[1]))) {
    dom.tacticalEditorValidation.textContent = "Latitude and longitude are required for point items.";
    return;
  }
  const rawUnitType = dom.tacticalEditorUnitType.value;
  const updated = normalizeTacticalObject({
    ...original,
    objectClass: dom.tacticalEditorObjectClass.value,
    name: dom.tacticalEditorName.value.trim() || original.name,
    designator: dom.tacticalEditorDesignator.value.trim(),
    affiliation: dom.tacticalEditorAffiliation.value,
    domain: dom.tacticalEditorDomain.value,
    unitType: rawUnitType,
    catalogId: rawUnitType,
    size: dom.tacticalEditorUnitSize.value,
    cotType: dom.tacticalEditorCotType.value.trim(),
    coordinates,
    linkedAssetIds: getSelectedTacticalEditorAssetIds(),
    lastModified: nowIso(),
  });
  if (!isUnitTacticalObject(updated) && Number.isFinite(Number(original.linkedPlanUnitId))) {
    state.assets.forEach((asset) => {
      if (Number(asset.toUnitId) === Number(original.linkedPlanUnitId)) {
        asset.toUnitId = null;
      }
    });
    _toState.links = _toState.links.filter((link) => link.parentId !== Number(original.linkedPlanUnitId) && link.childId !== Number(original.linkedPlanUnitId));
    _toState.units = _toState.units.filter((unit) => unit.id !== Number(original.linkedPlanUnitId));
    updated.linkedPlanUnitId = null;
    updated.linkedAssetIds = [];
    renderToView();
    renderAssets();
  }
  if (isUnitTacticalObject(updated)) {
    const planUnit = ensureLinkedPlanUnitForTacticalObject(updated);
    updated.linkedPlanUnitId = planUnit?.id ?? updated.linkedPlanUnitId;
    updateLinkedAssetsForTacticalUnit(updated, updated.linkedAssetIds);
  }

  const existingIndex = state.tacticalObjects.findIndex((entry) => entry.id === updated.id);
  if (existingIndex >= 0) {
    state.tacticalObjects.splice(existingIndex, 1, updated);
  } else {
    state.tacticalObjects.push(updated);
    const contentId = buildTacticalContentId(updated.id);
    if (!state.mapContentOrder.includes(contentId)) {
      state.mapContentOrder.push(contentId);
    }
  }
  renderTacticalObjectLayer(updated);
  renderMapContents();
  syncCesiumEntities();
  saveMapState();
  if (updated.streamToTak !== false) {
    void publishTakTacticalObject(updated);
  }
  closeTacticalEditorModal();
  setStatus(`${updated.name} saved as tactical content.`);
}

