function formatTacticalPickerLabel(value = "", options = {}) {
  const formatted = formatWintakHierarchySegment(value, options);
  return formatted
    .replace(/\bAnd\b/g, "and")
    .replace(/\bOf\b/g, "of")
    .trim();
}

function normalizeTacticalObjectRootLabel(entry, config, parts = []) {
  const symbolSet = String(entry?.symbolSetCode || "").padStart(2, "0");
  const selectionId = String(config?.selectionId || "").trim();
  if (selectionId === "ground_track") {
    if (symbolSet === "10") return "Unit";
    if (symbolSet === "15") return "Equipment";
    if (symbolSet === "20") return "Installation";
    if (symbolSet === "11") return "Civilian";
  }
  if (selectionId === "air_track" && symbolSet === "02") return "Weapon";
  if (selectionId === "space_track" && symbolSet === "06") return "Weapon";
  if (selectionId === "subsurface_track" && symbolSet === "36") return "Mine warfare";
  const first = formatTacticalPickerLabel(parts[0] || config?.label || config?.selectionLabel || "Track", {
    selectionId,
    depth: 0,
  })
    .replace(/\s*\((Air|Ground|Land|Sea Surface|Sea Subsurface|Subsurface|Space)\)\s*/gi, "")
    .trim();
  return first || config?.label || "Track";
}

function getLandUnitWintakGroup(parts = []) {
  const top = String(parts[0] || "").trim();
  return WINTAK_LAND_UNIT_TOP_GROUP[top] || "Combat support";
}

function mapLandUnitBranchPart(part = "", { top = "", index = 0 } = {}) {
  const raw = String(part || "").trim();
  const alias = WINTAK_LAND_UNIT_BRANCH_ALIASES[raw];
  if (alias) return alias;
  if (top === "Sustainment" && index === 0 && /supply|maintenance|transportation|medical|material|ordnance|quartermaster/i.test(raw)) {
    return formatTacticalPickerLabel(raw);
  }
  return formatTacticalPickerLabel(raw);
}

function getLandUnitWintakBranchParts(parts = []) {
  const top = String(parts[0] || "").trim();
  let tail = parts.slice(1).filter(Boolean);
  if (!tail.length) {
    tail = [top || "Unit"];
  }
  if (top === "Named Headquarters") {
    tail = ["Named headquarters", ...tail];
  } else if (top === "Command and Control") {
    tail = ["Command and control", ...tail];
  } else if (top === "Special Entity Subtypes") {
    tail = tail.length ? tail : ["Headquarters component"];
  }
  const mapped = tail.map((part, index) => mapLandUnitBranchPart(part, { top, index })).filter(Boolean);
  if (top === "Movement and Maneuver") {
    if (/^Army Aviation|^Aviation/i.test(tail[0] || "")) {
      const variant = /Rotary/i.test(tail[0] || "") ? "Rotary-wing"
        : /Fixed/i.test(tail[0] || "") ? "Fixed-wing"
          : /Composite/i.test(tail[0] || "") ? "Composite"
            : "";
      return ["Aviation", variant, ...mapped.slice(1)].filter(Boolean);
    }
  }
  return mapped;
}

function getTacticalPickerSortWeight(selectionId = "", pathLabels = [], label = "") {
  const normalizedLabel = String(label || "").trim();
  if (!pathLabels.length) {
    const order = WINTAK_ROOT_SORT[selectionId] || [];
    const index = order.indexOf(normalizedLabel);
    return index >= 0 ? index : 500;
  }
  if (selectionId === "ground_track" && pathLabels.length === 1 && pathLabels[0] === "Unit") {
    const index = WINTAK_LAND_UNIT_GROUP_ORDER.indexOf(normalizedLabel);
    return index >= 0 ? index : 500;
  }
  return 500;
}

function isSofMilstdEntry(entry = null) {
  const haystack = [
    entry?.label || "",
    entry?.cleanLabel || "",
    entry?.searchText || "",
    ...(Array.isArray(entry?.tags) ? entry.tags : []),
  ].join(" ").toLowerCase();
  return /\bsof\b/.test(haystack)
    || haystack.includes("special operations forces")
    || haystack.includes("special forces");
}

function getWintakHierarchyParts(entry, config) {
  const selectionId = String(config?.selectionId || "").trim() || "ground_track";
  const cleanLabel = String(entry?.cleanLabel || entry?.label || "").trim();
  const parts = cleanLabel.split(" : ").map((part) => part.trim()).filter(Boolean);
  const symbolSet = String(entry?.symbolSetCode || "").padStart(2, "0");
  if (selectionId === "ground_track") {
    const root = normalizeTacticalObjectRootLabel(entry, config, parts);
    if (symbolSet === "10") {
      return [
        root,
        getLandUnitWintakGroup(parts),
        ...getLandUnitWintakBranchParts(parts),
      ].filter(Boolean);
    }
    return [
      root,
      ...parts.map((part, index) => formatTacticalPickerLabel(part, { selectionId, depth: index })).filter(Boolean),
    ].filter((part, index, all) => index === 0 || part !== all[index - 1]);
  }
  if (selectionId === "sof_unit") {
    const sofIndex = parts.findIndex((part) => /\bSOF\b|Special Operations Forces|Special Forces/i.test(part));
    const tail = (sofIndex >= 0 ? parts.slice(sofIndex + 1) : parts)
      .map((part, index) => formatTacticalPickerLabel(part, { selectionId, depth: index + 1 }))
      .filter(Boolean);
    return ["Special operations forces (SOF)", ...tail];
  }
  let normalizedParts = parts
    .map((part, index) => formatTacticalPickerLabel(part, { selectionId, depth: index }))
    .filter(Boolean);
  if (normalizedParts.length) {
    const root = normalizeTacticalObjectRootLabel(entry, config, parts);
    if (root && normalizedParts[0] !== root) {
      normalizedParts = [root, ...normalizedParts];
    }
  }
  if (["air_missile", "space_missile", "mine_warfare"].includes(String(config?.id || ""))) {
    if (normalizedParts[0] === "Weapon") {
      return normalizedParts;
    }
    return ["Weapon", ...normalizedParts];
  }
  if (selectionId === "activities" || selectionId === "cyberspace") {
    return normalizedParts;
  }
  if (selectionId === "sigint") {
    return [config?.label || "SIGINT", ...normalizedParts];
  }
  if (String(selectionId).startsWith("metoc")) {
    return [config?.label || config?.selectionLabel || "METOC", ...normalizedParts];
  }
  return normalizedParts;
}

function makeTacticalNavNode({ id = "", label = "", preview = null, symbolSetCode = "", entry = null } = {}) {
  return {
    id,
    label,
    preview,
    symbolSetCode,
    entry,
    children: [],
    childMap: new Map(),
  };
}

function getTacticalNavChildren(node = null) {
  return Array.isArray(node?.children) ? node.children : [];
}

function getTacticalNavNodeAtPath(selectionId = "", path = []) {
  const roots = getTacticalNavRootsForSelection(selectionId);
  let children = roots;
  let current = null;
  for (const segment of path) {
    current = children.find((node) => node.id === segment) || null;
    if (!current) {
      return null;
    }
    children = getTacticalNavChildren(current);
  }
  return current;
}

function getTacticalNavRootsForSelection(selectionId = "") {
  const normalizedSelection = String(selectionId || "").trim() || "ground";
  if (!TACTICAL_NAV_ROOTS) {
    TACTICAL_NAV_ROOTS = buildTacticalNavRoots();
  }
  return TACTICAL_NAV_ROOTS.get(normalizedSelection) || [];
}

function getTacticalNavSiblings(selectionId = "", path = []) {
  if (!path.length) {
    return getTacticalNavRootsForSelection(selectionId);
  }
  const parent = getTacticalNavNodeAtPath(selectionId, path.slice(0, -1));
  return parent ? getTacticalNavChildren(parent) : getTacticalNavRootsForSelection(selectionId);
}

function buildTacticalNavRoots() {
  const byDomain = new Map();
  TACTICAL_PALETTE_SELECTION_ORDER.forEach((selectionId) => {
    byDomain.set(selectionId, []);
  });
  Object.values(MILSTD_SYMBOL_SET_NAV_CONFIG).forEach(({ selectionId }) => {
    const normalizedSelection = String(selectionId || "").trim() || "ground";
    if (!byDomain.has(normalizedSelection)) {
      byDomain.set(normalizedSelection, []);
    }
  });

  const rawEntries = MILSTD_SYMBOL_CATALOG
    .filter((entry) => hasRenderableMilstdAssetPath(entry))
    .filter((entry) => /:\s*Main Icon$/i.test(String(entry?.category || "").trim()))
    .filter((entry) => !/^Frame$/i.test(String(entry?.category || "").trim()))
    .filter((entry) => !/^Amplifier/i.test(String(entry?.category || "").trim()))
    .map((entry) => ({
      ...entry,
      cleanLabel: sanitizeTacticalHierarchyLabel(entry.label || ""),
    }))
    .filter((entry) => entry.cleanLabel);

  const deduped = new Map();
  rawEntries.forEach((entry) => {
    const key = `${entry.symbolSetCode || ""}|${entry.cleanLabel.toLowerCase()}`;
    if (!deduped.has(key)) {
      deduped.set(key, entry);
      return;
    }
    const existing = deduped.get(key);
    const existingScore = String(existing.defaultPath || "").includes("_1.svg") ? 1 : 0;
    const nextScore = String(entry.defaultPath || "").includes("_1.svg") ? 1 : 0;
    if (nextScore > existingScore) {
      deduped.set(key, entry);
    }
  });

  const insertEntry = (entry, config) => {
    const selectionKey = String(config.selectionId || "").trim() || "ground";
    const roots = byDomain.get(selectionKey) || [];
    if (!byDomain.has(selectionKey)) {
      byDomain.set(selectionKey, roots);
    }
    const parts = getWintakHierarchyParts(entry, config);
    if (!parts.length) {
      return;
    }
    let cursor = null;
    parts.forEach((part, index) => {
      const parentChildren = cursor ? cursor.children : roots;
      const parentChildMap = cursor ? cursor.childMap : null;
      const nodeId = cursor
        ? `${cursor.id}/${slugifyTacticalNavSegment(part)}`
        : `${selectionKey}/${slugifyTacticalNavSegment(part)}`;
      let child = cursor
        ? parentChildMap.get(nodeId)
        : parentChildren.find((node) => node.id === nodeId);
      if (!child) {
        child = makeTacticalNavNode({
          id: nodeId,
          label: part,
          preview: entry,
          symbolSetCode: entry.symbolSetCode || "",
        });
        if (cursor) {
          cursor.childMap.set(nodeId, child);
          cursor.children.push(child);
        } else {
          roots.push(child);
        }
      }
      if (!child.preview) {
        child.preview = entry;
      }
      if (index === parts.length - 1) {
        child.entry = entry;
        child.symbolSetCode = entry.symbolSetCode || child.symbolSetCode;
      }
      cursor = child;
    });
  };

  [...deduped.values()].forEach((entry) => {
    const config = MILSTD_SYMBOL_SET_NAV_CONFIG[String(entry.symbolSetCode || "").padStart(2, "0")];
    if (config) {
      insertEntry(entry, config);
    }
    if (isSofMilstdEntry(entry)) {
      insertEntry(entry, {
        selectionId: "sof_unit",
        selectionLabel: TACTICAL_PALETTE_SELECTION_LABELS.sof_unit,
        domain: entry.domain || "ground",
        id: "sof_unit",
        label: "Special operations forces (SOF)",
      });
    }
  });

  for (const [selectionId, roots] of byDomain.entries()) {
    const sortTree = (nodes, pathLabels = []) => {
      nodes.sort((left, right) => {
        const leftWeight = getTacticalPickerSortWeight(selectionId, pathLabels, left.label);
        const rightWeight = getTacticalPickerSortWeight(selectionId, pathLabels, right.label);
        return leftWeight - rightWeight || String(left.label || "").localeCompare(String(right.label || ""));
      });
      nodes.forEach((node) => sortTree(node.children, [...pathLabels, node.label]));
    };
    sortTree(roots);
  }
  return byDomain;
}

function findTacticalNavPath(selectionId = "", matcher = () => false) {
  const visit = (nodes, trail = []) => {
    for (const node of nodes) {
      const nextTrail = [...trail, node.id];
      if (matcher(node)) {
        return nextTrail;
      }
      const nested = visit(getTacticalNavChildren(node), nextTrail);
      if (nested) {
        return nested;
      }
    }
    return null;
  };
  return visit(getTacticalNavRootsForSelection(selectionId), []);
}

function isPlanPickableMilstdEntry(entry = null) {
  const category = String(entry?.category || "").toLowerCase();
  const searchText = String(entry?.searchText || "").toLowerCase();
  return Boolean(entry)
    && String(entry.objectClass || "") === "unit"
    && hasRenderableMilstdAssetPath(entry, _tpalState.affiliation || "friendly")
    && !category.includes("equipment")
    && !category.includes("installation")
    && !searchText.includes("land equipment")
    && !searchText.includes("land installation")
    && !shouldRenderStandaloneMilstd(entry);
}

function isTpalEntryAllowed(entry = null) {
  if (!entry || !hasRenderableMilstdAssetPath(entry, _tpalState.affiliation || "friendly")) {
    return false;
  }
  if (_tpalState.mode === "plan-picker") {
    return isPlanPickableMilstdEntry(entry);
  }
  return true;
}

function getTpalNodeDisplayEntry(node = null) {
  if (!node) return null;
  if (isTpalEntryAllowed(node.entry)) return node.entry;
  if (isTpalEntryAllowed(node.preview)) return node.preview;
  for (const child of getTacticalNavChildren(node)) {
    const match = getTpalNodeDisplayEntry(child);
    if (match) return match;
  }
  return null;
}

function isTpalNodeVisible(node = null) {
  return Boolean(getTpalNodeDisplayEntry(node));
}

function getTpalFamilyChoices() {
  const grouped = MILSTD_SYMBOL_CATALOG.reduce((map, entry) => {
    const config = MILSTD_SYMBOL_SET_NAV_CONFIG[String(entry?.symbolSetCode || "").padStart(2, "0")];
    if (!config) return map;
    if (_tpalState.mode === "plan-picker" && !isPlanPickableMilstdEntry(entry)) {
      return map;
    }
    const selectionId = String(config.selectionId || "").trim() || "ground";
    if (!map.has(selectionId)) {
      map.set(selectionId, {
        id: selectionId,
        label: config.selectionLabel || TACTICAL_PALETTE_SELECTION_LABELS[selectionId] || formatToUnitLabelPart(selectionId),
        selectionId,
        count: 0,
        preview: entry,
      });
    }
    const bucket = map.get(selectionId);
    bucket.count += 1;
    if (!bucket.preview) bucket.preview = entry;
    return map;
  }, new Map());
  if (!grouped.has("sof_unit")) {
    const sofPreview = getMilstdSymbolCatalogEntry("10121700") || getMilstdSymbolCatalogEntry("10121100");
    if (sofPreview) {
      grouped.set("sof_unit", {
        id: "sof_unit",
        label: TACTICAL_PALETTE_SELECTION_LABELS.sof_unit,
        selectionId: "sof_unit",
        count: 1,
        preview: sofPreview,
      });
    }
  }

  let choices = [...grouped.values()];
  if (_tpalState.mode === "plan-picker") {
    choices = choices.filter((entry) => (
      TACTICAL_PALETTE_PRIMARY_SELECTIONS.has(entry.selectionId)
      && getTacticalNavRootsForSelection(entry.selectionId).some((node) => isTpalNodeVisible(node))
    ));
  }
  return choices.sort((a, b) => {
    const ai = TACTICAL_PALETTE_SELECTION_ORDER.indexOf(a.selectionId);
    const bi = TACTICAL_PALETTE_SELECTION_ORDER.indexOf(b.selectionId);
    return (ai >= 0 ? ai : 999) - (bi >= 0 ? bi : 999) || a.label.localeCompare(b.label);
  });
}

function ensureTpalSelectionPath() {
  if (!_tpalState.selection) {
    _tpalState.path = [];
    return;
  }
  const roots = getTacticalNavRootsForSelection(_tpalState.selection);
  if (!roots.length) {
    _tpalState.path = [];
    return;
  }
  if (!_tpalState.path.length) {
    return;
  }
  const active = getTacticalNavNodeAtPath(_tpalState.selection, _tpalState.path);
  if (!active) {
    _tpalState.path = [];
  }
}

function getTpalCurrentNode() {
  return getTacticalNavNodeAtPath(_tpalState.selection, _tpalState.path);
}

function getTpalCurrentRoots() {
  return getTacticalNavRootsForSelection(_tpalState.selection);
}

function buildTpalNodeSearchText(node = null, selectionLabel = "") {
  return [
    selectionLabel,
    node?.label || "",
    node?.entry?.cleanLabel || node?.preview?.cleanLabel || "",
    node?.entry?.label || node?.preview?.label || "",
    node?.entry?.category || node?.preview?.category || "",
    node?.entry?.searchText || node?.preview?.searchText || "",
  ].join(" ").toLowerCase();
}

function scoreTpalSearchResult(node = null, query = "", searchText = "") {
  const label = String(node?.label || "").toLowerCase();
  const cleanLabel = String(node?.entry?.cleanLabel || node?.preview?.cleanLabel || "").toLowerCase();
  if (label === query || cleanLabel === query) return 0;
  if (label.startsWith(query)) return 1;
  if (cleanLabel.startsWith(query)) return 2;
  if (label.includes(query)) return 3;
  if (cleanLabel.includes(query)) return 4;
  return searchText.includes(query) ? 8 : 20;
}

function getTpalSearchResults({ global = false, limit = 80 } = {}) {
  const query = String(_tpalState.search || "").trim().toLowerCase();
  if (!query) {
    return [];
  }
  const results = [];
  const familyChoices = getTpalFamilyChoices();
  const selections = global || !_tpalState.selection
    ? familyChoices.map((choice) => ({
        id: choice.selectionId || choice.id,
        label: choice.label,
      }))
    : [{
        id: _tpalState.selection,
        label: familyChoices.find((choice) => choice.id === _tpalState.selection || choice.selectionId === _tpalState.selection)?.label
          || TACTICAL_PALETTE_SELECTION_LABELS[_tpalState.selection]
          || "",
      }];
  const visit = (node, trail, selection) => {
    const nextTrail = [...trail, node.id];
    const haystack = buildTpalNodeSearchText(node, selection.label);
    if (node.entry && isTpalEntryAllowed(node.entry) && haystack.includes(query)) {
      results.push({
        node,
        path: nextTrail,
        exact: true,
        searchResult: true,
        selectionId: selection.id,
        selectionLabel: selection.label,
        score: scoreTpalSearchResult(node, query, haystack),
      });
    }
    getTacticalNavChildren(node).forEach((child) => visit(child, nextTrail, selection));
  };
  selections.forEach((selection) => {
    const currentNode = !global && selection.id === _tpalState.selection ? getTpalCurrentNode() : null;
    const bases = currentNode ? [currentNode] : getTacticalNavRootsForSelection(selection.id);
    const baseTrail = currentNode ? _tpalState.path.slice(0, -1) : [];
    bases.forEach((node) => visit(node, baseTrail, selection));
  });
  return results
    .sort((left, right) => left.score - right.score || String(left.node.label || "").localeCompare(String(right.node.label || "")))
    .slice(0, limit);
}

function getTpalVisibleItems() {
  const searchResults = getTpalSearchResults();
  if (searchResults.length) {
    return searchResults;
  }
  const currentNode = getTpalCurrentNode();
  if (!currentNode) {
    return getTpalCurrentRoots()
      .filter((node) => isTpalNodeVisible(node))
      .map((node) => ({ node, path: [node.id], exact: false, searchResult: false }));
  }
  const children = getTacticalNavChildren(currentNode).map((node) => ({
    node,
    path: [..._tpalState.path, node.id],
    exact: false,
    searchResult: false,
  })).filter((item) => isTpalNodeVisible(item.node));
  if (currentNode.entry && isTpalEntryAllowed(currentNode.entry)) {
    return [{
      node: currentNode,
      path: _tpalState.path.slice(),
      exact: true,
      searchResult: false,
    }, ...children];
  }
  return children;
}

function buildTpalPreviewUnit({ entry = null, affiliation = "friendly", size = "" } = {}) {
  const catalogId = normalizeToUnitType(
    entry?.id
    || entry?.catalogId
    || entry?.type
    || entry?.uniqueId
    || deriveTacticalUnitTypeFromDomain(entry?.domain || "ground"),
  );
  const previewSize = entry?.echelonAllowed === false ? "" : size;
  return normalizeToUnit({
    affiliation,
    type: catalogId,
    catalogId,
    size: previewSize,
    sidc: "",
    detail: {},
    frameOnly: false,
  });
}

function getTacticalPaletteCustomName(fallback = "") {
  const value = String(dom.tacticalPaletteName?.value || "").trim();
  return value || String(fallback || "").trim();
}

function renderTpalSymbol(entry, options = {}) {
  const displayEntry = getTpalNodeDisplayEntry(entry) || entry?.preview || entry;
  const previewUnit = buildTpalPreviewUnit({
    entry: displayEntry,
    affiliation: options.affiliation || "friendly",
    size: typeof entry?.size === "string"
      ? entry.size
      : (displayEntry?.domain === "ground" && displayEntry?.echelonAllowed !== false ? "team" : ""),
  });
  return renderToUnitIcon(previewUnit);
}

function renderTpalBreadcrumbs() {
  if (!dom.tpalHierarchyBreadcrumbs) {
    return;
  }
  if (!_tpalState.path.length) {
    dom.tpalHierarchyBreadcrumbs.innerHTML = "";
    return;
  }
  const segments = [];
  let runningPath = [];
  _tpalState.path.forEach((nodeId, index) => {
    const node = getTacticalNavNodeAtPath(_tpalState.selection, [...runningPath, nodeId]);
    if (!node) {
      return;
    }
    runningPath = [...runningPath, nodeId];
    if (index > 0) {
      segments.push('<span class="tpal-crumb-sep" aria-hidden="true">/</span>');
    }
    segments.push(`<button class="tpal-crumb" type="button" data-depth="${index + 1}">${escapeHtml(node.label)}</button>`);
  });
  dom.tpalHierarchyBreadcrumbs.innerHTML = segments.join("");
}

function renderTpalAffiliationChoices() {
  if (!dom.tpalStep1) {
    return;
  }
  const activeAffiliation = normalizeTacticalAffiliation(_tpalState.affiliation || "friendly");
  dom.tpalStep1.querySelectorAll(".tpal-affil-btn").forEach((button) => {
    const isActive = normalizeTacticalAffiliation(button.dataset.affiliation || "") === activeAffiliation;
    button.classList.toggle("active", isActive);
    button.setAttribute("aria-pressed", isActive ? "true" : "false");
  });
}

function _tpalSetStep(step) {
  _tpalState.step = step;
  const isPlanPicker = _tpalState.mode === "plan-picker";
  dom.tacticalPaletteModal?.classList.toggle("tactical-palette-modal--plan-picker", isPlanPicker);
  const titleEl = document.getElementById("tacticalPaletteTitle");
  if (titleEl) {
    titleEl.textContent = isPlanPicker ? "Choose Unit Symbology" : "Add Tactical Item";
  }
  [dom.tpalStep1, dom.tpalStep2, dom.tpalStep3].forEach((el, i) => {
    el?.classList.toggle("hidden", i + 1 !== step);
  });
  dom.tacticalPaletteName?.closest("label")?.classList.toggle("hidden", _tpalState.mode === "plan-picker");
  dom.tacticalPaletteSearch?.closest("label")?.classList.toggle("hidden", step === 1);
  // Update step indicators
  dom.tacticalPaletteModal?.querySelectorAll(".tpal-step").forEach((el) => {
    const s = Number(el.dataset.step);
    el.classList.toggle("active", s === step);
    el.classList.toggle("done", s < step);
  });
  dom.tpalBackBtn?.classList.toggle("hidden", step === 1 || (isPlanPicker && step === 2));
  const subtitles = isPlanPicker
    ? [
        "Select the unit affiliation.",
        "Choose the domain, then search or browse the available unit types.",
        "Navigate the hierarchy and select the exact symbol for this T/O unit.",
      ]
    : [
        "Select affiliation to begin.",
        "Choose the symbol family you want to browse.",
        "Navigate the hierarchy and select the exact symbol to place on the map.",
      ];
  if (dom.tacticalPaletteSubtitle) dom.tacticalPaletteSubtitle.textContent = subtitles[step - 1] || "";
  if (dom.tacticalPaletteStatus) dom.tacticalPaletteStatus.textContent = "";
  if (step === 1) {
    renderTpalAffiliationChoices();
  }
  if (step === 3) {
    requestAnimationFrame(() => (_tpalState.mode === "plan-picker" ? dom.tacticalPaletteSearch : dom.tacticalPaletteName)?.focus());
  }
}

function renderTpalSearchSuggestionRows(results = []) {
  const aff = _tpalState.affiliation || "friendly";
  return results.map((item) => {
    const node = item.node;
    const pathLabels = item.path
      .map((nodeId, index) => getTacticalNavNodeAtPath(item.selectionId, item.path.slice(0, index + 1))?.label || "")
      .filter(Boolean);
    const displayPath = [item.selectionLabel, ...pathLabels.slice(0, -1)].filter(Boolean).join(" / ");
    return `<button class="tpal-type-btn tpal-type-btn--suggestion" type="button"
      data-selection="${escapeHtml(item.selectionId || _tpalState.selection || "")}"
      data-node-id="${escapeHtml(node.id)}"
      data-path="${escapeHtml(item.path.join("|"))}"
      data-exact="1">
      <span class="tpal-type-symbol">${renderTpalSymbol(node, { affiliation: aff })}</span>
      <span class="tpal-type-title">${escapeHtml(node.label)}${displayPath ? `<small>${escapeHtml(displayPath)}</small>` : ""}</span>
      <span class="tpal-type-meta is-select">Select</span>
    </button>`;
  }).join("");
}

function _tpalRenderTrackChoices() {
  if (!dom.tpalStep2) return;
  const aff = _tpalState.affiliation || "friendly";
  const choices = getTpalFamilyChoices();
  const grid = dom.tpalStep2.querySelector(".tpal-domain-grid");
  if (grid) {
    const suggestions = getTpalSearchResults({ global: true, limit: 10 });
    const renderRows = (items) => items.map((entry) => `
      <button class="tpal-list-row tpal-list-row--family" type="button" data-selection="${entry.id}">
        <span class="tpal-list-row-symbol">${renderTpalSymbol(entry, { affiliation: aff })}</span>
        <span class="tpal-list-row-label">${escapeHtml(entry.label)}</span>
        <span class="tpal-list-row-action" aria-hidden="true">&#8594;</span>
      </button>
    `).join("");
    const primaryChoices = choices.filter((entry) => TACTICAL_PALETTE_PRIMARY_SELECTIONS.has(entry.selectionId));
    const specializedChoices = choices.filter((entry) => TACTICAL_PALETTE_SPECIALIZED_SELECTIONS.has(entry.selectionId));
    grid.innerHTML = choices.length
      ? `${suggestions.length ? `<div class="tpal-section-title">Suggestions</div>${renderTpalSearchSuggestionRows(suggestions)}` : ""}${primaryChoices.length ? `<div class="tpal-section-title">Tracks</div>${renderRows(primaryChoices)}` : ""}${specializedChoices.length && _tpalState.mode !== "plan-picker" ? `<div class="tpal-section-title">Specialized</div>${renderRows(specializedChoices)}` : ""}`
      : '<div class="tpal-empty-state">No symbol families are available for this workflow.</div>';
  }
}

function _tpalRenderCategories() {
  if (dom.tpalCategoryList) {
    dom.tpalCategoryList.innerHTML = "";
  }
  renderTpalBreadcrumbs();
}

function _tpalRenderTypes() {
  if (!dom.tpalTypeGrid) return;
  const aff = _tpalState.affiliation || "friendly";
  const items = getTpalVisibleItems();
  dom.tpalTypeGrid.innerHTML = items.map((item) => {
    const node = item.node;
    const hasChildren = getTacticalNavChildren(node).some((child) => isTpalNodeVisible(child));
    const isFolder = hasChildren && !item.exact;
    const selectionId = item.selectionId || _tpalState.selection || "";
    const pathLabels = item.searchResult
      ? item.path
          .map((nodeId, index) => getTacticalNavNodeAtPath(selectionId, item.path.slice(0, index + 1))?.label || "")
          .filter(Boolean)
      : [];
    const displayPath = item.searchResult ? [item.selectionLabel, ...pathLabels.slice(0, -1)].filter(Boolean).join(" / ") : "";
    return `<button class="tpal-type-btn" type="button"
      data-selection="${escapeHtml(selectionId)}"
      data-node-id="${escapeHtml(node.id)}"
      data-path="${escapeHtml(item.path.join("|"))}"
      data-exact="${item.exact ? "1" : "0"}">
      <span class="tpal-type-symbol">${renderTpalSymbol(node, { affiliation: aff })}</span>
      <span class="tpal-type-title">${escapeHtml(node.label)}${displayPath ? `<small>${escapeHtml(displayPath)}</small>` : ""}</span>
      <span class="tpal-type-meta ${isFolder ? "" : "is-select"}">${isFolder ? "More" : "Select"}</span>
    </button>`;
  }).join("");
  if (!items.length) {
    dom.tpalTypeGrid.innerHTML = '<div class="tpal-empty-state">No symbols match the current filter.</div>';
  }
  renderTpalBreadcrumbs();
}

function renderTacticalPaletteStep3() {
  ensureTpalSelectionPath();
  if (dom.tpalCategoryList) dom.tpalCategoryList.innerHTML = "";
  _tpalRenderTypes();
}

function handleTpalTypeButtonSelection(typeBtn) {
  if (!typeBtn) return false;
  const selectionId = String(typeBtn.dataset.selection || _tpalState.selection || "").trim();
  if (selectionId) {
    _tpalState.selection = selectionId;
  }
  const path = String(typeBtn.dataset.path || "").trim()
    ? String(typeBtn.dataset.path).split("|").filter(Boolean)
    : (String(typeBtn.dataset.nodeId || "").trim()
        ? [..._tpalState.path.slice(0, -1), String(typeBtn.dataset.nodeId || "").trim()]
        : _tpalState.path.slice());
  const node = getTacticalNavNodeAtPath(_tpalState.selection, path);
  const entry = node?.entry || node?.preview || null;
  if (!entry) return false;
  const hasChildren = getTacticalNavChildren(node).some((child) => isTpalNodeVisible(child));
  const exact = typeBtn.dataset.exact === "1";
  if (!exact && hasChildren) {
    _tpalState.path = path;
    _tpalState.search = "";
    if (dom.tacticalPaletteSearch) dom.tacticalPaletteSearch.value = "";
    renderTacticalPaletteStep3();
    _tpalSetStep(3);
    return true;
  }
  const sizeSelect = _tpalState.mode === "plan-picker"
    ? document.getElementById(_tpalState.planTarget === "edit" ? "toEditUnitSize" : "toUnitSize")
    : null;
  const currentSize = String(sizeSelect?.value || "").trim();
  commitTacticalPaletteSelection(entry, {
    affiliation: _tpalState.affiliation || "friendly",
    size: currentSize || (entry?.domain === "ground" && milstdUnitEntryAllowsEchelon(entry) ? "team" : ""),
    mode: _tpalState.mode,
  });
  return true;
}

function refreshPlanUnitTypePickerLabel(catalogId = "", affiliation = "friendly", { target = "create", entry = null } = {}) {
  const labelEl = target === "edit" ? dom.toEditUnitTypePickerLabel : dom.toUnitTypePickerLabel;
  if (!labelEl) {
    return;
  }
  const resolvedEntry = entry
    || getMilstdSymbolCatalogEntry(catalogId)
    || getDoctrinalCatalogEntryById(catalogId);
  const affLabel = FORCE_LABELS?.[affiliation] || formatToUnitLabelPart(affiliation || "friendly");
  const resolvedLabel = cleanMilstdUnitLabel(resolvedEntry?.label || "");
  labelEl.textContent = resolvedLabel ? `${affLabel} • ${resolvedLabel}` : `${affLabel} • Select Symbology`;
}

function updatePlanUnitTypePickerLabel(catalogId = "", affiliation = "friendly") {
  if (!dom.toUnitTypePickerLabel) {
    return;
  }
  const entry = getDoctrinalCatalogEntryById(catalogId);
  const affLabel = FORCE_LABELS?.[affiliation] || formatToUnitLabelPart(affiliation || "friendly");
  dom.toUnitTypePickerLabel.textContent = entry ? `${affLabel} • ${entry.label}` : `${affLabel} • Land Unit`;
}

function commitTacticalPaletteSelection(entry, { affiliation, size = "", mode = "placement" } = {}) {
  if (!entry) {
    return;
  }
  const aff = normalizeTacticalAffiliation(affiliation || _tpalState.affiliation || "friendly");
  const milstdEntry = getMilstdSymbolCatalogEntry(entry?.milstdCatalogId || entry?.id || entry?.uniqueId || entry);
  if (!milstdEntry) {
    return;
  }
  const uniqueId = normalizeMilstdUniqueId(milstdEntry.uniqueId || milstdEntry.id || "");
  const objectClass = milstdEntry.objectClass || "unit";
  const catalogId = normalizeToUnitType(uniqueId || milstdEntry.id || DEFAULT_MILSTD_UNIT_ID);
  const allowsEchelon = milstdUnitEntryAllowsEchelon(milstdEntry);
  const nextSize = allowsEchelon ? normalizePlanUnitSize(catalogId, size || DEFAULT_TO_UNIT_SIZE) : "";
  const detail = buildMilstdDetail({}, milstdEntry, aff, nextSize);
  const entryLabel = cleanMilstdUnitLabel(milstdEntry.label || entry.label || "Tactical Item");
  if (mode === "plan-picker") {
    const isEditTarget = _tpalState.planTarget === "edit";
    const typeInput = document.getElementById(isEditTarget ? "toEditUnitType" : "toUnitType");
    const sizeSelect = document.getElementById(isEditTarget ? "toEditUnitSize" : "toUnitSize");
    if (typeInput) {
      typeInput.value = catalogId;
    }
    const affiliationSelect = document.getElementById(isEditTarget ? "toEditAffiliation" : "toAffiliation");
    if (affiliationSelect) {
      affiliationSelect.value = aff;
    }
    setPlanUnitSizeSelectValue(sizeSelect, catalogId, nextSize);
    refreshPlanUnitTypePickerLabel(catalogId, aff, { target: isEditTarget ? "edit" : "create", entry: milstdEntry });
    if (isEditTarget) {
      syncToolbarFromEditDraft();
    } else {
      syncSelectedPlanUnitFromToolbar();
    }
    closeTacticalPaletteModal();
    setStatus(`Selected ${entryLabel} for the T/O builder.`);
    return;
  }
  beginTacticalPlacement({
    id: generateId(),
    name: getTacticalPaletteCustomName(entryLabel),
    objectClass,
    domain: normalizeTacticalDomain(milstdEntry.domain || "ground"),
    unitType: catalogId,
    catalogId: objectClass === "unit" ? catalogId : "",
    size: objectClass === "unit" && allowsEchelon ? (size || "team") : "",
    affiliation: aff,
    cotType: buildCatalogCotType(catalogId, aff) || getMilstdSymbolDefaultCotType(milstdEntry, aff),
    sidc: detail.milsymId || "",
    detail,
    geometryType: "Point",
    drawMode: "",
    shapeKind: "",
  });
}

function openTacticalPaletteModal(options = {}) {
  _tpalState.step = 1;
  _tpalState.mode = options.mode === "plan-picker" ? "plan-picker" : "placement";
  _tpalState.planTarget = options.planTarget === "edit" ? "edit" : "create";
  _tpalState.affiliation = options.affiliation
    ? normalizeTacticalAffiliation(options.affiliation)
    : (_tpalState.mode === "plan-picker" ? "friendly" : null);
  _tpalState.selection = null;
  _tpalState.path = [];
  _tpalState.search = "";
  if (dom.tacticalPaletteName) {
    dom.tacticalPaletteName.value = "";
  }
  if (dom.tacticalPaletteSearch) {
    dom.tacticalPaletteSearch.value = "";
  }
  if (_tpalState.mode === "plan-picker") {
    _tpalRenderTrackChoices();
    _tpalSetStep(2);
  } else {
    _tpalSetStep(1);
  }
  dom.tacticalPaletteModal?.classList.remove("hidden");
  updateModalBodyState();
}

function closeTacticalPaletteModal() {
  dom.tacticalPaletteModal?.classList.add("hidden");
  dom.tacticalPaletteModal?.classList.remove("tactical-palette-modal--plan-picker");
  updateModalBodyState();
}

