function getDefaultEnabledAiAgentProfileIds() {
  return Object.keys(AI_AGENT_PROFILES).filter((profileId) => profileId !== "general");
}

function normalizeEnabledAiAgentProfileIds(profileIds) {
  if (!Array.isArray(profileIds)) {
    return getDefaultEnabledAiAgentProfileIds();
  }
  return [...new Set(profileIds.filter((profileId) =>
    profileId !== "general" && Boolean(AI_AGENT_PROFILES[profileId])
  ))];
}

function getEnabledAiAgentProfileIds({ includeGeneral = true } = {}) {
  const enabled = normalizeEnabledAiAgentProfileIds(state.ai?.enabledAgentProfileIds);
  return (includeGeneral ? ["general", ...enabled] : enabled)
    .filter((profileId, index, list) => Boolean(AI_AGENT_PROFILES[profileId]) && list.indexOf(profileId) === index);
}

function isAiAgentProfileEnabled(profileId) {
  if (profileId === "general") {
    return true;
  }
  return getEnabledAiAgentProfileIds({ includeGeneral: false }).includes(profileId);
}

function getAiAgentProfileTriggerSummary(profileId) {
  const profile = AI_AGENT_PROFILES[profileId];
  if (!profile) {
    return [];
  }
  return [...new Set((profile.triggerPhrases || []).filter(Boolean))].slice(0, 5);
}

function renderAiAgentProfileSettings() {
  const container = dom.aiAgentProfilesList;
  if (!container) {
    return;
  }
  const enabled = new Set(getEnabledAiAgentProfileIds({ includeGeneral: false }));
  const profiles = Object.entries(AI_AGENT_PROFILES)
    .sort((left, right) => {
      if (left[0] === "general") return -1;
      if (right[0] === "general") return 1;
      return (right[1].routingPriority || 0) - (left[1].routingPriority || 0);
    });
  container.innerHTML = profiles.map(([profileId, profile]) => {
    const triggers = getAiAgentProfileTriggerSummary(profileId);
    const isGeneral = profileId === "general";
    const isEnabled = isGeneral || enabled.has(profileId);
    const triggerList = triggers.length
      ? triggers.map((t) => `<span class="ai-agent-profile-trigger">${escapeHtml(t)}</span>`).join("")
      : `<span class="ai-agent-profile-trigger-note">Fallback mode when no specialist trigger is strong.</span>`;
    const tooltipHtml = `
      <div class="ai-agent-profile-tooltip-description">${escapeHtml(profile.summary)}</div>
      <div class="ai-agent-profile-tooltip-triggers">${triggerList}</div>
    `.trim();
    return `
      <div class="ai-agent-profile-chip${isEnabled ? "" : " is-disabled"}" data-ai-agent-profile-card="${profileId}">
        <label class="ai-agent-profile-chip-toggle${isGeneral ? " is-always-on" : ""}">
          <input
            type="checkbox"
            data-ai-agent-profile-id="${profileId}"
            ${isEnabled ? "checked" : ""}
            ${isGeneral ? "disabled" : ""}
          >
          <span class="ai-agent-profile-chip-box" aria-hidden="true">${isEnabled ? "âœ•" : ""}</span>
        </label>
        <span class="ai-agent-profile-chip-name">${escapeHtml(profile.label)}</span>
        <button type="button" class="ai-agent-profile-info-btn" aria-label="About ${escapeHtml(profile.label)}" data-ai-profile-tooltip="${escapeHtml(tooltipHtml)}">â“˜</button>
      </div>
    `;
  }).join("");
}

function setEnabledAiAgentProfileIds(profileIds, { reason = "" } = {}) {
  state.ai.enabledAgentProfileIds = normalizeEnabledAiAgentProfileIds(profileIds);
  if (!isAiAgentProfileEnabled(state.ai.agentProfileId)) {
    const previousProfile = getAiAgentProfile(state.ai.agentProfileId);
    setAiAgentProfile("general", {
      confidence: 1,
      reason: reason || `${previousProfile.label} was disabled in AI Integration settings.`,
      pinned: false,
    });
  }
}

function getAiViewProfile(view = state.ui?.currentView) {
  return AI_VIEW_PROFILES[view] ?? AI_VIEW_PROFILES.map;
}

function getAiAgentProfile(profileId = state.ai?.agentProfileId) {
  return AI_AGENT_PROFILES[profileId] ?? AI_AGENT_PROFILES.general;
}

function buildCurrentViewAiContext(view = state.ui?.currentView, options = {}) {
  if (view === "plan") return buildPlanAiContext(options);
  if (view === "emitters") return buildEmittersAiContext(options);
  if (view === "topology") return buildTopoAiContext(options);
  if (view === "analyze") return buildAnalyzeAiContext(options);
  return "";
}

const AI_SCENARIO_TIER_LIMITS = {
  minimal: {
    assets: 12,
    importedIndex: 24,
    mapLookupIndex: 36,
    viewsheds: 6,
    planUnits: 20,
  },
  standard: {
    assets: 24,
    importedIndex: 80,
    mapLookupIndex: 120,
    viewsheds: 12,
    planUnits: 40,
  },
  rich: {
    assets: 40,
    importedIndex: 200,
    mapLookupIndex: 300,
    viewsheds: 20,
    planUnits: 80,
  },
};

function normalizeAgentRoutingText(value) {
  return String(value ?? "").toLowerCase();
}

function resolveAiAgentProfile({ prompt = "", currentView = state.ui?.currentView, contextIds = [], recentMessages = [] } = {}) {
  const text = normalizeAgentRoutingText(prompt);
  const recentText = recentMessages.slice(-6).map((msg) => normalizeAgentRoutingText(msg?.text)).join(" \n ");
  const combined = `${text}\n${recentText}`;
  const scores = {};
  const eligibleProfiles = getEnabledAiAgentProfileIds();
  eligibleProfiles.forEach((key) => {
    scores[key] = key === "general" ? 1 : 0;
  });

  eligibleProfiles.forEach((profileId) => {
    const profile = AI_AGENT_PROFILES[profileId];
    (profile.triggerPhrases || []).forEach((phrase) => {
      if (combined.includes(normalizeAgentRoutingText(phrase))) {
        scores[profileId] += 18;
      }
    });
  });

  const addScore = (profileId, value) => {
    if (Object.prototype.hasOwnProperty.call(scores, profileId)) {
      scores[profileId] += value;
    }
  };

  if (/\b(cp|command post|toc)\b/.test(combined)) addScore("command_post_site_selection", 30);
  if (/\b(relay|retrans|repeater|los|line of sight|qth|shore|beach)\b/.test(combined)) addScore("relay_planning", 26);
  if (/\b(rocket m5|ubiquiti|5 ghz|backhaul|fresnel|dish|ptp)\b/.test(combined)) addScore("microwave_backhaul", 28);
  if (/\b(sensor|isr|surveillance|observation|watch)\b/.test(combined)) addScore("rf_sensor_site_selection", 24);
  if (/\b(interference|deconflict|spectrum|channel plan|frequency conflict)\b/.test(combined)) addScore("spectrum_deconfliction", 24);
  if (/\b(jammer|ew|intercept|detection risk|lpi|lpd)\b/.test(combined)) addScore("ew_threat_analysis", 24);
  if (/\b(route|movement|convoy|handoff)\b/.test(combined)) addScore("movement_route_comms", 22);
  if (/\b(compare|best site|which site|candidate)\b/.test(combined)) addScore("site_comparison", 18);
  if (/\b(masked|concealed|screened|terrain masking|hidden site)\b/.test(combined)) addScore("terrain_masking", 18);
  if (/\b(why can't|why cant|blocked link|diagnose|why is this link|marginal)\b/.test(combined)) addScore("link_diagnosis", 20);

  if (currentView === "topology") {
    addScore("link_diagnosis", 8);
    addScore("relay_planning", 5);
  } else if (currentView === "analyze") {
    addScore("spectrum_deconfliction", 4);
    addScore("ew_threat_analysis", 4);
  }

  if (state.siteStudy?.type === "relay") addScore("relay_planning", 6);
  if (state.siteStudy?.type === "sensor") addScore("rf_sensor_site_selection", 6);
  if (state.siteStudy?.type === "command-post") addScore("command_post_site_selection", 6);
  if (state.siteStudy?.type === "link") addScore("link_diagnosis", 6);

  const selectedObjects = contextIds
    .map((contentId) => getMapContentName(contentId))
    .filter(Boolean)
    .map((name) => normalizeAgentRoutingText(name))
    .join(" ");
  if (/\b(cp|command post|toc)\b/.test(selectedObjects)) addScore("command_post_site_selection", 10);
  if (/\b(sensor|radar|observation)\b/.test(selectedObjects)) addScore("rf_sensor_site_selection", 10);

  const ranked = Object.entries(scores)
    .sort((left, right) => right[1] - left[1]);
  const [bestId, bestScore] = ranked[0];
  const secondScore = ranked[1]?.[1] ?? 0;
  const spread = bestScore - secondScore;
  const confidence = bestId === "general"
    ? 0.35
    : spread >= 20 ? 0.95 : spread >= 12 ? 0.82 : spread >= 6 ? 0.66 : 0.48;
  const reason = bestId === "general"
    ? "No strong specialist task cues detected."
    : `Matched ${getAiAgentProfile(bestId).label} intent from prompt and scenario context.`;
  return {
    profileId: bestId,
    confidence,
    reason,
    alternatives: ranked.slice(1, 3).map(([profileId]) => profileId),
  };
}

function setAiAgentProfile(profileId, { confidence = 1, reason = "", pinned = false } = {}) {
  const next = AI_AGENT_PROFILES[profileId] && isAiAgentProfileEnabled(profileId) ? profileId : "general";
  state.ai.agentProfileId = next;
  state.ai.agentProfileConfidence = confidence;
  state.ai.agentProfileReason = reason || getAiAgentProfile(next).summary;
  state.ai.agentProfilePinned = next === "general" ? false : Boolean(pinned);
  state.ai.agentProfileLastUpdatedAt = new Date().toISOString();
}

function syncAiAgentModeSelect() {
  const select = dom.aiAgentModeSelect;
  if (!select) return;
  const allowedProfiles = new Set(getEnabledAiAgentProfileIds());
  const currentValue = allowedProfiles.has(state.ai.agentProfileId) ? state.ai.agentProfileId : "general";
  if (currentValue !== state.ai.agentProfileId) {
    setAiAgentProfile("general", {
      confidence: 1,
      reason: "Current agent profile is disabled in AI Integration settings.",
      pinned: false,
    });
  }
  const profiles = Object.entries(AI_AGENT_PROFILES)
    .filter(([profileId]) => allowedProfiles.has(profileId))
    .sort((a, b) => (b[1].routingPriority || 0) - (a[1].routingPriority || 0));
  const expected = profiles.length;
  if (select.options.length !== expected) {
    select.innerHTML = "";
    profiles.forEach(([profileId, profile]) => {
      const option = document.createElement("option");
      option.value = profileId;
      option.textContent = profile.label;
      select.appendChild(option);
    });
  }
  select.value = AI_AGENT_PROFILES[currentValue] ? currentValue : "general";
}

function syncAiViewMeta() {
  const profile = getAiViewProfile();
  const agentProfile = getAiAgentProfile();
  if (dom.aiChatInput) {
    dom.aiChatInput.placeholder = agentProfile.label === "General"
      ? profile.placeholder
      : `${agentProfile.label}: ${agentProfile.summary}`;
  }
  if (dom.aiPanel) {
    dom.aiPanel.setAttribute("aria-label", `${agentProfile.label} ${profile.role} panel`);
  }
}

function getAiProviderMeta(provider) {
  return AI_PROVIDER_CATALOG[provider] ?? null;
}

function normalizeAiModelId(modelId) {
  return String(modelId ?? "").trim();
}

function humanizeAiModelLabel(modelId) {
  return normalizeAiModelId(modelId)
    .replace(/[-_]+/g, " ")
    .replace(/\b\w/g, (match) => match.toUpperCase())
    .replace(/\bAi\b/g, "AI")
    .replace(/\bMil\b/g, "mil");
}

function normalizeAiModelEntries(entries = []) {
  const deduped = [];
  entries.forEach((entry) => {
    const value = normalizeAiModelId(typeof entry === "string" ? entry : entry?.value ?? entry?.id ?? entry?.model ?? entry?.name);
    if (!value || deduped.some((model) => model.value === value)) {
      return;
    }
    const label = typeof entry === "string"
      ? humanizeAiModelLabel(value)
      : normalizeAiModelId(entry?.label ?? entry?.display_name ?? entry?.displayName) || humanizeAiModelLabel(value);
    deduped.push({ value, label });
  });
  return deduped;
}

function getDiscoveredAiProviderModels(provider) {
  return Array.isArray(state.ai.discoveredModelsByProvider?.[provider])
    ? state.ai.discoveredModelsByProvider[provider]
    : [];
}

function getAiProviderModels(provider) {
  const discovered = getDiscoveredAiProviderModels(provider);
  if (discovered.length) {
    return discovered;
  }
  return getAiProviderMeta(provider)?.models ?? [];
}

function choosePreferredGenAiMilModel(models = []) {
  const available = normalizeAiModelEntries(models);
  if (!available.length) {
    return "";
  }
  const exactPreferences = [
    "gemini-3.1-pro",
    "gemini-3.1",
    "gemini-2.5-pro",
    "gemini-2.5-flash",
  ];
  for (const preference of exactPreferences) {
    const exact = available.find((model) => model.value.toLowerCase() === preference);
    if (exact) {
      return exact.value;
    }
  }
  const regexPreferences = [
    /gemini[-_]?3(?:\.|-)?1.*pro/i,
    /gemini[-_]?3(?:\.|-)?1/i,
    /gemini[-_]?2(?:\.|-)?5.*pro/i,
    /gemini[-_]?2(?:\.|-)?5.*flash/i,
    /gemini[-_]?2(?:\.|-)?5/i,
    /gemini/i,
  ];
  for (const pattern of regexPreferences) {
    const match = available.find((model) => pattern.test(model.value));
    if (match) {
      return match.value;
    }
  }
  return available[0]?.value ?? "";
}

function getDefaultAiModel(provider) {
  if (provider === "genai-mil") {
    return choosePreferredGenAiMilModel(getAiProviderModels(provider)) || getAiProviderMeta(provider)?.defaultModel || "";
  }
  return getAiProviderMeta(provider)?.defaultModel ?? "";
}

function ensureAiModelForProvider(provider, model = "") {
  const meta = getAiProviderMeta(provider);
  if (meta?.isLocalModel) return typeof model === "string" ? model : "";
  const models = getAiProviderModels(provider);
  if (!models.length) return "";
  if (models.some((entry) => entry.value === model)) return model;
  return getDefaultAiModel(provider);
}

function getAiModelLabel(provider, model) {
  return getAiProviderModels(provider).find((entry) => entry.value === model)?.label ?? model ?? "";
}

function setDiscoveredAiProviderModels(provider, entries = []) {
  state.ai.discoveredModelsByProvider[provider] = normalizeAiModelEntries(entries);
}

function getAiProviderLabel(provider) {
  return getAiProviderMeta(provider)?.shortLabel ?? "No Provider";
}

function maskAiApiKey(apiKey) {
  if (!apiKey) {
    return "No key";
  }
  if (apiKey.length <= 8) {
    return `${apiKey.slice(0, 2)}...${apiKey.slice(-2)}`;
  }
  return `${apiKey.slice(0, 4)}...${apiKey.slice(-4)}`;
}

function generateAiConfigId() {
  if (window.crypto?.randomUUID) {
    return window.crypto.randomUUID();
  }
  return `ai-${Date.now()}-${Math.random().toString(16).slice(2, 10)}`;
}

function sanitizeAiSavedConfig(config) {
  if (!config || typeof config !== "object") {
    return null;
  }
  const provider = typeof config.provider === "string" ? config.provider : "";
  const apiKey = typeof config.apiKey === "string" ? config.apiKey.trim() : "";
  const meta = getAiProviderMeta(provider);
  if (!meta) return null;
  // Local model doesn't require an API key â€” model name is stored in the apiKey field
  if (!meta.isLocalModel && !apiKey) return null;
  return {
    id: typeof config.id === "string" && config.id ? config.id : generateAiConfigId(),
    label: typeof config.label === "string" ? config.label.trim() : "",
    provider,
    apiKey,
    model: ensureAiModelForProvider(provider, typeof config.model === "string" ? config.model : ""),
    localModelUrl: typeof config.localModelUrl === "string" ? config.localModelUrl.trim() : "",
    serverWide: Boolean(config.serverWide),
    ownerUsername: typeof config.ownerUsername === "string" ? config.ownerUsername.trim() : "",
  };
}

function serializeAiSavedConfigForClientStorage(config) {
  if (!config) {
    return null;
  }
  return {
    id: config.id,
    label: config.label,
    provider: config.provider,
    apiKey: config.apiKey,
    model: config.model,
    localModelUrl: config.localModelUrl || "",
    serverWide: Boolean(config.serverWide),
    ownerUsername: config.ownerUsername || "",
  };
}

function sameAiSavedConfig(left, right) {
  if (!left || !right) {
    return false;
  }
  return left.label === right.label
    && left.provider === right.provider
    && left.apiKey === right.apiKey
    && left.model === right.model
    && Boolean(left.serverWide) === Boolean(right.serverWide);
}

function mergeAiSavedConfigs(primaryConfigs = [], secondaryConfigs = []) {
  const merged = [];
  [...primaryConfigs, ...secondaryConfigs].forEach((config) => {
    const sanitized = sanitizeAiSavedConfig(config);
    if (!sanitized) {
      return;
    }
    const exists = merged.some((entry) => entry.id === sanitized.id || sameAiSavedConfig(entry, sanitized));
    if (!exists) {
      merged.push(sanitized);
    }
  });
  return merged;
}

function aiSavedConfigListsEqual(leftConfigs = [], rightConfigs = []) {
  if (leftConfigs.length !== rightConfigs.length) {
    return false;
  }
  return leftConfigs.every((config, index) => {
    const other = rightConfigs[index];
    return Boolean(other)
      && config.id === other.id
      && sameAiSavedConfig(config, other);
  });
}

function getAiSavedConfigDisplayLabel(config) {
  if (!config) {
    return "";
  }
  const baseLabel = config.label || `${getAiProviderLabel(config.provider)} | ${maskAiApiKey(config.apiKey)}`;
  return config.serverWide ? `${baseLabel} | Server Wide` : baseLabel;
}

function getSavedAiConfig(configId = state.ai.activeConfigId) {
  return state.ai.savedConfigs.find((config) => config.id === configId) ?? null;
}

function getEffectiveAiConfig() {
  if (state.ai.provider && state.ai.apiKey) {
    return {
      provider: state.ai.provider,
      apiKey: state.ai.apiKey,
      model: ensureAiModelForProvider(state.ai.provider, state.ai.model),
      source: "user",
      serverWide: false,
    };
  }
  const fallback = sanitizeAiSavedConfig(state.ai.serverFallbackConfig);
  if (!state.ai.serverFallbackGrantEnabled || !fallback) {
    return null;
  }
  return {
    provider: fallback.provider,
    apiKey: fallback.apiKey,
    model: ensureAiModelForProvider(fallback.provider, fallback.model),
    source: "server",
    serverWide: true,
    ownerUsername: state.ai.serverFallbackConfig?.ownerUsername || "",
  };
}

function isUsingServerFallbackAiConfig() {
  return getEffectiveAiConfig()?.source === "server";
}

function isAnalyticsAdmin() {
  return !isGuestSession() && Boolean(state.session.user?.isAdmin);
}

function setActiveAiDraft(provider, apiKey, model, configId = "", label = "") {
  state.ai.provider = provider;
  state.ai.apiKey = apiKey;
  state.ai.model = ensureAiModelForProvider(provider, model);
  state.ai.activeConfigId = configId;
  state.ai.configLabel = label;
}

function syncActiveAiConfigFromDraft() {
  // Draft edits should not mutate a saved key until the user explicitly saves.
}

function setAiStatusFromCurrentConfig() {
  if (state.ai.provider && state.ai.apiKey) {
    state.ai.status = "pending";
    state.ai.statusMessage = "Provider configured. Testing connection...";
    return;
  }
  state.ai.status = "offline";
  state.ai.statusMessage = defaultAiStatusMessage();
}

function renderAiSavedConfigOptions() {
  if (!dom.aiSavedConfigSelect) {
    return;
  }
  const options = state.ai.savedConfigs.length
    ? [
        '<option value="">Select saved key</option>',
        ...state.ai.savedConfigs.map((config) => {
          return `<option value="${escapeHtml(config.id)}">${escapeHtml(getAiSavedConfigDisplayLabel(config))}</option>`;
        }),
      ]
    : ['<option value="">No saved keys</option>'];
  dom.aiSavedConfigSelect.innerHTML = options.join("");
  dom.aiSavedConfigSelect.value = state.ai.savedConfigs.some((config) => config.id === state.ai.activeConfigId)
    ? state.ai.activeConfigId
    : "";
}

function renderAiModelSelect(selectEl, { emptyLabel = "No model available" } = {}) {
  if (!selectEl) {
    return;
  }
  const isLocal = getAiProviderMeta(state.ai.provider)?.isLocalModel;
  if (isLocal) {
    // For local models the model name is free-form â€” show a single editable option.
    const modelName = state.ai.apiKey.trim() || state.ai.model.trim() || "default";
    selectEl.innerHTML = `<option value="${escapeHtml(modelName)}">${escapeHtml(modelName)}</option>`;
    selectEl.value = modelName;
    return;
  }
  const models = getAiProviderModels(state.ai.provider);
  if (!models.length) {
    selectEl.innerHTML = `<option value="">${escapeHtml(emptyLabel)}</option>`;
    selectEl.value = "";
    return;
  }
  selectEl.innerHTML = models
    .map((model) => `<option value="${escapeHtml(model.value)}">${escapeHtml(model.label)}</option>`)
    .join("");
  selectEl.value = ensureAiModelForProvider(state.ai.provider, state.ai.model);
}

function renderAiModelOptions() {
  renderAiModelSelect(dom.aiChatModelSelect);
  renderAiModelSelect(dom.aiSettingsModelSelect, { emptyLabel: "Auto-select after key validation" });
}

async function syncAiProviderSettingsToServer() {
  if (!state.session.token) {
    return;
  }

  await apiFetch("/user/ai-configs", {
    method: "PUT",
    body: JSON.stringify({
      configs: state.ai.savedConfigs.map((config) => ({
        id: config.id,
        label: config.label,
        provider: config.provider,
        apiKey: config.apiKey,
        model: config.model,
        serverWide: Boolean(config.serverWide),
      })),
    }),
  });
}

async function loadServerAiProviderSettings() {
  if (!state.session.token) {
    return;
  }

  try {
    const localConfigs = state.ai.savedConfigs.map(sanitizeAiSavedConfig).filter(Boolean);
    const payload = await apiFetch("/user/ai-configs");
    const serverConfigs = Array.isArray(payload.configs)
      ? payload.configs.map(sanitizeAiSavedConfig).filter(Boolean)
      : [];
    const mergedConfigs = mergeAiSavedConfigs(serverConfigs, localConfigs);

    state.ai.savedConfigs = mergedConfigs;
    state.ai.canManageServerWideKey = Boolean(payload.canManageServerWideKey);
    state.ai.serverFallbackGrantEnabled = Boolean(payload.fallbackGrantEnabled);
    state.ai.serverFallbackConfig = sanitizeAiSavedConfig(payload.fallbackConfig);
    state.ai.serverWideDraftEnabled = false;
    if (state.ai.activeConfigId && !mergedConfigs.some((config) => config.id === state.ai.activeConfigId)) {
      state.ai.activeConfigId = "";
    }
    const activeConfig = mergedConfigs.find((config) => config.id === state.ai.activeConfigId) ?? mergedConfigs[0] ?? null;
    if (activeConfig) {
      setActiveAiDraft(activeConfig.provider, activeConfig.apiKey, activeConfig.model, activeConfig.id, activeConfig.label);
      state.ai.serverWideDraftEnabled = Boolean(activeConfig.serverWide);
    }
    setAiStatusFromCurrentConfig();

    persistAiProviderSettings();
    syncAiUi();

    if (!aiSavedConfigListsEqual(serverConfigs, mergedConfigs)) {
      await syncAiProviderSettingsToServer();
    }
  } catch (error) {
    syncAiUi();
    setStatus(`AI provider settings unavailable: ${error.message}`, true);
  }
}

function persistSessionStorage() {
  if (isGuestSession()) {
    window.sessionStorage.removeItem(AUTH_TOKEN_STORAGE_KEY);
    window.sessionStorage.removeItem(ACTIVE_PROJECT_STORAGE_KEY);
    window.sessionStorage.removeItem(LOCAL_WORKSPACE_MODE_STORAGE_KEY);
    window.localStorage.removeItem(AUTH_TOKEN_STORAGE_KEY);
    window.localStorage.removeItem(ACTIVE_PROJECT_STORAGE_KEY);
    window.localStorage.removeItem(LOCAL_WORKSPACE_MODE_STORAGE_KEY);
    return;
  }
  setSessionToken(state.session.token);
  setSessionScopedItem(ACTIVE_PROJECT_STORAGE_KEY, state.session.activeProjectId);
  setSessionScopedItem(LOCAL_WORKSPACE_MODE_STORAGE_KEY, state.session.localModePinned ? "1" : null);
}

function clearSessionState({ preserveGuest = false } = {}) {
  if (state.session.autosaveTimerId) {
    window.clearTimeout(state.session.autosaveTimerId);
  }
  if (state.session.localSaveTimerId) {
    window.clearTimeout(state.session.localSaveTimerId);
  }
  stopTakLivePolling({ clearContacts: true });
  if (!preserveGuest) {
    setGuestSessionEnabled(false);
  }
  clearAiChatHistory();
  state.ai.messages = [];
  state.ai.savedConfigs = [];
  state.ai.activeConfigId = "";
  state.ai.canManageServerWideKey = false;
  state.ai.serverWideDraftEnabled = false;
  state.ai.serverFallbackGrantEnabled = false;
  state.ai.serverFallbackConfig = null;
  state.session.token = null;
  state.session.user = null;
  state.session.projects = [];
  state.session.activeProjectId = null;
  state.session.localModePinned = false;
  state.session.activeProjectRevision = null;
  state.session.autosaveTimerId = null;
  state.session.autosavePending = false;
  state.session.localSaveTimerId = null;
  state.takSettings.profiles = [];
  state.takSettings.projectAssignments = new Map();
  state.takIdentity = normalizeTakIdentity({ callsign: "RF SIM" });
  resetTakDraft();
  persistSessionStorage();
  syncTakIdentityUi();
}

async function hydrateSession({ preferServerProject = false } = {}) {
  if (isGuestSession()) {
    await loadEmitterProfileLibrary();
    syncWorkspaceUi();
    return;
  }
  if (!state.session.token) {
    await loadEmitterProfileLibrary();
    syncWorkspaceUi();
    return;
  }

  try {
    const payload = await apiFetch("/auth/me");
    state.session.user = payload.user;
    loadTakIdentitySettings();
    await loadProjectList({ preferServerProject });
    await loadServerTakSettings();
    await loadEmitterProfileLibrary();
    await loadServerAiProviderSettings();
    fireAnalyticsEvent({ event_type: "visit" });
  } catch (error) {
    if (/Invalid token|Authentication required|User not found/i.test(error.message)) {
      clearSessionState();
      setStatus(`Session reset: ${error.message}`, true);
    } else {
      setStatus(`Workspace sync warning: ${error.message}`, true);
    }
  }
  syncWorkspaceUi();
}

async function loadProjectList({ preferServerProject = false } = {}) {
  if (!state.session.token) {
    state.session.projects = [];
    syncWorkspaceUi();
    return;
  }
  const payload = await apiFetch("/projects");
  state.session.projects = payload.projects ?? [];
  const resolvedActiveProjectId = workspacePolicy.resolveActiveProjectId({
    projects: state.session.projects,
    requestedProjectId: state.session.activeProjectId,
    preferServerProject: preferServerProject && !isLocalWorkspaceModePinned(),
    allowLocalMode: true,
  });
  if (resolvedActiveProjectId !== state.session.activeProjectId) {
    state.session.activeProjectId = resolvedActiveProjectId;
    setActiveProjectRevision(null);
    persistSessionStorage();
  }
  syncWorkspaceUi();
}

function setActiveProjectRevision(revision = null) {
  const numericRevision = Number(revision);
  state.session.activeProjectRevision = Number.isFinite(numericRevision) ? numericRevision : null;
}

function setAuthScreenStatus(message = "", isError = false) {
  if (!dom.authScreenStatus) {
    return;
  }
  const fallback = state.authScreenMode === "register"
    ? "Create an account to enter the workspace."
    : "Sign in or use guest mode to continue.";
  dom.authScreenStatus.textContent = message || fallback;
  dom.authScreenStatus.classList.toggle("error", Boolean(isError));
}

function setAuthScreenMode(mode) {
  state.authScreenMode = mode === "register" ? "register" : "login";
  syncAuthScreenUi();
}

function syncAuthScreenUi() {
  if (!dom.authScreen) {
    return;
  }
  const hasAccess = hasWorkspaceAccess();
  document.body.classList.toggle("auth-screen-active", !hasAccess);
  dom.authScreen.classList.toggle("hidden", hasAccess);
  dom.authScreen.setAttribute("aria-hidden", String(hasAccess));
  if (hasAccess) {
    return;
  }

  const isRegister = state.authScreenMode === "register";
  dom.authScreenTitle.textContent = "RF Sim";
  dom.authScreenCopy.textContent = isRegister
    ? "Create a free account to save projects, retain your AI chat, and access all features."
    : "Sign in to access your projects and AI planning tools.";
  dom.authScreenFullNameRow?.classList.add("hidden");
  dom.authScreenSubmitBtn.textContent = isRegister ? "Create Account" : "Sign In";
  // Toggle mode button switches role between register CTA and back-to-login link
  dom.authScreenToggleModeBtn.textContent = isRegister ? "Back to sign in" : "Create a free account";
  dom.authScreenToggleModeBtn.className = isRegister ? "auth-screen-link" : "auth-screen-register-btn";
  // Mode copy line only shown in register mode
  if (dom.authScreenModeCopy) {
    dom.authScreenModeCopy.textContent = isRegister ? "Already have an account?" : "";
    dom.authScreenModeCopy.style.display = isRegister ? "" : "none";
  }
  // Guest link only shown on login screen
  if (dom.authScreenGuestBtn) {
    dom.authScreenGuestBtn.style.display = isRegister ? "none" : "";
  }
  if (!dom.authScreenStatus.textContent.trim()) {
    setAuthScreenStatus("", false);
  }
}

function getAuthScreenCredentials() {
  return {
    fullName: dom.authScreenFullName?.value.trim() ?? "",
    email: dom.authScreenEmail?.value.trim() ?? "",
    password: dom.authScreenPassword?.value ?? "",
  };
}

async function submitAuthScreen() {
  const credentials = getAuthScreenCredentials();
  if (state.authScreenMode === "register") {
    setAuthScreenStatus("Creating account...");
    await onWorkspaceRegister(credentials);
  } else {
    setAuthScreenStatus("Signing in...");
    await onWorkspaceLogin(credentials);
  }
  dom.authScreenPassword.value = "";
}

async function enterGuestMode() {
  setGuestSessionEnabled(true);
  clearSessionState({ preserveGuest: true });
  await loadEmitterProfileLibrary();
  loadSettings();
  syncWorkspaceUi();
  await reloadWorkspaceState({ restoreAiHistory: true, statusMessage: "Guest workspace ready." });
}

function syncWorkspaceUi() {
  if (!dom.workspaceMenuBtn || !dom.workspaceMenu) {
    return;
  }

  const hasAccess = hasWorkspaceAccess();
  const guest = isGuestSession();
  dom.workspaceAuthGuest.classList.toggle("hidden", hasAccess);
  dom.workspaceAuthMember.classList.toggle("hidden", !hasAccess);
  dom.workspaceSignOutBtn.classList.toggle("hidden", !hasAccess);
  const isAdmin = hasAccess && !guest && isAnalyticsAdmin();
  dom.workspaceAdminRow?.classList.toggle("hidden", !isAdmin);
  dom.workspaceAnalyticsBtn?.setAttribute("aria-hidden", String(!isAdmin));
  dom.workspaceAnalyticsBtn?.toggleAttribute("hidden", !isAdmin);

  if (!hasAccess) {
    dom.workspaceMenuValue.textContent = "Sign In";
    dom.workspaceMenuHeadline.textContent = "Account & Projects";
    dom.workspaceStatus.textContent = "Sign in to enter RF Sim and access server-backed projects, or use guest mode for an in-memory session.";
    dom.workspaceProjectDeleteBtn?.setAttribute("disabled", "true");
    setAutosaveIndicator("hidden");
    syncTakUi();
    syncTakIdentityUi();
    syncAuthScreenUi();
    return;
  }

  if (guest) {
    setAutosaveIndicator("hidden");
    dom.workspaceSignOutBtn.textContent = "Exit Guest";
    dom.workspaceMenuValue.textContent = "Guest";
    dom.workspaceMenuHeadline.textContent = "Guest Workspace";
    dom.workspaceUserLabel.textContent = "Guest Session";
    dom.workspaceProjectMode.textContent = "Guest";
    dom.workspaceProjectStatus.textContent = "Guest mode does not save projects, AI keys, or Cesium tokens.";
    dom.workspaceProjectSelect.innerHTML = '<option value="">Ephemeral Session</option>';
    dom.workspaceProjectSelect.value = "";
    dom.workspaceProjectSelect.setAttribute("disabled", "true");
    dom.workspaceProjectName.value = "";
    dom.workspaceProjectName.setAttribute("disabled", "true");
    dom.workspaceProjectCreateBtn?.setAttribute("disabled", "true");
    dom.workspaceProjectSaveBtn?.setAttribute("disabled", "true");
    dom.workspaceProjectReloadBtn?.setAttribute("disabled", "true");
    dom.workspaceProjectDeleteBtn?.setAttribute("disabled", "true");
    setAuthScreenStatus("", false);
    syncTakUi();
    syncTakIdentityUi();
    syncAuthScreenUi();
    return;
  }

  dom.workspaceSignOutBtn.textContent = "Sign Out";
  dom.workspaceProjectSelect.removeAttribute("disabled");
  dom.workspaceProjectName.removeAttribute("disabled");
  dom.workspaceProjectCreateBtn?.removeAttribute("disabled");
  dom.workspaceProjectSaveBtn?.removeAttribute("disabled");
  dom.workspaceProjectReloadBtn?.removeAttribute("disabled");
  const userLabel = state.session.user.fullName || state.session.user.username || state.session.user.email;
  const activeProject = state.session.projects.find((project) => project.id === state.session.activeProjectId) ?? null;
  const activeProjectLabel = activeProject?.name || "Local Browser Draft";
  const activeTakProfile = getTakProfileForProject(state.session.activeProjectId);
  dom.workspaceUserLabel.textContent = userLabel;
  dom.workspaceMenuValue.textContent = activeProjectLabel;
  dom.workspaceMenuHeadline.textContent = state.session.activeProjectId ? "Server Project" : "Workspace";
  dom.workspaceProjectMode.textContent = state.session.activeProjectId ? "Server" : "Local";
  dom.workspaceProjectStatus.textContent = state.session.activeProjectId
    ? `Changes autosave to the server.${activeTakProfile ? ` TAK enabled via ${activeTakProfile.label || activeTakProfile.serverHost}.` : " TAK is not enabled for this project."}`
    : "Local browser draft mode is active. Project-backed work stays on the server; local drafts stay in this browser only.";

  dom.workspaceProjectSelect.innerHTML = "";
  const localOption = document.createElement("option");
  localOption.value = "";
  localOption.textContent = "Local Browser Draft";
  dom.workspaceProjectSelect.appendChild(localOption);
  state.session.projects.forEach((project) => {
    const option = document.createElement("option");
    option.value = project.id;
    option.textContent = project.name;
    dom.workspaceProjectSelect.appendChild(option);
  });
  dom.workspaceProjectSelect.value = state.session.activeProjectId ?? "";
  if (state.session.activeProjectId) {
    dom.workspaceProjectDeleteBtn?.removeAttribute("disabled");
  } else {
    dom.workspaceProjectDeleteBtn?.setAttribute("disabled", "true");
  }
  setAuthScreenStatus("", false);
  syncTakUi();
  syncTakIdentityUi();
  syncAuthScreenUi();
}

async function applyAuthenticatedSession(payload, successMessage) {
  setGuestSessionEnabled(false);
  setLocalWorkspaceModePinned(false);
  state.session.token = payload.token;
  state.session.user = payload.user;
  loadTakIdentitySettings();
  persistSessionStorage();
  await loadProjectList({ preferServerProject: true });
  await loadServerTakSettings();
  await loadEmitterProfileLibrary();
  await loadServerAiProviderSettings();
  await autoConnectAiProviderIfConfigured({ openPanelOnSuccess: false, force: true });
  syncWorkspaceUi();
  closeWorkspaceMenu();
  setAuthScreenStatus("", false);
  await reloadWorkspaceState({ restoreAiHistory: true, statusMessage: successMessage });
}

async function onWorkspaceLogin(credentials = null) {
  const username = (credentials?.email ?? dom.workspaceEmail.value).trim();
  const password = credentials?.password ?? dom.workspacePassword.value;
  if (!username || !password) {
    setStatus("Enter username and password.", true);
    setAuthScreenStatus("Enter username and password.", true);
    return;
  }

  const payload = await apiFetch("/auth/login", {
    method: "POST",
    body: JSON.stringify({ username, password }),
  });
  await applyAuthenticatedSession(
    payload,
    `Signed in as ${payload.user.fullName || payload.user.username || payload.user.email}.`,
  );
  fireAnalyticsEvent({ event_type: "visit" });
}

async function onWorkspaceRegister(credentials = null) {
  const username = (credentials?.email ?? dom.workspaceEmail.value).trim();
  const password = credentials?.password ?? dom.workspacePassword.value;
  if (!username || !password) {
    setStatus("Enter username and password to create an account.", true);
    setAuthScreenStatus("Enter username and password to create an account.", true);
    return;
  }

  const payload = await apiFetch("/auth/register", {
    method: "POST",
    body: JSON.stringify({ username, password }),
  });
  await applyAuthenticatedSession(
    payload,
    `Account created for ${payload.user.fullName || payload.user.username || payload.user.email}.`,
  );
}

async function onWorkspaceSignOut() {
  if (isGuestSession()) {
    clearSessionState();
    await loadEmitterProfileLibrary();
    loadSettings();
    syncWorkspaceUi();
    await reloadWorkspaceState({ restoreAiHistory: true, statusMessage: "Exited guest workspace." });
    return;
  }
  clearSessionState();
  await loadEmitterProfileLibrary();
  loadSettings();
  setAuthScreenMode("login");
  setAuthScreenStatus("Signed out. Sign in to continue.");
  syncWorkspaceUi();
  await reloadWorkspaceState({ restoreAiHistory: true, statusMessage: "Signed out." });
}

async function onWorkspaceProjectCreate() {
  if (!state.session.token) {
    setStatus("Sign in first to create a server project.", true);
    return;
  }

  const name = dom.workspaceProjectName.value.trim();
  if (!name) {
    setStatus("Enter a project name.", true);
    return;
  }

  if (!state.session.activeProjectId) {
    persistMapStateNow();
  }
  const projectKmzItems = state.importedItems
    .filter((item) => !item.drawn && !item.tak)
    .map((item) => serializeImportedItem(item));
  const payload = await apiFetch("/projects", {
    method: "POST",
    body: JSON.stringify({ name, description: "", state: serializeMapStateForServer() }),
  });
  await idbSaveKmzItems(payload.project.id, projectKmzItems);
  setLocalWorkspaceModePinned(false);
  state.session.activeProjectId = payload.project.id;
  setActiveProjectRevision(payload.project.revision);
  persistSessionStorage();
  await loadProjectList();
  dom.workspaceProjectName.value = "";
  await reloadWorkspaceState({ statusMessage: `Created project ${payload.project.name}.` });
}

async function onWorkspaceProjectSelectChanged() {
  const nextProjectId = dom.workspaceProjectSelect.value || null;
  if (!state.session.activeProjectId && nextProjectId) {
    persistMapStateNow();
  }
  setLocalWorkspaceModePinned(!nextProjectId);
  state.session.activeProjectId = nextProjectId;
  setActiveProjectRevision(null);
  persistSessionStorage();
  await reloadWorkspaceState({
    statusMessage: state.session.activeProjectId
      ? "Loaded server-backed project."
      : "Switched to local browser draft.",
  });
}

// â”€â”€ Autosave â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
// Three states: saving (ring fills with real XHR progress) â†’ saved (green check)
//                                                           â†’ error (red X)
// The indicator is always visible while a project is active.

const CIRCUMFERENCE = 37.7; // 2Ï€ Ã— r=6

function setAutosaveRingProgress(fraction) {
  const fill = document.getElementById("autosaveRingFill");
  if (fill) fill.style.strokeDashoffset = String(CIRCUMFERENCE * (1 - fraction));
}

function setAutosaveIndicator(state_) {
  const el = dom.autosaveIndicator;
  if (!el) return;

  el.classList.remove("hidden", "is-saving", "is-saved", "is-error");

  if (!state.session.activeProjectId) {
    el.classList.add("hidden");
  } else if (state_ === "saving") {
    el.classList.add("is-saving");
    el.setAttribute("title", "Saving to server...");
    setAutosaveRingProgress(0);
  } else if (state_ === "saved") {
    el.classList.add("is-saved");
    el.setAttribute("title", "All changes saved");
  } else if (state_ === "error") {
    el.classList.add("is-error");
    el.setAttribute("title", "Save failed â€” changes kept in browser storage");
  } else {
    el.classList.add("hidden");
  }

  // â”€â”€ Workspace dropdown status row â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  const row = dom.workspaceAutosaveStatus;
  const label = dom.workspaceAutosaveLabel;
  if (!row || !label) return;

  if (!state.session.activeProjectId) {
    row.className = "workspace-autosave-status hidden";
    return;
  }

  row.classList.remove("hidden");
  if (state_ === "saving") {
    row.className = "workspace-autosave-status is-saving";
    label.textContent = "Saving to server...";
  } else if (state_ === "saved") {
    row.className = "workspace-autosave-status is-saved";
    label.textContent = "All changes saved";
  } else if (state_ === "error") {
    row.className = "workspace-autosave-status is-error";
    label.textContent = "Save failed â€” changes in browser storage";
  } else {
    row.className = "workspace-autosave-status hidden";
  }
}

// XHR-based PUT so we get real upload progress events for the ring.
function xhrPutProject(projectId, body, token) {
  return new Promise((resolve, reject) => {
    const xhr = new XMLHttpRequest();
    xhr.open("PUT", `${API_BASE_URL}/projects/${projectId}`);
    xhr.setRequestHeader("Content-Type", "application/json");
    if (token) xhr.setRequestHeader("Authorization", `Bearer ${token}`);

    xhr.upload.addEventListener("progress", (e) => {
      if (e.lengthComputable) setAutosaveRingProgress(e.loaded / e.total);
    });
    xhr.upload.addEventListener("load", () => setAutosaveRingProgress(1));

    xhr.addEventListener("load", () => {
      let payload = {};
      try {
        payload = xhr.responseText ? JSON.parse(xhr.responseText) : {};
      } catch {
        payload = {};
      }
      if (xhr.status >= 200 && xhr.status < 300) {
        resolve(payload);
      } else {
        const error = new Error(payload.error ?? `HTTP ${xhr.status}`);
        error.status = xhr.status;
        error.payload = payload;
        reject(error);
      }
    });
    xhr.addEventListener("error", () => reject(new Error("Network error")));
    xhr.addEventListener("timeout", () => reject(new Error("Request timed out")));
    xhr.timeout = 30000;
    xhr.send(body);
  });
}

async function saveActiveProjectNow({ silent = false } = {}) {
  if (!state.session.token || !state.session.activeProjectId) return false;

  if (state.session.localSaveTimerId) {
    window.clearTimeout(state.session.localSaveTimerId);
    state.session.localSaveTimerId = null;
  }
  setAutosaveIndicator("saving");

  // Write to localStorage immediately as a safety net
  try {
    window.localStorage.setItem(getMapStateStorageKey(), JSON.stringify(serializeCurrentMapState()));
  } catch { /* quota */ }

  try {
    const serverState = serializeMapStateForServer();
    const body = JSON.stringify({
      state: serverState,
      revision: state.session.activeProjectRevision ?? 0,
      schemaVersion: STATE_SCHEMA_VERSION,
      clientSavedAt: serverState.savedAt ?? nowIso(),
    });
    const payload = await xhrPutProject(state.session.activeProjectId, body, state.session.token);
    setActiveProjectRevision(payload?.project?.revision ?? state.session.activeProjectRevision);
  } catch (err) {
    setAutosaveIndicator("error");
    if (err?.status === 409) {
      setActiveProjectRevision(err.payload?.project?.revision ?? state.session.activeProjectRevision);
      setStatus("Server project changed elsewhere. Reload the project before saving again.", true);
    }
    throw err;
  }

  state.session.autosavePending = false;
  syncWorkspaceUi();
  setAutosaveIndicator("saved");
  return true;
}

function flushPendingAutosave() {
  if (state.session.localSaveTimerId) {
    window.clearTimeout(state.session.localSaveTimerId);
    state.session.localSaveTimerId = null;
  }
  // Always write localStorage â€” guaranteed local recovery layer.
  try {
    window.localStorage.setItem(getMapStateStorageKey(), JSON.stringify(serializeCurrentMapState()));
  } catch { /* quota */ }

  if (!state.session.autosavePending && !state.session.autosaveTimerId) return;
  if (!state.session.token || !state.session.activeProjectId) return;

  if (state.session.autosaveTimerId) {
    window.clearTimeout(state.session.autosaveTimerId);
    state.session.autosaveTimerId = null;
  }

  // keepalive fetch survives page unload
  try {
    fetch(`${API_BASE_URL}/projects/${state.session.activeProjectId}`, {
      method: "PUT",
      keepalive: true,
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Bearer ${state.session.token}`,
      },
      body: JSON.stringify({
        state: serializeMapStateForServer(),
        revision: state.session.activeProjectRevision ?? 0,
      }),
    });
  } catch { /* best-effort */ }

  state.session.autosavePending = false;
}

function queueActiveProjectAutosave() {
  if (!state.session.token || !state.session.activeProjectId) return;

  state.session.autosavePending = true;
  syncWorkspaceUi();

  if (state.session.autosaveTimerId) window.clearTimeout(state.session.autosaveTimerId);

  state.session.autosaveTimerId = window.setTimeout(async () => {
    state.session.autosaveTimerId = null;
    try {
      await saveActiveProjectNow({ silent: true });
    } catch (error) {
      setStatus(`Autosave failed: ${error.message}`, true);
    }
  }, 1500);
}

async function onWorkspaceProjectReload() {
  if (!state.session.activeProjectId) {
    setStatus("Select a server project first.", true);
    return;
  }
  await reloadWorkspaceState({ statusMessage: "Reloaded active project from the server." });
}

async function onWorkspaceProjectSnapshot() {
  if (!state.session.activeProjectId) {
    setStatus("Select a server project first.", true);
    return;
  }
  const label = window.prompt("Snapshot label:", `Snapshot ${new Date().toLocaleString()}`)?.trim();
  if (!label) {
    return;
  }
  await apiFetch(`/projects/${state.session.activeProjectId}/snapshots`, {
    method: "POST",
    body: JSON.stringify({ label, state: serializeMapStateForServer() }),
  });
  setStatus(`Created snapshot ${label}.`);
}

async function onWorkspaceProjectDelete() {
  if (!state.session.token) {
    setStatus("Sign in first to manage server projects.", true);
    return;
  }

  const projectId = dom.workspaceProjectSelect.value || state.session.activeProjectId || "";
  if (!projectId) {
    setStatus("Select a server project first.", true);
    return;
  }

  const project = state.session.projects.find((entry) => entry.id === projectId);
  const projectName = project?.name || "this project";
  const confirmed = window.confirm(`Delete "${projectName}"? This removes the server project and its snapshots.`);
  if (!confirmed) {
    return;
  }

  await apiFetch(`/projects/${projectId}`, { method: "DELETE" });
  state.session.projects = state.session.projects.filter((entry) => entry.id !== projectId);
  state.takSettings.projectAssignments.delete(projectId);
  if (state.session.activeProjectId === projectId) {
    state.session.activeProjectId = state.session.projects[0]?.id ?? null;
    setLocalWorkspaceModePinned(!state.session.activeProjectId);
    setActiveProjectRevision(null);
  }
  persistSessionStorage();
  syncWorkspaceUi();
  syncTakUi();
  await reloadWorkspaceState({
    statusMessage: state.session.activeProjectId
      ? `Deleted project ${projectName}. Switched to the next server project.`
      : `Deleted project ${projectName}. Switched to local browser draft.`,
  });
}

// â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
// EMITTER MODAL
// â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

const emitterModal = {
  // Cached DOM refs set once on first open
  backdrop: null,
  emitterTypeSelect: null,
  programSelect: null,
  libSummary: null,
  savedProfileSearchInput: null,
  savedProfileSelect: null,
  profileNameInput: null,
  newDraftBtn: null,
  applySavedProfileBtn: null,
  saveSavedProfileBtn: null,
  saveProfileCopyBtn: null,
  deleteSavedProfileBtn: null,
  tabs: null,
  panels: null,
  fields: {},
  linkBudgetEls: {},
  typeSpecificFields: {},
  currentSavedProfileLink: null,
  originalAssetProfileLink: null,
  originalAssetPayload: null,

  init() {
    this.backdrop      = document.querySelector("#emitterModal");
    this.emitterTypeSelect = document.querySelector("#emitterTypeSelect");
    this.programSelect   = document.querySelector("#emitterProgramSelect");
    this.libSummary      = document.querySelector("#emitterLibSummary");
    this.savedProfileSearchInput = document.querySelector("#emitterSavedProfileSearch");
    this.savedProfileSelect = document.querySelector("#emitterSavedProfileSelect");
    this.profileNameInput = document.querySelector("#emitterProfileNameInput");
    this.newDraftBtn = document.querySelector("#emitterProfileNewBtn");
    this.applySavedProfileBtn = document.querySelector("#emitterProfileApplyBtn");
    this.saveSavedProfileBtn = document.querySelector("#emitterProfileSaveBtn");
    this.saveProfileCopyBtn = document.querySelector("#emitterProfileSaveCopyBtn");
    this.deleteSavedProfileBtn = document.querySelector("#emitterProfileDeleteBtn");
    this.tabs    = [...document.querySelectorAll(".emitter-tab")];
    this.panels  = [...document.querySelectorAll(".emitter-tab-panel")];

    // Map all input/select field IDs
    const ids = [
      "emName","emUnit","emForce","emIcon","emColor","emNotes",
      "emFreqMHz","emBandwidthKHz","emModulation","emWaveform","emDuplex","emChannelSpacingKHz",
      "emRadarMode","emPulseWidthUs","emPrfHz","emScanType",
      "emPowerW","emPowerDbm","emDutyCycle","emPapr","emSpectralEff","emEirpDbm",
      "emRxSensDbm","emNoiseFigDb","emReqSnrDb","emAcrDb","emBdrDb",
      "emAntennaType","emAntennaGainDbi","emRadPattern","emPolarization","emAntennaHeightM","emCableLossDb","emSystemLossDb",
      "emPropModel","emClutterType","emTerrainEnabled","emDiffractionEnabled",
      "emNvisEnabled","emIonoModel","emTimeDayEffects","emSolarIndex",
      "emIsManet","emRelayCapable","emMaxHops","emLatencyMs","emAdaptiveDataRate",
      "emSatcomEnabled","emSatType","emSatUplinkMHz","emSatDownlinkMHz","emSatGainDbi",
      "emGridLocation","emColocateAsset",
    ];
    ids.forEach((id) => { this.fields[id] = document.querySelector(`#${id}`); });
    ids.forEach((id) => {
      this.fields[id]?.addEventListener("input", () => this.onFormChanged());
      this.fields[id]?.addEventListener("change", () => this.onFormChanged());
    });
    this.typeSpecificFields = {
      waveform: document.querySelector("#emWaveformField"),
      duplex: document.querySelector("#emDuplexField"),
      channelSpacing: document.querySelector("#emChannelSpacingField"),
      radarMode: document.querySelector("#emRadarModeField"),
      pulseWidthUs: document.querySelector("#emPulseWidthUsField"),
      prfHz: document.querySelector("#emPrfHzField"),
      scanType: document.querySelector("#emScanTypeField"),
    };

    const lbIds = ["lb_txPower","lb_antennaGain","lb_cableLoss","lb_eirp","lb_fspl10","lb_rxPower10","lb_rxSens","lb_margin10","lb_maxRange"];
    lbIds.forEach((id) => { this.linkBudgetEls[id] = document.querySelector(`#${id}`); });

    // Tab switching
    this.tabs.forEach((tab) => {
      tab.addEventListener("click", () => this.switchTab(tab.dataset.tab));
    });

    // Radio type â†’ populate programs
    this.emitterTypeSelect.addEventListener("change", () => this.onEmitterTypeChange());

    // Program â†’ load profile
    this.programSelect?.addEventListener("change", () => this.onProgramChange());
    this.savedProfileSearchInput?.addEventListener("input", () => {
      state.emitterProfiles.searchText = this.savedProfileSearchInput.value.trim().toLowerCase();
      this.renderSavedProfileLibrary();
    });
    this.savedProfileSelect?.addEventListener("change", () => {
      state.emitterProfiles.activeProfileId = this.savedProfileSelect.value || "";
      this.syncSavedProfileSelectionUi();
    });
    this.newDraftBtn?.addEventListener("click", () => this.createNewDraft());
    this.applySavedProfileBtn?.addEventListener("click", () => this.applySelectedSavedProfile());
    this.saveSavedProfileBtn?.addEventListener("click", () => this.saveCurrentProfileToLibrary().catch((error) => setStatus(error.message, true)));
    this.saveProfileCopyBtn?.addEventListener("click", () => this.saveCurrentProfileToLibrary({ saveAsCopy: true }).catch((error) => setStatus(error.message, true)));
    this.deleteSavedProfileBtn?.addEventListener("click", () => this.deleteSelectedSavedProfile().catch((error) => setStatus(error.message, true)));

    // Live link budget update on any param change
    ["emFreqMHz","emPowerW","emAntennaGainDbi","emCableLossDb","emSystemLossDb","emRxSensDbm"].forEach((id) => {
      this.fields[id]?.addEventListener("input", () => this.updateLinkBudget());
    });

    // Derived dBm display
    this.fields.emPowerW?.addEventListener("input", () => this.updateDerivedFields());

    // Auto-update marker color when force affiliation changes
    this.fields.emForce?.addEventListener("change", () => {
      if (this.fields.emColor) {
        this.fields.emColor.value = FORCE_COLORS[this.fields.emForce.value] ?? FORCE_COLORS.friendly;
      }
    });

    // Close buttons
    document.querySelector("#emitterModalCloseBtn")?.addEventListener("click", () => this.close());
    document.querySelector("#emitterCancelBtn")?.addEventListener("click", () => this.close());
    this.backdrop.addEventListener("click", (e) => { if (e.target === this.backdrop) this.close(); });

    // Place on map
    document.querySelector("#emitterPlaceBtn")?.addEventListener("click", () => this.placeOnMap());

    // Save custom profile
    document.querySelector("#emitterSaveCustomBtn")?.addEventListener("click", () => this.saveCustomProfile());

    // Open via add-emitter button in map contents header
    document.querySelector("#addEmitterBtn")?.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      if (dom.mapEmitterAddMenu?.classList.contains("hidden")) openMapEmitterAddMenu(event.currentTarget);
      else closeMapEmitterAddMenu();
    });
    this.renderSavedProfileLibrary();
  },

  async open(prefill = null) {
    await ensureEmitterLibraryLoaded();
    this.backdrop.classList.remove("hidden");
    updateModalBodyState();
    setAssetPlacementMode(false);
    this.switchTab("rf");
    this.originalAssetProfileLink = null;
    this.originalAssetPayload = null;
    this.currentSavedProfileLink = null;
    const isEditing = prefill && prefill.lat !== undefined;
    // Track which asset is being edited for TO linking
    _currentEmitterEditId = isEditing ? (prefill?.id ?? null) : null;
    clearPendingToLink();
    // Show existing TO link badge if editing
    const existingToId = isEditing ? prefill?.toUnitId : null;
    const existingToUnit = existingToId ? _toState.units.find(u => u.id === existingToId) : null;
    updateEmitterToLinkBadge(existingToUnit ?? null);
    this.populateColocateOptions(prefill?.id ?? null);
    if (isEditing) {
      this.resetToDefaults();
      this.applyAsset(prefill);
      this.originalAssetPayload = buildEmitterProfilePayloadFromAsset(prefill);
      if (prefill?.profileId) {
        this.originalAssetProfileLink = {
          id: prefill.profileId,
          name: prefill.profileName || "",
          version: Number(prefill.profileVersion) || 1,
        };
        this.currentSavedProfileLink = { ...this.originalAssetProfileLink };
        state.emitterProfiles.activeProfileId = prefill.profileId;
      }
    } else if (prefill) {
      this.applyPayload(normalizeEmitterProfilePayload(prefill));
    } else {
      this.resetToDefaults();
    }
    this.renderSavedProfileLibrary();
    this.syncSavedProfileSelectionUi();
    const placeBtn = document.querySelector("#emitterPlaceBtn");
    if (placeBtn) {
      if (isEditing) {
        placeBtn.textContent = "Save Changes";
      } else if (isEmitterWorkspaceViewActive()) {
        placeBtn.textContent = "Add to Workspace";
      } else {
        placeBtn.textContent = "Place on Map";
      }
    }
    this.updateDerivedFields();
    this.updateLinkBudget();
    this.fields.emName?.focus();
  },

  populateColocateOptions(excludeAssetId = null) {
    const select = this.fields.emColocateAsset;
    if (!select) {
      return;
    }
    const options = ['<option value="">Do not co-locate</option>'];
    state.assets
      .filter((asset) => asset.id !== excludeAssetId)
      .forEach((asset) => {
        const label = `${asset.name}${asset.unit ? ` | ${asset.unit}` : ""} | ${toMgrs(asset.lat, asset.lon)}`;
        options.push(`<option value="${escapeHtml(asset.id)}">${escapeHtml(label)}</option>`);
      });
    if (options.length === 1) {
      options.push('<option value="" disabled>No existing emitters on map</option>');
    }
    select.innerHTML = options.join("");
    select.value = "";
  },

  close() {
    this.backdrop.classList.add("hidden");
    updateModalBodyState();
    document.querySelector("#emitterValidation").textContent = "";
    const placeBtn = document.querySelector("#emitterPlaceBtn");
    if (placeBtn) placeBtn.textContent = "Place on Map";
    state.editingAssetId = null;

    _currentEmitterEditId = null;
    this.currentSavedProfileLink = null;
    this.originalAssetProfileLink = null;
    this.originalAssetPayload = null;
    _emittersWorkspaceState.pendingSpawnLayout = null;
    clearPendingToLink();
    updateEmitterToLinkBadge(null);
    // If opened from tactical editor link mode and user cancelled, reopen the tactical editor
    if (_emitterLinkCallback) {
      _emitterLinkCallback = null;
      dom.tacticalEditorModal?.classList.remove("hidden");
      updateModalBodyState();
    }
  },

  onFormChanged() {
    this.validateInputs();
    this.updateSavedProfileStatus();
  },

  updateEmitterTypeSpecificFields(profile = null) {
    const emitterType = profile?.emitterType || this.emitterTypeSelect?.value || "";
    const isRadar = isRadarEmitterType(emitterType);
    const toggle = (key, show) => this.typeSpecificFields[key]?.classList.toggle("hidden", !show);
    toggle("waveform", !isRadar);
    toggle("duplex", !isRadar);
    toggle("channelSpacing", !isRadar);
    toggle("radarMode", isRadar);
    toggle("pulseWidthUs", isRadar);
    toggle("prfHz", isRadar);
    toggle("scanType", isRadar);
  },

  renderSavedProfileLibrary() {
    if (!this.savedProfileSelect) {
      return;
    }
    const query = state.emitterProfiles.searchText || "";
    const filtered = state.emitterProfiles.items.filter((profile) => {
      if (!query) {
        return true;
      }
      const haystack = [
        profile.name,
        profile.emitterLabel,
        profile.waveform,
        formatEmitterProfileListMeta(profile),
      ].join(" ").toLowerCase();
      return haystack.includes(query);
    });
    this.savedProfileSelect.innerHTML = filtered.length
      ? filtered.map((profile) => `<option value="${escapeHtml(profile.id)}">${escapeHtml(profile.name)} â€” ${escapeHtml(formatEmitterProfileListMeta(profile))}</option>`).join("")
      : '<option value="">No saved profiles</option>';
    const selectedId = state.emitterProfiles.activeProfileId || this.currentSavedProfileLink?.id || "";
    this.savedProfileSelect.value = filtered.some((profile) => profile.id === selectedId) ? selectedId : "";
    this.savedProfileSelect.toggleAttribute("disabled", !filtered.length);
    this.syncSavedProfileSelectionUi();
  },

  syncSavedProfileSelectionUi() {
    const selectedProfile = findEmitterProfileById(this.savedProfileSelect?.value || state.emitterProfiles.activeProfileId || "");
    if (selectedProfile) {
      state.emitterProfiles.activeProfileId = selectedProfile.id;
      if (this.profileNameInput && (!this.profileNameInput.value.trim() || document.activeElement !== this.profileNameInput)) {
        this.profileNameInput.value = selectedProfile.name;
      }
    }
    this.applySavedProfileBtn?.toggleAttribute("disabled", !selectedProfile);
    this.deleteSavedProfileBtn?.toggleAttribute("disabled", !selectedProfile);
    this.updateSavedProfileStatus();
  },

  createNewDraft() {
    state.emitterProfiles.activeProfileId = "";
    this.currentSavedProfileLink = null;
    this.savedProfileSelect && (this.savedProfileSelect.value = "");
    if (this.profileNameInput) {
      this.profileNameInput.value = "";
    }
    this.updateSavedProfileStatus();
  },

  applySelectedSavedProfile() {
    const profile = findEmitterProfileById(this.savedProfileSelect?.value || state.emitterProfiles.activeProfileId || "");
    if (!profile) {
      setStatus("Select a saved emitter profile first.", true);
      return;
    }
    this.applyPayload(profile.profile);
    this.currentSavedProfileLink = {
      id: profile.id,
      name: profile.name,
      version: profile.version,
    };
    state.emitterProfiles.activeProfileId = profile.id;
    if (this.profileNameInput) {
      this.profileNameInput.value = profile.name;
    }
    this.updateSavedProfileStatus();
    setStatus(`Applied saved profile "${profile.name}".`);
  },

  resolveProfileRefForPayload(payload) {
    if (this.currentSavedProfileLink?.id) {
      const linked = findEmitterProfileById(this.currentSavedProfileLink.id);
      if (linked && payloadsEqual(payload, linked.profile)) {
        return { id: linked.id, name: linked.name, version: linked.version };
      }
    }
    if (this.originalAssetProfileLink?.id && this.originalAssetPayload && payloadsEqual(payload, this.originalAssetPayload)) {
      return { ...this.originalAssetProfileLink };
    }
    return null;
  },

  updateSavedProfileStatus() {
    return;
  },

  async saveCurrentProfileToLibrary({ saveAsCopy = false } = {}) {
    const payload = this.readFields();
    const requestedName = this.profileNameInput?.value?.trim() || payload.name.trim() || "Custom Profile";
    let savedProfile = null;
    const existingProfile = !saveAsCopy
      ? findEmitterProfileById(this.savedProfileSelect?.value || state.emitterProfiles.activeProfileId || "")
      : null;

    if (state.session.token) {
      if (existingProfile) {
        const response = await apiFetch(`/user/emitter-profiles/${existingProfile.id}`, {
          method: "PUT",
          body: JSON.stringify({ name: requestedName, profile: payload }),
        });
        savedProfile = normalizeEmitterProfileRecord(response.profile);
        state.emitterProfiles.items = state.emitterProfiles.items.map((profile) => profile.id === savedProfile.id ? savedProfile : profile);
      } else {
        const response = await apiFetch("/user/emitter-profiles", {
          method: "POST",
          body: JSON.stringify({ name: requestedName, profile: payload }),
        });
        savedProfile = normalizeEmitterProfileRecord(response.profile);
        state.emitterProfiles.items.push(savedProfile);
      }
    } else {
      const nextTimestamp = nowIso();
      if (existingProfile) {
        savedProfile = normalizeEmitterProfileRecord({
          ...existingProfile,
          name: requestedName,
          version: (existingProfile.version || 1) + 1,
          updatedAt: nextTimestamp,
          profile: payload,
        });
        state.emitterProfiles.items = state.emitterProfiles.items.map((profile) => profile.id === savedProfile.id ? savedProfile : profile);
      } else {
        savedProfile = normalizeEmitterProfileRecord({
          id: generateId(),
          name: requestedName,
          version: 1,
          updatedAt: nextTimestamp,
          createdAt: nextTimestamp,
          profile: payload,
        });
        state.emitterProfiles.items.push(savedProfile);
      }
      persistGuestEmitterProfiles();
    }

    state.emitterProfiles.activeProfileId = savedProfile.id;
    this.currentSavedProfileLink = {
      id: savedProfile.id,
      name: savedProfile.name,
      version: savedProfile.version,
    };
    if (this.profileNameInput) {
      this.profileNameInput.value = savedProfile.name;
    }
    this.renderSavedProfileLibrary();
    setStatus(`Saved emitter profile "${savedProfile.name}"${saveAsCopy ? " as a copy" : ""}.`);
  },

  async deleteSelectedSavedProfile() {
    const profile = findEmitterProfileById(this.savedProfileSelect?.value || state.emitterProfiles.activeProfileId || "");
    if (!profile) {
      setStatus("Select a saved emitter profile to delete.", true);
      return;
    }
    if (!window.confirm(`Delete saved emitter profile "${profile.name}"?`)) {
      return;
    }
    if (state.session.token) {
      await apiFetch(`/user/emitter-profiles/${profile.id}`, { method: "DELETE" });
    } else {
      state.emitterProfiles.items = state.emitterProfiles.items.filter((entry) => entry.id !== profile.id);
      persistGuestEmitterProfiles();
    }
    if (state.session.token) {
      state.emitterProfiles.items = state.emitterProfiles.items.filter((entry) => entry.id !== profile.id);
    }
    state.emitterProfiles.activeProfileId = "";
    if (this.savedProfileSelect) {
      this.savedProfileSelect.value = "";
    }
    if (this.profileNameInput && this.profileNameInput.value.trim() === profile.name) {
      this.profileNameInput.value = "";
    }
    this.renderSavedProfileLibrary();
    setStatus(`Deleted saved emitter profile "${profile.name}".`);
  },

  switchTab(name) {
    this.tabs.forEach((t) => t.classList.toggle("active", t.dataset.tab === name));
    this.panels.forEach((p) => p.classList.toggle("active", p.dataset.panel === name));
    if (name === "link") this.updateLinkBudget();
  },

  onEmitterTypeChange() {
    const key = this.emitterTypeSelect.value;
    const emitter = EMITTER_LIBRARY[key];
    const sel = this.programSelect;
    if (sel) {
      sel.innerHTML = "";
    }
    if (!emitter) {
      if (sel) {
        sel.disabled = true;
        sel.innerHTML = '<option value="">- Manual -</option>';
      }
      this.libSummary.innerHTML = "<p>Configure all parameters manually.</p>";
      this.updateEmitterTypeSpecificFields({ emitterType: "" });
      this.onFormChanged();
      return;
    }
    const defaultProgramKey = getDefaultEmitterProgramKey(key);
    if (sel) {
      sel.disabled = false;
      Object.entries(emitter.programs).forEach(([pKey, prog]) => {
        const opt = document.createElement("option");
        opt.value = pKey;
        opt.textContent = prog.label;
        sel.appendChild(opt);
      });
      sel.value = defaultProgramKey;
    }
    this.onProgramChange(defaultProgramKey);
  },

  onProgramChange(forcedProgramKey = "") {
    const emitterType = this.emitterTypeSelect.value;
    const progKey  = forcedProgramKey || this.programSelect?.value || getDefaultEmitterProgramKey(emitterType);
    const emitter  = EMITTER_LIBRARY[emitterType];
    const prog     = emitter?.programs[progKey];
    if (!prog) return;
    this.applyPayload(buildEmitterProfilePayloadFromProgram(emitterType, progKey));
    this.currentSavedProfileLink = null;
    this.libSummary.innerHTML = `
      <strong>${emitter.label}</strong><br>
      <em>${prog.label}</em><br>
      <span>${prog.rf.frequencyMHz} MHz · ${prog.tx.powerW} W · ${prog.antenna.gainDbi} dBi · ${prog.rf.waveform}</span>
    `;
    this.updateSavedProfileStatus();
  },
  applyPayload(payload) {
    const profile = normalizeEmitterProfilePayload(payload);
    const f = this.fields;
    const set = (id, val) => { if (f[id] && val !== undefined && val !== null) f[id].value = val; };
    const setCheck = (id, val) => { if (f[id]) f[id].checked = Boolean(val); };
    if (this.emitterTypeSelect) this.emitterTypeSelect.value = profile.emitterType || "";
    if (this.programSelect) {
      this.programSelect.disabled = !profile.emitterType || !EMITTER_LIBRARY[profile.emitterType];
      if (profile.emitterType && EMITTER_LIBRARY[profile.emitterType]) {
        this.programSelect.innerHTML = "";
        Object.entries(EMITTER_LIBRARY[profile.emitterType].programs).forEach(([pKey, prog]) => {
          const opt = document.createElement("option");
          opt.value = pKey;
          opt.textContent = prog.label;
          this.programSelect.appendChild(opt);
        });
        this.programSelect.value = profile.programKey || this.programSelect.value || getDefaultEmitterProgramKey(profile.emitterType);
      } else {
        this.programSelect.innerHTML = '<option value="">â€” Manual â€”</option>';
      }
    }
    if (profile.emitterType && EMITTER_LIBRARY[profile.emitterType]) {
      const emitter = EMITTER_LIBRARY[profile.emitterType];
      const summaryProgramKey = profile.programKey || getDefaultEmitterProgramKey(profile.emitterType);
      const program = emitter.programs?.[summaryProgramKey];
      this.libSummary.innerHTML = program
        ? `<strong>${emitter.label}</strong><br><em>${program.label}</em><br><span>${program.rf.frequencyMHz} MHz Â· ${program.tx.powerW} W Â· ${program.antenna.gainDbi} dBi Â· ${program.rf.waveform}</span>`
        : `<strong>${emitter.label}</strong><br><span>Saved custom configuration based on this emitter family.</span>`;
    } else {
      this.libSummary.innerHTML = "<p>Configure all parameters manually.</p>";
    }
    set("emName",             profile.name);
    set("emUnit",             profile.unit);
    set("emForce",            profile.force);
    set("emIcon",             profile.icon);
    set("emColor",            profile.color);
    set("emNotes",            profile.notes);

    // RF
    set("emFreqMHz",          profile.rf.frequencyMHz);
    set("emBandwidthKHz",     profile.rf.bandwidthKHz);
    set("emModulation",       profile.rf.modulation);
    set("emWaveform",         profile.rf.waveform);
    set("emDuplex",           profile.rf.duplex);
    set("emChannelSpacingKHz",profile.rf.channelSpacingKHz);
    set("emRadarMode",        profile.radar.mode || profile.rf.waveform);
    set("emPulseWidthUs",     profile.radar.pulseWidthUs);
    set("emPrfHz",            profile.radar.prfHz);
    set("emScanType",         profile.radar.scanType);
    // TX
    set("emPowerW",           profile.tx.powerW);
    set("emDutyCycle",        profile.tx.dutyCycle);
    set("emPapr",             profile.tx.papr);
    set("emSpectralEff",      profile.tx.spectralEfficiency);
    // RX
    set("emRxSensDbm",        profile.rx.sensitivityDbm);
    set("emNoiseFigDb",       profile.rx.noiseFigDb);
    set("emReqSnrDb",         profile.rx.requiredSnrDb);
    set("emAcrDb",            profile.rx.acrDb);
    set("emBdrDb",            profile.rx.bdrDb);
    // Antenna
    set("emAntennaType",      profile.antenna.type);
    set("emAntennaGainDbi",   profile.antenna.gainDbi);
    set("emRadPattern",       profile.antenna.pattern);
    set("emPolarization",     profile.antenna.polarization);
    set("emAntennaHeightM",   profile.antenna.heightM);
    set("emCableLossDb",      profile.antenna.cableLossDb);
    set("emSystemLossDb",     profile.antenna.systemLossDb);
    // Propagation
    set("emPropModel",        profile.prop.model);
    set("emClutterType",      profile.prop.clutter);
    setCheck("emTerrainEnabled",    profile.prop.terrainEnabled);
    setCheck("emDiffractionEnabled",profile.prop.diffractionEnabled);
    setCheck("emNvisEnabled",       profile.prop.nvisEnabled);
    set("emIonoModel",        profile.prop.ionoModel);
    setCheck("emTimeDayEffects",    profile.prop.timeDayEffects);
    set("emSolarIndex",       profile.prop.solarIndex);
    // Network
    setCheck("emIsManet",           profile.network.isManet);
    setCheck("emRelayCapable",      profile.network.relayCapable);
    set("emMaxHops",          profile.network.maxHops);
    set("emLatencyMs",        profile.network.latencyMs);
    setCheck("emAdaptiveDataRate",  profile.network.adaptiveDataRate);
    setCheck("emSatcomEnabled",     profile.network.satcomEnabled);
    set("emSatType",          profile.network.satType);
    set("emSatUplinkMHz",     profile.network.satUplinkMHz);
    set("emSatDownlinkMHz",   profile.network.satDownlinkMHz);
    set("emSatGainDbi",       profile.network.satGainDbi);
    set("emGridLocation",     profile.locationDefaults.gridLocation);
    set("emColocateAsset",    profile.locationDefaults.colocateAssetId);

    this.updateEmitterTypeSpecificFields(profile);
    this.updateDerivedFields();
    this.updateLinkBudget();
    this.validateInputs();
  },

  applyAsset(asset) {
    const payload = buildEmitterProfilePayloadFromAsset(asset);
    if (!payload.locationDefaults.gridLocation && Number.isFinite(asset?.lat) && Number.isFinite(asset?.lon)) {
      payload.locationDefaults.gridLocation = toMgrs(asset.lat, asset.lon);
    }
    this.applyPayload(payload);
  },
  resetToDefaults() {
    this.libSummary.innerHTML = "<p>Select an emitter type and program to auto-fill parameters, or configure manually below.</p>";
    if (this.programSelect) {
      this.programSelect.disabled = true;
      this.programSelect.innerHTML = '<option value="">Select an emitter type first</option>';
    }
    if (this.profileNameInput) {
      this.profileNameInput.value = "";
    }
    this.applyPayload(createDefaultEmitterProfilePayload());
  },

  updateDerivedFields() {
    const pw = parseFloat(this.fields.emPowerW?.value);
    if (Number.isFinite(pw) && pw > 0) {
      const dbm = (10 * Math.log10(pw * 1000)).toFixed(1);
      if (this.fields.emPowerDbm) this.fields.emPowerDbm.value = `${dbm} dBm`;
    }
    this.updateLinkBudget();
  },

  updateLinkBudget() {
    const el = this.linkBudgetEls;
    const freqMHz  = parseFloat(this.fields.emFreqMHz?.value);
    const powerW   = parseFloat(this.fields.emPowerW?.value);
    const gainDbi  = parseFloat(this.fields.emAntennaGainDbi?.value);
    const cableLoss= parseFloat(this.fields.emCableLossDb?.value) || 0;
    const sysLoss  = parseFloat(this.fields.emSystemLossDb?.value) || 0;
    const rxSens   = parseFloat(this.fields.emRxSensDbm?.value);
    if (!Number.isFinite(freqMHz) || !Number.isFinite(powerW) || !Number.isFinite(gainDbi) || !Number.isFinite(rxSens)) return;
    const txDbm = 10 * Math.log10(powerW * 1000);
    const totalLoss = cableLoss + (sysLoss - cableLoss);
    const eirp = txDbm + gainDbi - totalLoss;
    const fspl = 20 * Math.log10(10000) + 20 * Math.log10(freqMHz * 1e6) - 147.55;
    const rxPwr = eirp - fspl + gainDbi;
    const margin = rxPwr - rxSens;
    const maxRangeM = Math.pow(10, (eirp + gainDbi - rxSens + 147.55 - 20 * Math.log10(freqMHz * 1e6)) / 20);
    const fmt = (v, unit) => `${v.toFixed(1)} ${unit}`;
    const fmtRange = (m) => m > 1000 ? `${(m / 1000).toFixed(1)} km` : `${Math.round(m)} m`;
    if (el.lb_txPower)   el.lb_txPower.textContent   = fmt(txDbm, "dBm");
    if (el.lb_antennaGain) el.lb_antennaGain.textContent = fmt(gainDbi, "dBi");
    if (el.lb_cableLoss) el.lb_cableLoss.textContent = fmt(totalLoss, "dB");
    if (el.lb_eirp)      el.lb_eirp.textContent      = fmt(eirp, "dBm");
    if (el.lb_fspl10)    el.lb_fspl10.textContent     = fmt(fspl, "dB");
    if (el.lb_rxPower10) el.lb_rxPower10.textContent  = fmt(rxPwr, "dBm");
    if (el.lb_rxSens)    el.lb_rxSens.textContent     = fmt(rxSens, "dBm");
    if (el.lb_margin10) {
      el.lb_margin10.textContent = fmt(margin, "dB");
      el.lb_margin10.style.color = margin >= 0 ? "var(--accent)" : "var(--enemy)";
    }
    if (el.lb_maxRange)  el.lb_maxRange.textContent   = fmtRange(maxRangeM);
    if (this.fields.emEirpDbm) this.fields.emEirpDbm.value = fmt(eirp, "dBm");
  },

  validateInputs() {
    const warnings = [];
    const f = this.fields;
    const freq  = parseFloat(f.emFreqMHz?.value);
    const power = parseFloat(f.emPowerW?.value);
    const gain  = parseFloat(f.emAntennaGainDbi?.value);
    const height= parseFloat(f.emAntennaHeightM?.value);
    const sens  = parseFloat(f.emRxSensDbm?.value);
    if (Number.isFinite(power)) {
      if (power > 100) warnings.push("Power >100 W is unusual for man-portable systems.");
      if (power < 0.01) warnings.push("Power <10 mW â€” signal will be extremely weak.");
    }
    if (Number.isFinite(gain) && gain > 15) warnings.push("Antenna gain >15 dBi is physically implausible for a portable whip/blade.");
    if (Number.isFinite(height)) {
      if (height < 0.5) warnings.push("Antenna height <0.5 m â€” may be body-shadowed.");
      if (height > 30 && f.emAntennaType?.value !== "tower") warnings.push("Antenna height >30 m â€” requires a tower or mast.");
    }
    if (Number.isFinite(sens) && sens > -80) warnings.push("Receiver sensitivity >âˆ’80 dBm is poor â€” check your value.");
    const gridInput = f.emGridLocation?.value?.trim();
    if (gridInput) {
      try {
        parseMgrsReferenceInput(gridInput);
      } catch (error) {
        warnings.push(error.message);
      }
    }
    const el = document.querySelector("#emitterValidation");
    if (el) el.textContent = warnings.join(" Â· ");
  },

  resolveLocation() {
    const gridInput = this.fields.emGridLocation?.value?.trim();
    if (gridInput) {
      const parsed = parseMgrsReferenceInput(gridInput);
      return {
        lat: parsed.lat,
        lng: parsed.lng,
        description: parsed.normalized,
      };
    }

    const colocateAssetId = this.fields.emColocateAsset?.value;
    if (colocateAssetId) {
      const asset = state.assets.find((entry) => entry.id === colocateAssetId);
      if (!asset) {
        throw new Error("The selected co-located emitter could not be found.");
      }
      return {
        lat: asset.lat,
        lng: asset.lon,
        description: `co-located with ${asset.name}`,
      };
    }

    return null;
  },

  readFields() {
    const f = this.fields;
    const v = (id) => f[id]?.value;
    const n = (id) => parseFloat(f[id]?.value);
    const numOr = (id, fallback) => {
      const parsed = n(id);
      return Number.isFinite(parsed) ? parsed : fallback;
    };
    const b = (id) => f[id]?.checked ?? false;
    const iconVal = v("emIcon") || "radio";
    const emitterType = this.emitterTypeSelect?.value || "";
    const programKey = this.programSelect?.value || getDefaultEmitterProgramKey(emitterType);
    const isRadar = isRadarEmitterType(emitterType);
    const radarMode = isRadar ? String(v("emRadarMode") || v("emWaveform") || "").trim() : "";
    return normalizeEmitterProfilePayload({
      emitterType,
      programKey,
      type: EMITTER_ICONS[iconVal] ? iconVal : "radio",
      emitterLabel: emitterType
        ? (EMITTER_LIBRARY[emitterType]?.label ?? "emitter")
        : ((v("emName") || "").trim() || "emitter"),
      force: v("emForce") || "friendly",
      name: v("emName") || "Emitter",
      unit: v("emUnit") || "",
      icon: iconVal,
      color: v("emColor") || FORCE_COLORS["friendly"],
      notes: v("emNotes") || "",
      rf: {
        frequencyMHz: numOr("emFreqMHz", 150),
        bandwidthKHz: n("emBandwidthKHz"),
        modulation: v("emModulation"),
        waveform: isRadar ? radarMode : v("emWaveform"),
        duplex: v("emDuplex"),
        channelSpacingKHz: n("emChannelSpacingKHz"),
      },
      radar: {
        mode: radarMode,
        pulseWidthUs: isRadar ? n("emPulseWidthUs") : null,
        prfHz: isRadar ? n("emPrfHz") : null,
        scanType: isRadar ? (v("emScanType") || "") : "",
      },
      tx: {
        powerW: numOr("emPowerW", 5),
        dutyCycle: n("emDutyCycle"),
        papr: n("emPapr"),
        spectralEfficiency: n("emSpectralEff"),
      },
      rx: {
        sensitivityDbm: numOr("emRxSensDbm", -107),
        noiseFigDb: n("emNoiseFigDb"),
        requiredSnrDb: n("emReqSnrDb"),
        acrDb: n("emAcrDb"),
        bdrDb: n("emBdrDb"),
      },
      antenna: {
        type: v("emAntennaType"),
        gainDbi: numOr("emAntennaGainDbi", 2.15),
        pattern: v("emRadPattern"),
        polarization: v("emPolarization"),
        heightM: numOr("emAntennaHeightM", 2),
        cableLossDb: n("emCableLossDb"),
        systemLossDb: numOr("emSystemLossDb", 3),
      },
      prop: {
        model: v("emPropModel"),
        clutter: v("emClutterType"),
        terrainEnabled: b("emTerrainEnabled"),
        diffractionEnabled: b("emDiffractionEnabled"),
        nvisEnabled: b("emNvisEnabled"),
        ionoModel: v("emIonoModel"),
        timeDayEffects: b("emTimeDayEffects"),
        solarIndex: n("emSolarIndex"),
      },
      network: {
        isManet: b("emIsManet"),
        relayCapable: b("emRelayCapable"),
        maxHops: n("emMaxHops"),
        latencyMs: n("emLatencyMs"),
        adaptiveDataRate: b("emAdaptiveDataRate"),
        satcomEnabled: b("emSatcomEnabled"),
        satType: v("emSatType"),
        satUplinkMHz: n("emSatUplinkMHz"),
        satDownlinkMHz: n("emSatDownlinkMHz"),
        satGainDbi: n("emSatGainDbi"),
      },
      locationDefaults: {
        gridLocation: v("emGridLocation") || "",
        colocateAssetId: v("emColocateAsset") || "",
      },
    });
  },

  placeOnMap() {
    this.validateInputs();
    const payload = this.readFields();
    if (!payload.name.trim()) {
      document.querySelector("#emitterValidation").textContent = "Enter an emitter name before placing.";
      this.fields.emName?.focus();
      return;
    }
    const profileRef = this.resolveProfileRefForPayload(payload);
    const data = buildEmitterAssetFromProfilePayload(payload, { profileRef });
    const isEmittersWorkspaceView = isEmitterWorkspaceViewActive();

    let resolvedLocation = null;
    try {
      resolvedLocation = this.resolveLocation();
    } catch (error) {
      document.querySelector("#emitterValidation").textContent = error.message;
      this.switchTab("loc");
      this.fields.emGridLocation?.focus();
      return;
    }

    // If editing an existing asset, save edits directly
    if (state.editingAssetId) {
      const asset = state.assets.find((a) => a.id === state.editingAssetId);
      if (asset) {
        Object.assign(asset, data);
        // Commit TO link if pending
        if (window._pendingToUnitId !== undefined) {
          if (window._pendingToUnitId === null) delete asset.toUnitId;
          else asset.toUnitId = window._pendingToUnitId;
          clearPendingToLink();
        }
        const keepWorkspaceOnly = isEmittersWorkspaceView && !state.assetMarkers.has(asset.id);
        if (resolvedLocation && !keepWorkspaceOnly) {
          asset.lat = resolvedLocation.lat;
          asset.lon = resolvedLocation.lng;
          const marker = state.assetMarkers.get(asset.id);
          if (marker) {
            marker.setLatLng([asset.lat, asset.lon]);
          }
        } else if (keepWorkspaceOnly) {
          asset.lat = null;
          asset.lon = null;
          asset.groundElevationM = null;
          asset.workspaceVisible = true;
        }
        asset.groundElevationM = hasAssetMapLocation(asset)
          ? sampleTerrainElevation(asset.lat, asset.lon)
          : null;
        asset.version = (asset.version ?? 1) + 1;
        asset.lastModified = nowIso();
        updateAssetMarker(asset);
        renderAssets();
        renderMapContents();
        syncCesiumEntities();
        saveMapState();
        setStatus(resolvedLocation ? `Updated ${asset.name} at ${resolvedLocation.description}.` : `Updated ${asset.name}.`);
      }
      state.editingAssetId = null;
      refreshActionButtons();
      this.close();
      if (_emitterLinkCallback) {
        const cb = _emitterLinkCallback;
        _emitterLinkCallback = null;
        cb(asset.id);
      }
      return;
    }

    if (isEmittersWorkspaceView) {
      addAssetToWorkspace(data);
      this.close();
      setStatus("Emitter added to the workspace.");
      return;
    }

    if (resolvedLocation) {
      state.pendingEmitterData = data;
      setAssetPlacementMode(false);
      addAsset(resolvedLocation);
      this.close();
      setStatus(`Emitter placed at ${resolvedLocation.description}.`);
      return;
    }

    // New placement
    state.pendingEmitterData = data;
    this.close();
    setAssetPlacementMode(true);
    setStatus(state.view3dEnabled ? "Click in the 3D scene to place the emitter." : "Click on the map to place the emitter.");
  },

  saveCustomProfile() {
    if (this.profileNameInput && !this.profileNameInput.value.trim()) {
      this.profileNameInput.value = this.fields.emName?.value?.trim() || "Custom Profile";
    }
    this.saveCurrentProfileToLibrary().catch((error) => setStatus(error.message, true));
  },
};

