function loadSettings() {
  Object.assign(state.settings, cloneJsonValue(DEFAULT_SETTINGS_STATE));
  if (!canUsePersistentBrowserStorage()) {
    return;
  }
  const stored = window.localStorage.getItem(getSettingsStorageKey());
  if (!stored) {
    return;
  }

  try {
    const parsed = JSON.parse(stored);
    state.settings.measurementUnits = ["metric", "standard"].includes(parsed.measurementUnits)
      ? parsed.measurementUnits
      : state.settings.measurementUnits;
    state.settings.theme = ["dark", "light"].includes(parsed.theme)
      ? parsed.theme
      : state.settings.theme;
    state.settings.fontFamily = FONT_FAMILY_OPTIONS[parsed.fontFamily]
      ? parsed.fontFamily
      : state.settings.fontFamily;
    state.settings.coordinateSystem = ["mgrs", "latlon", "dms"].includes(parsed.coordinateSystem)
      ? parsed.coordinateSystem
      : state.settings.coordinateSystem;
    state.settings.gridLinesEnabled = Boolean(parsed.gridLinesEnabled);
    state.settings.centerGridEnabled = Boolean(parsed.centerGridEnabled);
    state.settings.gridColor = typeof parsed.gridColor === "string" ? parsed.gridColor : state.settings.gridColor;
    state.settings.cesiumPhotorealisticTilesEnabled = Boolean(parsed.cesiumPhotorealisticTilesEnabled);
    state.settings.cesiumOsmBuildingsEnabled = Boolean(parsed.cesiumOsmBuildingsEnabled);
    state.settings.buildingMaterialPreset = BUILDING_MATERIAL_MODELS[parsed.buildingMaterialPreset]
      ? parsed.buildingMaterialPreset
      : state.settings.buildingMaterialPreset;
    state.settings.buildingPropagationMode = BUILDING_PROPAGATION_MODES[parsed.buildingPropagationMode]
      ? parsed.buildingPropagationMode
      : state.settings.buildingPropagationMode;
    if (typeof parsed.labelDefaultPoint === "boolean") state.settings.labelDefaultPoint = parsed.labelDefaultPoint;
    if (typeof parsed.labelDefaultPolygon === "boolean") state.settings.labelDefaultPolygon = parsed.labelDefaultPolygon;
    if (typeof parsed.labelDefaultLine === "boolean") state.settings.labelDefaultLine = parsed.labelDefaultLine;
    if (typeof parsed.defaultTakStreamEnabled === "boolean") state.settings.defaultTakStreamEnabled = parsed.defaultTakStreamEnabled;
    if (typeof parsed.takTriggeredPromptingEnabled === "boolean") state.settings.takTriggeredPromptingEnabled = parsed.takTriggeredPromptingEnabled;
    if (Array.isArray(parsed.takTriggerPrefixes) && parsed.takTriggerPrefixes.every((p) => typeof p === "string")) {
      state.settings.takTriggerPrefixes = parsed.takTriggerPrefixes.length ? parsed.takTriggerPrefixes : ["/ai"];
    }
    if (typeof parsed.takTriggeredSystemPrompt === "string") state.settings.takTriggeredSystemPrompt = parsed.takTriggeredSystemPrompt;
    if (typeof parsed.takTriggeredIncludeMapContext === "boolean") state.settings.takTriggeredIncludeMapContext = parsed.takTriggeredIncludeMapContext;
    if (typeof parsed.takTriggeredNotify === "boolean") state.settings.takTriggeredNotify = parsed.takTriggeredNotify;
    if (typeof parsed.takTriggeredLog === "boolean") state.settings.takTriggeredLog = parsed.takTriggeredLog;
    if (typeof parsed.autoFetchWeatherOnSim === "boolean") state.settings.autoFetchWeatherOnSim = parsed.autoFetchWeatherOnSim;
    if (typeof parsed.tacticalMarkerSize === "number" && parsed.tacticalMarkerSize >= 30 && parsed.tacticalMarkerSize <= 120) {
      state.settings.tacticalMarkerSize = parsed.tacticalMarkerSize;
    }
  } catch {
    window.localStorage.removeItem(getSettingsStorageKey());
  }
}

function persistSettings() {
  if (!canUsePersistentBrowserStorage()) {
    return;
  }
  window.localStorage.setItem(getSettingsStorageKey(), JSON.stringify(state.settings));
}

function serializeImportedItem(item) {
  let coordinates;
  if (item.geometryType === "Point") {
    const ll = item.layer.getLatLng();
    coordinates = [ll.lat, ll.lng];
  } else if (item.geometryType === "LineString") {
    coordinates = item.layer.getLatLngs().map((p) => [p.lat, p.lng]);
  } else {
    const rings = item.layer.getLatLngs();
    const outer = Array.isArray(rings[0]) ? rings[0] : rings;
    coordinates = outer.map((p) => [p.lat, p.lng]);
  }
  // Preserve rendering properties plus all KML/GeoJSON attributes for AI querying.
  // Cap each string value at 200 chars and total property count at 40 to bound storage.
  const { isCircle, radiusM, center, ...rest } = item.properties ?? {};
  const properties = {};
  if (isCircle) properties.isCircle = isCircle;
  if (radiusM !== undefined) properties.radiusM = radiusM;
  if (center && Number.isFinite(Number(center.lat)) && Number.isFinite(Number(center.lng))) {
    properties.center = { lat: Number(center.lat), lng: Number(center.lng) };
  }
  // Persist remaining KML ExtendedData/GeoJSON properties so the AI agent can
  // query attributes (call sign, type, description, etc.) after page reload.
  let extraCount = 0;
  for (const [k, v] of Object.entries(rest)) {
    if (extraCount >= 37) break; // keep total â‰¤ 40 entries
    if (v === undefined || v === null || v === "") continue;
    const str = String(v);
    properties[k] = str.length > 200 ? str.slice(0, 200) : str;
    extraCount++;
  }

  return {
    id: item.id,
    version: item.version ?? 1,
    lastModified: item.lastModified ?? nowIso(),
    name: item.name,
    subtitle: item.subtitle,
    kind: item.kind,
    geometryType: item.geometryType,
    folderPath: item.folderPath ?? [],
    sourceLabel: item.sourceLabel ?? null,
    properties,
    drawn: item.drawn ?? false,
    tak: normalizeTakMetadata(item.tak),
    shapeKind: typeof item.shapeKind === "string" && item.shapeKind
      ? item.shapeKind
      : inferImportedShapeKind(item.geometryType, properties, item.name),
    shapeStyle: item.shapeStyle ?? null,
    markerStyle: item.markerStyle ?? null,
    coordinates,
  };
}

function getDefaultMapView() {
  return { ...DEFAULT_MAP_VIEW };
}

function getCurrentMapView() {
  const center = state.map.getCenter();
  return {
    lat: center.lat,
    lng: center.lng,
    zoom: state.map.getZoom(),
  };
}

function getMapViewCacheScopeKey() {
  return state.session.activeProjectId || "__local__";
}

function readMapViewCache() {
  try {
    const raw = window.localStorage.getItem(getMapViewCacheStorageKey());
    const parsed = raw ? JSON.parse(raw) : {};
    return parsed && typeof parsed === "object" ? parsed : {};
  } catch {
    window.localStorage.removeItem(getMapViewCacheStorageKey());
    return {};
  }
}

function getCachedMapViewForCurrentScope() {
  const cached = readMapViewCache()[getMapViewCacheScopeKey()];
  if (!cached) {
    return null;
  }
  const lat = Number(cached.lat);
  const lng = Number(cached.lng);
  const zoom = Number(cached.zoom);
  if (!Number.isFinite(lat) || !Number.isFinite(lng) || !Number.isFinite(zoom)) {
    return null;
  }
  return { lat, lng, zoom };
}

function applyCachedMapViewForCurrentScope() {
  const cached = getCachedMapViewForCurrentScope();
  if (!cached) {
    return false;
  }
  state.map.setView([cached.lat, cached.lng], cached.zoom, { animate: false });
  return true;
}

function serializeCurrentMapState(options = {}) {
  const mapView = options.includeCurrentMapView ? getCurrentMapView() : getDefaultMapView();
  const serializedImported = state.importedItems
    .filter((item) => !isTakLiveImportedItem(item))
    .map(serializeImportedItem);
  const serializedTactical = state.tacticalObjects.map(serializeTacticalObject);
  const serializedOrder = state.mapContentOrder.filter((contentId) => !String(contentId || "").startsWith("taklive:"));
  const serializedAssignments = Array.from(state.mapContentAssignments.entries())
    .filter(([contentId]) => !String(contentId || "").startsWith("taklive:"));
  const serializedHiddenIds = [...state.hiddenContentIds]
    .filter((contentId) => !String(contentId || "").startsWith("taklive:"));
  const serializedHiddenLabelIds = [...state.hiddenLabelContentIds]
    .filter((contentId) => !String(contentId || "").startsWith("taklive:"));

  return {
    schemaVersion: STATE_SCHEMA_VERSION,
    savedAt: nowIso(),
    mapView,
    assets: state.assets,
    plan: serializeToPlanState(),
    weather: state.weather,
    settings: state.settings,
    importedItems: serializedImported,
    tacticalObjects: serializedTactical,
    mapContentFolders: state.mapContentFolders,
    mapContentOrder: serializedOrder,
    mapContentAssignments: serializedAssignments,
    hiddenContentIds: serializedHiddenIds,
    hiddenLabelContentIds: serializedHiddenLabelIds,
    activeTerrainId: state.activeTerrainId,
    activeProjectId: state.session.activeProjectId ?? null,
  };
}

// Leaner version of serializeCurrentMapState for server saves â€” omits settings
// and KMZ-imported geometry (stored localStorage-only) to keep payload
// small. Only user-drawn shapes (item.drawn === true) go to the server.
function serializeMapStateForServer() {
  const full = serializeCurrentMapState();
  const { settings, ...serverState } = full;
  serverState.importedItems = (serverState.importedItems ?? []).filter((item) =>
    (item.drawn || item.tak) && item?.tak?.source !== "tak-live-pli"
  );
  // Keep schemaVersion and savedAt so the server can record what version wrote the state.
  return serverState;
}

// Cheap browser-only map-view cache triggered on every pan/zoom. This is
// intentionally separate from project/autosave state so saved projects can
// reopen at the default view while browser refresh still restores the last
// local viewport for the current project scope.
function saveMapViewPosition() {
  try {
    const cache = readMapViewCache();
    cache[getMapViewCacheScopeKey()] = getCurrentMapView();
    window.localStorage.setItem(getMapViewCacheStorageKey(), JSON.stringify(cache));
  } catch {
    // quota or parse error â€” skip silently
  }
}

function persistMapStateNow() {
  const payload = serializeCurrentMapState();

  // KMZ (non-drawn) items go to IndexedDB â€” no size limit, async, non-blocking.
  // Drawn items and structural state go to localStorage (small enough to fit).
  const kmzItems = (payload.importedItems ?? []).filter((i) => !i.drawn && !i.tak);
  const drawnItems = (payload.importedItems ?? []).filter((i) => i.drawn || i.tak);
  const compactPayload = { ...payload, importedItems: drawnItems };
  if (!workspacePolicy.shouldPersistLocalMapState(state.session.activeProjectId)) {
    idbSaveKmzItems(state.session.activeProjectId, kmzItems).catch(() => {});
    queueActiveProjectAutosave();
    return;
  }

  // Fire-and-forget â€” KMZ write is async but we don't need to await it here.
  idbSaveKmzItems(state.session.activeProjectId, kmzItems).catch(() => {});

  try {
    window.localStorage.setItem(getMapStateStorageKey(), JSON.stringify(compactPayload));
  } catch {
    // Still over quota without KMZ â€” write minimal envelope so map position
    // and folder structure survive a refresh.
    try {
      const minimalPayload = {
        schemaVersion: compactPayload.schemaVersion,
        savedAt: compactPayload.savedAt,
        mapView: compactPayload.mapView,
        plan: compactPayload.plan,
        tacticalObjects: compactPayload.tacticalObjects,
        mapContentFolders: compactPayload.mapContentFolders,
        mapContentOrder: compactPayload.mapContentOrder,
        mapContentAssignments: compactPayload.mapContentAssignments,
        hiddenContentIds: compactPayload.hiddenContentIds,
        hiddenLabelContentIds: compactPayload.hiddenLabelContentIds,
        activeTerrainId: compactPayload.activeTerrainId,
        activeProjectId: compactPayload.activeProjectId,
        importedItems: [],
        assets: compactPayload.assets,
      };
      window.localStorage.setItem(getMapStateStorageKey(), JSON.stringify(minimalPayload));
    } catch { /* truly out of space */ }
  }

  queueActiveProjectAutosave();
}

function saveMapState() {
  if (state.session.localSaveTimerId) {
    window.clearTimeout(state.session.localSaveTimerId);
  }
  state.session.localSaveTimerId = window.setTimeout(() => {
    state.session.localSaveTimerId = null;
    persistMapStateNow();
  }, 120);
}

