function resolveMilstdCotTail(unit) {
  return getCotTypeTail(unit?.cotType || buildCatalogCotType(normalizeToUnitType(unit?.type), unit?.affiliation || "friendly"));
}

function resolveMilstdDomain(unit) {
  const tail = resolveMilstdCotTail(unit);
  const dimension = tail.split("-").filter(Boolean)[0] || "";
  if (dimension === "P") return "space";
  if (dimension === "S") return "sea_surface";
  if (dimension === "U") return "subsurface";
  if (dimension === "A") return "air";
  if (dimension === "G") return "ground";
  const type = normalizeToUnitType(unit?.type);
  if (type === "space") return "space";
  if (["naval_surface", "amphibious", "mine_warfare", "coast_guard"].includes(type)) return "sea_surface";
  if (type === "submarine") return "subsurface";
  if (type.includes("fixed") || type.includes("rotary")
    || ["fighter", "bomber", "attack_fixed", "transport_fixed", "isr_fixed", "tanker", "uav_fixed", "attack_helo", "utility_helo", "recon_helo", "medevac", "uav_rotary", "naval_aviation"].includes(type)) {
    return "air";
  }
  return "ground";
}

function resolveMilstdFrameClass(unit) {
  const tail = resolveMilstdCotTail(unit);
  if (tail.startsWith("G-E")) return "ground_equipment";
  return resolveMilstdDomain(unit);
}

function resolveMilstdFramePath(unit) {
  const affiliation = MILSTD_FRAME_PATHS[unit.affiliation] ? unit.affiliation : "unknown";
  const frameClass = resolveMilstdFrameClass(unit);
  if (frameClass === "ground_equipment") {
    return MILSTD_EQUIPMENT_FRAME_PATHS[affiliation] || MILSTD_EQUIPMENT_FRAME_PATHS.unknown;
  }
  return MILSTD_FRAME_PATHS[affiliation][frameClass] || MILSTD_FRAME_PATHS.unknown.ground;
}

function resolveMilstdMainPath(unit) {
  const type = normalizeToUnitType(unit?.type);
  const asset = MILSTD_MAIN_ASSETS[type];
  if (!asset) return null;
  if (asset.path) return asset.path;
  if (asset.fullFrame && asset.base) {
    const suffix = MILSTD_FULL_FRAME_SUFFIX[unit.affiliation] || MILSTD_FULL_FRAME_SUFFIX.unknown;
    return `${asset.base}_${suffix}.svg`;
  }
  return asset.base ? `${asset.base}.svg` : null;
}

function resolveMilstdModifierPaths(unit) {
  const type = normalizeToUnitType(unit?.type);
  const asset = MILSTD_MAIN_ASSETS[type];
  return Array.isArray(asset?.modifiers) ? asset.modifiers.filter(Boolean) : [];
}

function getMilstdFallbackText(unit) {
  const type = normalizeToUnitType(unit?.type);
  return MILSTD_FALLBACK_TEXT[type]
    || UNIT_TYPE_SYMBOLS[type]
    || UNIT_TYPE_SYMBOLS.default;
}

function normalizeToUnitType(type) {
  const normalized = TO_UNIT_TYPE_ALIASES[type] || type || DEFAULT_MILSTD_UNIT_ID;
  return getDoctrinalCatalogEntryById(normalized)?.id || normalizeMilstdUniqueId(normalized) || DEFAULT_MILSTD_UNIT_ID;
}

function formatToUnitLabelPart(value) {
  return String(value || "")
    .split("_")
    .filter(Boolean)
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ");
}

function formatToUnitSizeLabel(size = "") {
  const normalized = String(size || "").trim();
  return TO_UNIT_SIZE_LABELS[normalized] || formatToUnitLabelPart(normalized);
}

function normalizePlanUnitSize(type = DEFAULT_MILSTD_UNIT_ID, size = "") {
  const normalizedType = normalizeToUnitType(type);
  if (!catalogAllowsEchelon(normalizedType)) {
    return "";
  }
  const normalizedSize = String(size || "").trim();
  return TO_UNIT_SIZE_LABELS[normalizedSize] ? normalizedSize : DEFAULT_TO_UNIT_SIZE;
}

function inferPlanUnitSizeFromLabel(label = "", type = DEFAULT_MILSTD_UNIT_ID) {
  const text = String(label || "").trim();
  if (!text) return "";
  const normalizedType = normalizeToUnitType(type);
  return TO_UNIT_SIZE_ORDER.find((size) => text === buildDefaultToUnitLabel(size, normalizedType)) || "";
}

function normalizeToUnit(unit) {
  if (!unit || typeof unit !== "object") return unit;
  const detail = unit.detail && typeof unit.detail === "object" ? { ...unit.detail } : {};
  const explicitSidc = String(unit.sidc || detail.milsymId || "").trim();
  const explicitUniqueId = normalizeMilstdUniqueId(
    unit.symbolUniqueId
    || detail.milsymUniqueId
    || extractMilstdUniqueIdFromSidc(explicitSidc)
    || unit.catalogId
    || unit.type
    || ""
  );
  const normalizedType = normalizeToUnitType(unit.type || unit.catalogId || explicitUniqueId);
  const entry = getDoctrinalCatalogEntryById(normalizedType) || getMilstdSymbolCatalogEntry({
    ...unit,
    detail,
    sidc: explicitSidc,
    uniqueId: explicitUniqueId || normalizedType,
  });
  const affiliation = normalizeTacticalAffiliation(unit.affiliation || "friendly");
  const size = typeof unit.size === "string" ? unit.size : "";
  if (unit.type !== normalizedType) unit.type = normalizedType;
  if (unit.catalogId !== normalizedType) unit.catalogId = normalizedType;
  unit.symbolUniqueId = normalizeMilstdUniqueId(explicitUniqueId || entry?.uniqueId || unit.catalogId || normalizedType || "");
  if (!unit.cotType) {
    unit.cotType = buildCatalogCotType(normalizedType, affiliation) || unit.cotType || "";
  }
  if (entry) {
    unit.detail = buildMilstdDetail(detail, getMilstdSymbolCatalogEntry(entry.milstdCatalogId || entry.id || explicitUniqueId || normalizedType), affiliation, size);
    unit.sidc = String(explicitSidc || unit.detail?.milsymId || "").trim();
  } else if (detail && Object.keys(detail).length) {
    unit.detail = detail;
    unit.sidc = String(explicitSidc || unit.sidc || "").trim();
  }
  return unit;
}

function normalizePlanUnit(unit = {}) {
  const normalized = normalizeToUnit({
    ...unit,
    type: unit.catalogId || unit.symbolUniqueId || unit.type,
  });
  normalized.catalogId = normalized.catalogId || normalized.type;
  normalized.symbolUniqueId = normalizeMilstdUniqueId(normalized.catalogId || normalized.type || normalized.detail?.milsymUniqueId || "");
  normalized.cotType = String(
    unit.cotType
    || buildCatalogCotType(normalized.catalogId, normalized.affiliation || "friendly")
    || ""
  ).trim();
  const normalizedInitialSize = normalizePlanUnitSize(normalized.catalogId || normalized.type, normalized.size);
  normalized.label = (normalized.label || "").trim() || (normalized.designator || "").trim() || buildDefaultToUnitLabel(normalizedInitialSize, normalized.type);
  normalized.designator = String(normalized.designator || "").trim();
  normalized.affiliation = normalized.affiliation || "friendly";
  const inferredSize = !normalized.designator ? inferPlanUnitSizeFromLabel(normalized.label, normalized.catalogId || normalized.type) : "";
  normalized.size = normalizePlanUnitSize(normalized.catalogId || normalized.type, inferredSize || normalized.size);
  normalized.x = Number(normalized.x) || 0;
  normalized.y = Number(normalized.y) || 0;
  return normalized;
}

function buildDefaultToUnitLabel(size, type) {
  const sizeLabel = formatToUnitSizeLabel(size);
  const entry = getDoctrinalCatalogEntryById(normalizeToUnitType(type));
  const typeLabel = entry?.label || String(normalizeToUnitType(type) || DEFAULT_MILSTD_UNIT_ID).replace(/_/g, " ");
  return `${sizeLabel} ${typeLabel}`.trim();
}

let _syncingPlanUnitControls = false;

function getPlanUnitControlElements(target = "create") {
  const isEditTarget = target === "edit";
  return {
    affiliationSelect: document.getElementById(isEditTarget ? "toEditAffiliation" : "toAffiliation"),
    typeSelect: document.getElementById(isEditTarget ? "toEditUnitType" : "toUnitType"),
    sizeSelect: document.getElementById(isEditTarget ? "toEditUnitSize" : "toUnitSize"),
  };
}

function setSelectValueIfPresent(selectEl, value = "", fallback = "") {
  if (!selectEl) return "";
  const text = String(value || "");
  const option = Array.from(selectEl.options || []).find((entry) => entry.value === text);
  if (option) {
    selectEl.value = text;
    return text;
  }
  const fallbackText = String(fallback || "");
  const fallbackOption = Array.from(selectEl.options || []).find((entry) => entry.value === fallbackText);
  if (fallbackOption) {
    selectEl.value = fallbackText;
    return fallbackText;
  }
  selectEl.value = "";
  return "";
}

function setPlanUnitSizeSelectValue(sizeSelect, type = DEFAULT_MILSTD_UNIT_ID, size = "") {
  if (!sizeSelect) return "";
  const normalizedType = normalizeToUnitType(type);
  const allowsEchelon = catalogAllowsEchelon(normalizedType);
  sizeSelect.disabled = !allowsEchelon;
  if (!allowsEchelon) {
    sizeSelect.value = "";
    return "";
  }
  const normalizedSize = normalizePlanUnitSize(normalizedType, size);
  return setSelectValueIfPresent(sizeSelect, normalizedSize, DEFAULT_TO_UNIT_SIZE);
}

function syncPlanUnitControls(values = {}, { target = "create", entry = null } = {}) {
  const { affiliationSelect, typeSelect, sizeSelect } = getPlanUnitControlElements(target);
  const type = normalizeToUnitType(values.catalogId || values.type || values.unitType || typeSelect?.value || DEFAULT_MILSTD_UNIT_ID);
  const affiliation = normalizeTacticalAffiliation(values.affiliation || affiliationSelect?.value || "friendly");
  _syncingPlanUnitControls = true;
  if (affiliationSelect) setSelectValueIfPresent(affiliationSelect, affiliation, "friendly");
  if (typeSelect) setSelectValueIfPresent(typeSelect, type, DEFAULT_MILSTD_UNIT_ID);
  const size = setPlanUnitSizeSelectValue(sizeSelect, type, values.size || sizeSelect?.value || DEFAULT_TO_UNIT_SIZE);
  _syncingPlanUnitControls = false;
  refreshPlanUnitTypePickerLabel(type, affiliation, { target, entry });
  return { affiliation, type, size };
}

function isPlanUnitAutoGeneratedLabel(unit = {}) {
  const label = String(unit?.label || "").trim();
  if (!label) return true;
  if (String(unit?.designator || "").trim()) return false;
  const type = normalizeToUnitType(unit.catalogId || unit.type);
  return TO_UNIT_SIZE_ORDER.some((size) => label === buildDefaultToUnitLabel(size, type));
}

function applyPlanUnitControlValues(unit, values = {}) {
  if (!unit) return null;
  const wasAutoLabel = isPlanUnitAutoGeneratedLabel(unit);
  const type = normalizeToUnitType(values.catalogId || values.type || unit.catalogId || unit.type);
  const affiliation = normalizeTacticalAffiliation(values.affiliation || unit.affiliation || "friendly");
  const size = normalizePlanUnitSize(type, values.size ?? unit.size);
  const nextLabel = values.label !== undefined
    ? String(values.label || "").trim()
    : (wasAutoLabel ? buildDefaultToUnitLabel(size, type) : String(unit.label || "").trim());
  const designator = values.designator !== undefined
    ? String(values.designator || "").trim()
    : String(unit.designator || "").trim();
  Object.assign(unit, normalizePlanUnit({
    ...unit,
    label: nextLabel || designator || buildDefaultToUnitLabel(size, type),
    designator,
    affiliation,
    type,
    catalogId: type,
    cotType: buildCatalogCotType(type, affiliation) || getMilstdSymbolDefaultCotType(getMilstdSymbolCatalogEntry(type), affiliation),
    size,
  }));
  return unit;
}

function getSelectedPlanUnit() {
  return Number.isFinite(Number(_toState.selectedUnit))
    ? _toState.units.find((entry) => Number(entry.id) === Number(_toState.selectedUnit)) || null
    : null;
}

function syncSelectedPlanUnitToToolbar() {
  const unit = getSelectedPlanUnit();
  if (!unit) return false;
  syncPlanUnitControls(normalizePlanUnit(unit), { target: "create" });
  return true;
}

function syncEditModalFromPlanUnit(unit) {
  if (!unit || Number(_toState.editingUnitId) !== Number(unit.id)) return false;
  syncPlanUnitControls(normalizePlanUnit(unit), { target: "edit" });
  return true;
}

function syncToolbarFromEditDraft() {
  if (_syncingPlanUnitControls || !Number.isFinite(Number(_toState.editingUnitId))) return;
  const { affiliationSelect, typeSelect, sizeSelect } = getPlanUnitControlElements("edit");
  syncPlanUnitControls({
    affiliation: affiliationSelect?.value || "friendly",
    type: typeSelect?.value || DEFAULT_MILSTD_UNIT_ID,
    size: sizeSelect?.value || DEFAULT_TO_UNIT_SIZE,
  }, { target: "create" });
}

function syncSelectedPlanUnitFromToolbar({ render = true, persist = true } = {}) {
  if (_syncingPlanUnitControls) return false;
  const unit = getSelectedPlanUnit();
  if (!unit) return false;
  const { affiliationSelect, typeSelect, sizeSelect } = getPlanUnitControlElements("create");
  const updated = applyPlanUnitControlValues(unit, {
    affiliation: affiliationSelect?.value || "friendly",
    type: typeSelect?.value || DEFAULT_MILSTD_UNIT_ID,
    size: sizeSelect?.value || DEFAULT_TO_UNIT_SIZE,
  });
  if (!updated) return false;
  syncPlanUnitControls(updated, { target: "create" });
  syncEditModalFromPlanUnit(updated);
  if (render) renderToView();
  syncTacticalObjectFromPlanUnit(updated.id);
  if (persist) saveMapState();
  return true;
}

function serializeToPlanState() {
  return {
    units: _toState.units.map((unit) => {
      const normalized = normalizePlanUnit(unit);
      return {
        id: normalized.id,
        label: normalized.label || "",
        designator: normalized.designator || "",
        affiliation: normalized.affiliation || "friendly",
        type: normalizeToUnitType(normalized.type),
        catalogId: normalized.catalogId || normalizeToUnitType(normalized.type),
        symbolUniqueId: normalizeMilstdUniqueId(normalized.catalogId || normalized.type || normalized.detail?.milsymUniqueId || ""),
        cotType: normalized.cotType || "",
        sidc: String(normalized.sidc || normalized.detail?.milsymId || "").trim(),
        detail: normalized.detail && typeof normalized.detail === "object" ? { ...normalized.detail } : {},
        size: normalized.size || "",
        x: Number(normalized.x) || 0,
        y: Number(normalized.y) || 0,
      };
    }),
    links: _toState.links.map((link) => ({
      parentId: link.parentId,
      childId: link.childId,
    })),
    nextId: _toState.nextId,
  };
}

function milstd2525Svg(unit) {
  const spec = getMilstdLayerSpec(unit);
  const domainClass = `milstd-stack--domain-${String(spec.domain || "ground").replace(/[^a-z0-9_-]/gi, "")}`;
  const renderLayer = (path, modifierClass = "") => `<img src="${path}" class="milstd-layer${modifierClass ? ` ${modifierClass}` : ""}" alt="" loading="lazy" decoding="async" onerror="this.style.display='none'">`;
  return `<span class="milstd-stack ms2525-icon ${domainClass}" aria-hidden="true">
    ${spec.framePath ? renderLayer(spec.framePath) : ""}
    ${spec.mainPath ? renderLayer(spec.mainPath) : ""}
    ${spec.modifierPaths.map((path) => renderLayer(path)).join("")}
    ${spec.fallbackText ? `<span class="milstd-fallback-text">${esc(spec.fallbackText)}</span>` : ""}
    ${spec.echelonPath ? renderLayer(spec.echelonPath, "milstd-layer--echelon") : ""}
  </span>`;
}

function renderToUnitIcon(unit) {
  return milstd2525Svg(unit);
}

function closeToEditModal({ syncToolbar = true } = {}) {
  _toState.editingUnitId = null;
  document.getElementById("toEditModal")?.classList.add("hidden");
  document.body.classList.remove("emitter-modal-open");
  const validation = document.getElementById("toEditValidation");
  if (validation) validation.textContent = "";
  if (syncToolbar) syncSelectedPlanUnitToToolbar();
}

function openToEditModal(unitId = _toState.selectedUnit) {
  const unit = _toState.units.find((entry) => entry.id === unitId);
  if (!unit) return;
  const normalized = normalizePlanUnit(unit);
  _toState.editingUnitId = unit.id;
  const labelInput = document.getElementById("toEditLabel");
  const designatorInput = document.getElementById("toEditDesignator");
  const affiliationSelect = document.getElementById("toEditAffiliation");
  const typeSelect = document.getElementById("toEditUnitType");
  const sizeSelect = document.getElementById("toEditUnitSize");
  if (!labelInput || !designatorInput || !affiliationSelect || !typeSelect || !sizeSelect) return;
  labelInput.value = normalized.label || "";
  designatorInput.value = normalized.designator || "";
  syncPlanUnitControls(normalized, { target: "edit" });
  syncPlanUnitControls(normalized, { target: "create" });
  const validation = document.getElementById("toEditValidation");
  if (validation) validation.textContent = "";
  document.getElementById("toEditModal")?.classList.remove("hidden");
  document.body.classList.add("emitter-modal-open");
  labelInput.focus();
  labelInput.select();
}

function saveToEditModal() {
  const unit = _toState.units.find((entry) => entry.id === _toState.editingUnitId);
  if (!unit) {
    closeToEditModal();
    return;
  }
  const labelInput = document.getElementById("toEditLabel");
  const designatorInput = document.getElementById("toEditDesignator");
  const affiliationSelect = document.getElementById("toEditAffiliation");
  const typeSelect = document.getElementById("toEditUnitType");
  const sizeSelect = document.getElementById("toEditUnitSize");
  const validation = document.getElementById("toEditValidation");
  if (!labelInput || !designatorInput || !affiliationSelect || !typeSelect || !sizeSelect) return;
  const type = normalizeToUnitType(typeSelect.value);
  const size = normalizePlanUnitSize(type, sizeSelect.value);
  const designator = (designatorInput.value || "").trim();
  const label = (labelInput.value || "").trim() || designator || buildDefaultToUnitLabel(size, type);
  const affiliation = affiliationSelect.value || "friendly";
  applyPlanUnitControlValues(unit, {
    label,
    designator,
    affiliation,
    type,
    catalogId: type,
    size,
  });
  if (validation) validation.textContent = "";
  closeToEditModal();
  renderToView();
  syncTacticalObjectFromPlanUnit(unit.id);
  saveMapState();
}

function initPlanViewIfNeeded() {
  if (_toState._initialized) return;
  _toState._initialized = true;

  const canvas = document.getElementById("toCanvas");
  const world  = document.getElementById("toWorld");
  const edgeSvg = document.getElementById("toEdgeSvg");
  const unitAffiliationSelect = document.getElementById("toAffiliation");
  const unitTypeSelect = document.getElementById("toUnitType");
  const unitSizeSelect = document.getElementById("toUnitSize");
  const editAffiliationSelect = document.getElementById("toEditAffiliation");
  const editTypeSelect = document.getElementById("toEditUnitType");
  const editSizeSelect = document.getElementById("toEditUnitSize");
  if (!canvas || !world) return;
  if (unitAffiliationSelect && editAffiliationSelect) editAffiliationSelect.innerHTML = unitAffiliationSelect.innerHTML;
  populateDoctrinalUnitTypeSelect(unitTypeSelect);
  populateDoctrinalUnitTypeSelect(editTypeSelect);
  if (unitSizeSelect && editSizeSelect) editSizeSelect.innerHTML = unitSizeSelect.innerHTML;
  syncPlanUnitControls({
    affiliation: unitAffiliationSelect?.value || "friendly",
    type: unitTypeSelect?.value || DEFAULT_MILSTD_UNIT_ID,
    size: unitSizeSelect?.value || DEFAULT_TO_UNIT_SIZE,
  }, { target: "create" });
  syncPlanUnitControls({
    affiliation: editAffiliationSelect?.value || "friendly",
    type: editTypeSelect?.value || DEFAULT_MILSTD_UNIT_ID,
    size: editSizeSelect?.value || DEFAULT_TO_UNIT_SIZE,
  }, { target: "edit" });
  unitAffiliationSelect?.addEventListener("change", () => {
    refreshPlanUnitTypePickerLabel(unitTypeSelect?.value || DEFAULT_MILSTD_UNIT_ID, unitAffiliationSelect.value || "friendly", { target: "create" });
    syncSelectedPlanUnitFromToolbar();
  });
  unitTypeSelect?.addEventListener("change", () => {
    refreshPlanUnitTypePickerLabel(unitTypeSelect.value || DEFAULT_MILSTD_UNIT_ID, unitAffiliationSelect?.value || "friendly", { target: "create" });
    setPlanUnitSizeSelectValue(unitSizeSelect, unitTypeSelect.value || DEFAULT_MILSTD_UNIT_ID, unitSizeSelect?.value || DEFAULT_TO_UNIT_SIZE);
    syncSelectedPlanUnitFromToolbar();
  });
  unitSizeSelect?.addEventListener("change", () => {
    syncSelectedPlanUnitFromToolbar();
  });
  editAffiliationSelect?.addEventListener("change", () => {
    refreshPlanUnitTypePickerLabel(editTypeSelect?.value || DEFAULT_MILSTD_UNIT_ID, editAffiliationSelect.value || "friendly", { target: "edit" });
    syncToolbarFromEditDraft();
  });
  editTypeSelect?.addEventListener("change", () => {
    refreshPlanUnitTypePickerLabel(editTypeSelect.value || DEFAULT_MILSTD_UNIT_ID, editAffiliationSelect?.value || "friendly", { target: "edit" });
    setPlanUnitSizeSelectValue(editSizeSelect, editTypeSelect.value || DEFAULT_MILSTD_UNIT_ID, editSizeSelect?.value || DEFAULT_TO_UNIT_SIZE);
    syncToolbarFromEditDraft();
  });
  editSizeSelect?.addEventListener("change", () => {
    syncToolbarFromEditDraft();
  });
  // â”€â”€ Wire toolbar buttons â”€â”€
  document.getElementById("toAddUnitBtn")?.addEventListener("click", () => {
    const aff  = document.getElementById("toAffiliation")?.value || "friendly";
    const type = document.getElementById("toUnitType")?.value || DEFAULT_MILSTD_UNIT_ID;
    const size = normalizePlanUnitSize(type, document.getElementById("toUnitSize")?.value || DEFAULT_TO_UNIT_SIZE);
    const des  = (document.getElementById("toUnitDesignator")?.value || "").trim();
    const label = des || buildDefaultToUnitLabel(size, type);
    const cx = canvas.clientWidth  / 2 - _toState.panX / _toState.zoom;
    const cy = canvas.clientHeight / 2 - _toState.panY / _toState.zoom;
    const jitter = () => (Math.random() - 0.5) * 120;
    addToUnit({ label, designator: des, affiliation: aff, type, catalogId: type, cotType: buildCatalogCotType(type, aff), size, x: cx + jitter(), y: cy + jitter() });
    document.getElementById("toUnitDesignator").value = "";
  });
  document.getElementById("toPlaceUnitBtn")?.addEventListener("click", () => {
    if (!Number.isFinite(Number(_toState.selectedUnit))) {
      setStatus("Select a T/O unit to place on the map.", true);
      return;
    }
    beginPlanUnitMapPlacement(Number(_toState.selectedUnit));
  });
  document.getElementById("toAutoLayoutBtn")?.addEventListener("click", toAutoLayout);
  document.getElementById("toFitViewBtn")?.addEventListener("click", toFitView);
  document.getElementById("toClearAllBtn")?.addEventListener("click", () => {
    if (!confirm("Clear all units?")) return;
    const linkedTacticalIds = state.tacticalObjects
      .filter((object) => Number.isFinite(Number(object.linkedPlanUnitId)))
      .map((object) => object.id);
    linkedTacticalIds.forEach((objectId) => deleteTacticalObject(objectId, { silent: true }));
    _toState.units = [];
    _toState.links = [];
    clearToSelection();
    closeToEditModal();
    renderToView();
    saveMapState();
  });
  document.getElementById("toZoomInBtn")?.addEventListener("click",  () => setToZoom(_toState.zoom * 1.2));
  document.getElementById("toZoomOutBtn")?.addEventListener("click", () => setToZoom(_toState.zoom / 1.2));

  // â”€â”€ Pan / zoom on canvas â”€â”€
  canvas.addEventListener("wheel", (e) => {
    e.preventDefault();
    const factor = e.deltaY < 0 ? 1.1 : 0.9;
    const rect = canvas.getBoundingClientRect();
    const mx = e.clientX - rect.left;
    const my = e.clientY - rect.top;
    const newZoom = Math.max(0.2, Math.min(4, _toState.zoom * factor));
    _toState.panX = mx - (mx - _toState.panX) * (newZoom / _toState.zoom);
    _toState.panY = my - (my - _toState.panY) * (newZoom / _toState.zoom);
    _toState.zoom = newZoom;
    applyToTransform();
  }, { passive: false });

  canvas.addEventListener("mousedown", (e) => {
    if (e.target === canvas || e.target === world || e.target === edgeSvg) {
      _toState.panning = true;
      _toState.panStart = { x: e.clientX - _toState.panX, y: e.clientY - _toState.panY };
      hideToContextMenu();
    }
  });
  document.addEventListener("pointermove", (e) => {
    if (_toState.panning) {
      _toState.panX = e.clientX - _toState.panStart.x;
      _toState.panY = e.clientY - _toState.panStart.y;
      applyToTransform();
      return;
    }
    if (_toState.dragging && e.pointerId === _toState.dragging.pointerId) {
      const d = _toState.dragging;
      const dx = (e.clientX - d.startX) / _toState.zoom;
      const dy = (e.clientY - d.startY) / _toState.zoom;
      const unit = _toState.units.find(u => u.id === d.unitId);
      if (unit) {
        unit.x = d.origX + dx;
        unit.y = d.origY + dy;
        const el = document.querySelector(`.to-unit[data-id="${unit.id}"]`);
        if (el) { el.style.left = unit.x + "px"; el.style.top = unit.y + "px"; }
        renderToEdges();
      }
    }
  });
  document.addEventListener("pointerup", (e) => {
    if (_toState.dragging?.pointerId === e.pointerId) {
      _toState.dragging.sourceEl?.releasePointerCapture?.(e.pointerId);
      _toState.dragging = null;
      saveMapState();
    }
    _toState.panning = false;
  });
  document.addEventListener("pointercancel", (e) => {
    if (_toState.dragging?.pointerId === e.pointerId) {
      _toState.dragging.sourceEl?.releasePointerCapture?.(e.pointerId);
      _toState.dragging = null;
    }
    _toState.panning = false;
  });

  // â”€â”€ Context menu â”€â”€
  document.getElementById("toCtxLinkParent")?.addEventListener("click", () => {
    if (!_toState.selectedUnit) return;
    _toState.linkMode = { type: "parent", fromId: _toState.selectedUnit };
    updateToLinkBannerMessage("Click another unit to link or unlink it as the parent of the selected unit.");
    hideToContextMenu();
  });
  document.getElementById("toCtxLinkChild")?.addEventListener("click", () => {
    if (!_toState.selectedUnit) return;
    _toState.linkMode = { type: "child", fromId: _toState.selectedUnit };
    updateToLinkBannerMessage("Click another unit to link or unlink it as a child of the selected unit.");
    hideToContextMenu();
  });
  document.getElementById("toCtxEmitters")?.addEventListener("click", () => {
    hideToContextMenu();
    openToEmitterManagerModal();
  });
  document.getElementById("toCtxEdit")?.addEventListener("click", () => {
    hideToContextMenu();
    openToEditModal();
  });
  document.getElementById("toCtxPlace")?.addEventListener("click", () => {
    hideToContextMenu();
    if (!Number.isFinite(Number(_toState.selectedUnit))) {
      setStatus("Select a T/O unit first.", true);
      return;
    }
    beginPlanUnitMapPlacement(Number(_toState.selectedUnit));
  });
  document.getElementById("toCtxDuplicate")?.addEventListener("click", () => {
    hideToContextMenu();
    duplicateToUnit();
  });
  document.getElementById("toCtxDelete")?.addEventListener("click", () => {
    if (!_toState.selectedUnit) return;
    const linkedTactical = getTacticalObjectByPlanUnitId(_toState.selectedUnit);
    if (linkedTactical) {
      hideToContextMenu();
      deleteTacticalObject(linkedTactical.id);
      return;
    }
    _toState.units = _toState.units.filter(u => u.id !== _toState.selectedUnit);
    _toState.links = _toState.links.filter(l => l.parentId !== _toState.selectedUnit && l.childId !== _toState.selectedUnit);
    clearToSelection();
    hideToContextMenu();
    renderToView();
    saveMapState();
  });
  document.getElementById("toLinkCancelBtn")?.addEventListener("click", cancelToLink);
  document.getElementById("toEditCloseBtn")?.addEventListener("click", closeToEditModal);
  document.getElementById("toEditCancelBtn")?.addEventListener("click", closeToEditModal);
  document.getElementById("toEditSaveBtn")?.addEventListener("click", saveToEditModal);
  document.getElementById("toEditModal")?.addEventListener("click", (e) => {
    if (e.target === document.getElementById("toEditModal")) closeToEditModal();
  });
  document.getElementById("toEditLabel")?.addEventListener("keydown", (e) => {
    if (e.key === "Enter") {
      e.preventDefault();
      saveToEditModal();
    }
  });
  document.getElementById("toEditDesignator")?.addEventListener("keydown", (e) => {
    if (e.key === "Enter") {
      e.preventDefault();
      saveToEditModal();
    }
  });
  dom.toEmitterManagerCloseBtn?.addEventListener("click", closeToEmitterManagerModal);
  dom.toEmitterManagerDoneBtn?.addEventListener("click", closeToEmitterManagerModal);
  dom.toEmitterManagerModal?.addEventListener("click", (e) => {
    if (e.target === dom.toEmitterManagerModal) {
      closeToEmitterManagerModal();
    }
  });
  dom.toEmitterLinkExistingBtn?.addEventListener("click", () => {
    _toEmitterManagerState.chooserOpen = true;
    renderToEmitterManagerModal();
  });
  dom.toEmitterChooserBackBtn?.addEventListener("click", () => {
    _toEmitterManagerState.chooserOpen = false;
    renderToEmitterManagerModal();
  });
  dom.toEmitterAvailableList?.addEventListener("click", (event) => {
    const button = event.target.closest('[data-to-emitter-action="link-asset"]');
    if (!button) return;
    const assetId = button.dataset.assetId || "";
    if (!assetId) return;
    if (linkEmitterAssetToPlanUnit(assetId)) {
      renderToEmitterManagerModal();
    }
  });
  dom.toEmitterLinkedList?.addEventListener("click", (event) => {
    const button = event.target.closest('[data-to-emitter-action="focus-asset"]');
    if (!button) return;
    const assetId = button.dataset.assetId || "";
    if (!assetId) return;
    focusMapContent(`asset:${assetId}`);
  });
  dom.toEmitterLinkedList?.addEventListener("contextmenu", (event) => {
    const row = event.target.closest(".to-emitter-manager-item");
    if (!row || !dom.toEmitterLinkedContextMenu) return;
    event.preventDefault();
    event.stopPropagation();
    hideToEmitterLinkedContextMenu();
    _toEmitterManagerState.contextAssetId = row.dataset.assetId || "";
    row.classList.add("is-context-target");
    dom.toEmitterLinkedContextMenu.style.left = `${event.clientX}px`;
    dom.toEmitterLinkedContextMenu.style.top = `${event.clientY}px`;
    dom.toEmitterLinkedContextMenu.classList.remove("hidden");
  });
  dom.toEmitterLinkedContextUnlink?.addEventListener("click", () => {
    const assetId = _toEmitterManagerState.contextAssetId;
    hideToEmitterLinkedContextMenu();
    if (!assetId) return;
    if (unlinkEmitterAssetById(assetId)) {
      renderToEmitterManagerModal();
    }
  });

  canvas.addEventListener("click", (e) => {
    hideToContextMenu();
    if (e.target === canvas || e.target === world || e.target === edgeSvg) {
      clearToSelection();
    }
  });
  document.addEventListener("click", (e) => {
    if (!dom.toEmitterLinkedContextMenu?.contains(e.target)) {
      hideToEmitterLinkedContextMenu();
    }
  });
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") {
      hideToContextMenu();
      cancelToLink();
      closeToEditModal();
      closeToEmitterManagerModal();
    }
  });

  // â”€â”€ AI form â”€â”€
  renderToView();
}

function addToUnit(props) {
  const type = normalizeToUnitType(props?.catalogId || props?.type);
  const size = normalizePlanUnitSize(type, props?.size || DEFAULT_TO_UNIT_SIZE);
  const designator = (props?.designator || "").trim();
  const label = (props?.label || "").trim() || designator || buildDefaultToUnitLabel(size, type);
  const unit = normalizePlanUnit({
    id: _toState.nextId++,
    ...props,
    label,
    designator,
    size,
    type,
    catalogId: type,
    cotType: props?.cotType || buildCatalogCotType(type, props?.affiliation || "friendly"),
  });
  _toState.units.push(unit);
  renderToView();
  saveMapState();
  return unit;
}

function renderToView() {
  const world = document.getElementById("toWorld");
  if (!world) return;
  world.innerHTML = "";
  for (const unit of _toState.units) renderToUnit(normalizePlanUnit(unit));
  renderToEdges();
  syncSelectedPlanUnitToToolbar();
  if (!dom.toEmitterManagerModal?.classList.contains("hidden")) {
    renderToEmitterManagerModal();
  }
}

function renderToUnit(unit) {
  const world = document.getElementById("toWorld");
  if (!world) return;
  const normalized = normalizePlanUnit(unit);
  const linkedTactical = getTacticalObjectByPlanUnitId(normalized.id);
  const linkedEmitters = getPlanUnitLinkedEmitters(normalized.id);
  const placementBadge = linkedTactical
    ? `<span class="to-unit-placement-badge">Map linked</span>`
    : `<span class="to-unit-placement-badge to-unit-placement-badge--pending">Not placed</span>`;
  const emitterBadge = linkedEmitters.length
    ? `<span class="to-unit-placement-badge">${linkedEmitters.length} emitter${linkedEmitters.length === 1 ? "" : "s"} linked</span>`
    : "";
  const el = document.createElement("div");
  el.className = "to-unit";
  if (_toState.selectedUnit === normalized.id) el.classList.add("selected");
  el.dataset.id = normalized.id;
  el.style.left = normalized.x + "px";
  el.style.top  = normalized.y + "px";
  el.innerHTML = `
    <div class="to-unit-card">
      <span class="to-unit-icon">${renderToUnitIcon(normalized)}</span>
      <span class="to-unit-label">${esc(normalized.label)}</span>
      ${emitterBadge}
      ${placementBadge}
    </div>
  `;
  el.setAttribute("draggable", "false");
  el.querySelectorAll("img, svg").forEach((node) => {
    node.setAttribute("draggable", "false");
  });
  el.addEventListener("dragstart", (e) => e.preventDefault());

  // Drag to move
  el.addEventListener("pointerdown", (e) => {
    if (e.button !== 0) return;
    e.stopPropagation();
    hideToContextMenu();
    closeToEditModal();
    const liveUnit = _toState.units.find((entry) => entry.id === normalized.id);
    if (!liveUnit) return;
    _toState.selectedUnit = liveUnit.id;
    syncSelectedPlanUnitToToolbar();
    document.querySelectorAll(".to-unit").forEach(u => u.classList.remove("selected"));
    el.classList.add("selected");
    _toState.dragging = {
      unitId: liveUnit.id,
      pointerId: e.pointerId,
      startX: e.clientX,
      startY: e.clientY,
      origX: Number(liveUnit.x) || 0,
      origY: Number(liveUnit.y) || 0,
      sourceEl: el,
    };
    el.setPointerCapture?.(e.pointerId);
  });
  el.addEventListener("lostpointercapture", () => {
    if (_toState.dragging?.sourceEl === el) _toState.dragging = null;
  });

  // Click to pick link target
  el.addEventListener("click", (e) => {
    e.stopPropagation();
    if (_toState.linkMode) {
      const { type, fromId } = _toState.linkMode;
      if (normalized.id === fromId) { cancelToLink(); return; }
      const result = toggleToLink(type, fromId, normalized.id);
      cancelToLink();
      if (!result.changed) {
        if (result.blocked) {
          setStatus("That link would create a loop in the unit hierarchy.", true);
        }
        return;
      }
      if (result.linked) {
        toAutoLayout();
      } else {
        renderToEdges();
        saveMapState();
      }
      setStatus(
        result.linked
          ? `Linked ${normalized.label || normalized.designator || "unit"} as ${type === "parent" ? "parent" : "child"}.`
          : `Unlinked ${normalized.label || normalized.designator || "unit"} from the selected ${type === "parent" ? "parent" : "child"} relationship.`,
      );
      return;
    }
    _toState.selectedUnit = normalized.id;
    syncSelectedPlanUnitToToolbar();
  });

  // Right-click context menu
  el.addEventListener("contextmenu", (e) => {
    e.preventDefault();
    e.stopPropagation();
    _toState.selectedUnit = normalized.id;
    syncSelectedPlanUnitToToolbar();
    document.querySelectorAll(".to-unit").forEach(u => u.classList.remove("selected"));
    el.classList.add("selected");
    showToContextMenu(e.clientX, e.clientY);
  });

  world.appendChild(el);
}

function showToContextMenu(x, y) {
  const menu = document.getElementById("toContextMenu");
  if (!menu) return;
  menu.style.left = x + "px";
  menu.style.top  = y + "px";
  menu.classList.remove("hidden");
}
function hideToContextMenu() {
  document.getElementById("toContextMenu")?.classList.add("hidden");
}

function updateToLinkBannerMessage(message) {
  const msg = document.getElementById("toLinkBannerMsg");
  const banner = document.getElementById("toLinkBanner");
  if (msg) msg.textContent = message;
  if (banner) banner.classList.remove("hidden");
}

function hasToLink(parentId, childId) {
  return _toState.links.some((link) => link.parentId === parentId && link.childId === childId);
}

function getToDescendantIds(unitId) {
  const descendants = new Set();
  const queue = [unitId];
  while (queue.length) {
    const currentId = queue.shift();
    _toState.links.forEach((link) => {
      if (link.parentId === currentId && !descendants.has(link.childId)) {
        descendants.add(link.childId);
        queue.push(link.childId);
      }
    });
  }
  return descendants;
}

function canCreateToLink(parentId, childId) {
  if (!Number.isFinite(parentId) || !Number.isFinite(childId) || parentId === childId) {
    return false;
  }
  return !getToDescendantIds(childId).has(parentId);
}

function toggleToLink(type, fromId, targetId) {
  if (!Number.isFinite(fromId) || !Number.isFinite(targetId) || fromId === targetId) {
    return { changed: false, linked: false };
  }
  const parentId = type === "parent" ? targetId : fromId;
  const childId = type === "child" ? targetId : fromId;
  const exists = hasToLink(parentId, childId);
  if (exists) {
    _toState.links = _toState.links.filter((link) => !(link.parentId === parentId && link.childId === childId));
    return { changed: true, linked: false, parentId, childId };
  }
  if (!canCreateToLink(parentId, childId)) {
    return { changed: false, linked: false, blocked: true, parentId, childId };
  }
  _toState.links = _toState.links.filter((link) => link.childId !== childId);
  _toState.links.push({ parentId, childId });
  return { changed: true, linked: true, parentId, childId };
}

function duplicateToUnit(unitId = _toState.selectedUnit) {
  const source = _toState.units.find((unit) => unit.id === unitId);
  if (!source) {
    return null;
  }
  const duplicate = normalizePlanUnit({
    ...source,
    id: _toState.nextId++,
    x: source.x + 48,
    y: source.y + 36,
  });
  _toState.units.push(duplicate);
  _toState.selectedUnit = duplicate.id;
  renderToView();
  saveMapState();
  return duplicate;
}

function cancelToLink() {
  _toState.linkMode = null;
  document.getElementById("toLinkBanner")?.classList.add("hidden");
}

function clearToSelection() {
  _toState.selectedUnit = null;
  document.querySelectorAll(".to-unit.selected").forEach((el) => el.classList.remove("selected"));
}

function getToUnitConnectorAnchors(unit, world, svg) {
  if (!unit || !world || !svg) return null;
  const unitEl = world.querySelector(`.to-unit[data-id="${unit.id}"]`);
  if (!unitEl) return null;
  // Use the full card bounds so connector stems start outside the label/badge area.
  const anchorEl = unitEl.querySelector(".to-unit-card") || unitEl;
  const anchorRect = anchorEl.getBoundingClientRect();
  const svgRect = svg.getBoundingClientRect();
  return {
    centerX: anchorRect.left - svgRect.left + (anchorRect.width / 2),
    topY: anchorRect.top - svgRect.top,
    bottomY: anchorRect.bottom - svgRect.top,
  };
}

function renderToEdges() {
  const svg = document.getElementById("toEdgeSvg");
  const world = document.getElementById("toWorld");
  if (!svg || !world) return;
  svg.innerHTML = "";
  for (const link of _toState.links) {
    const parent = _toState.units.find(u => u.id === link.parentId);
    const child  = _toState.units.find(u => u.id === link.childId);
    if (!parent || !child) continue;
    const parentAnchor = getToUnitConnectorAnchors(parent, world, svg);
    const childAnchor = getToUnitConnectorAnchors(child, world, svg);
    if (!parentAnchor || !childAnchor) continue;
    const x1 = parentAnchor.centerX;
    const y1 = parentAnchor.bottomY;
    const x2 = childAnchor.centerX;
    const y2 = childAnchor.topY;
    const midY = (y1 + y2) / 2;
    // Orthogonal elbow: down â†’ horizontal â†’ down
    const d = `M${x1},${y1} L${x1},${midY} L${x2},${midY} L${x2},${y2}`;
    const line = document.createElementNS("http://www.w3.org/2000/svg", "path");
    line.setAttribute("d", d);
    line.setAttribute("stroke", "var(--border-strong)");
    line.setAttribute("stroke-width", "1.5");
    line.setAttribute("fill", "none");
    line.setAttribute("stroke-linejoin", "round");
    svg.appendChild(line);
  }
}

function applyToTransform() {
  const world = document.getElementById("toWorld");
  if (world) world.style.transform = `translate(${_toState.panX}px,${_toState.panY}px) scale(${_toState.zoom})`;
  renderToEdges();
}

function centerPlanUnitInView(unitId) {
  const unit = getPlanUnitById(unitId);
  const canvas = document.getElementById("toCanvas");
  if (!unit || !canvas) {
    return;
  }
  _toState.panX = (canvas.clientWidth / 2) - (Number(unit.x) * _toState.zoom);
  _toState.panY = (canvas.clientHeight / 2) - (Number(unit.y) * _toState.zoom);
  applyToTransform();
}

function setToZoom(z) {
  _toState.zoom = Math.max(0.2, Math.min(4, z));
  applyToTransform();
}

function toAutoLayout() {
  if (!_toState.links.length || !_toState.units.length) return;

  // Build adjacency: find roots (nodes with no parent)
  const childSet = new Set(_toState.links.map(l => l.childId));
  const roots = _toState.units.filter(u => !childSet.has(u.id));
  if (!roots.length) return;

  const H_GAP = 190;
  const V_GAP = 230;

  function subtreeWidth(id, depth) {
    const children = _toState.links.filter(l => l.parentId === id).map(l => l.childId);
    if (!children.length) return H_GAP;
    return Math.max(H_GAP, children.reduce((sum, cid) => sum + subtreeWidth(cid, depth + 1), 0));
  }

  function layout(id, x, y) {
    const unit = _toState.units.find(u => u.id === id);
    if (!unit) return;
    unit.x = x;
    unit.y = y;
    const children = _toState.links.filter(l => l.parentId === id).map(l => l.childId);
    const totalW = children.reduce((sum, cid) => sum + subtreeWidth(cid, 0), 0);
    let cx = x - totalW / 2;
    for (const cid of children) {
      const w = subtreeWidth(cid, 0);
      layout(cid, cx + w / 2, y + V_GAP);
      cx += w;
    }
  }

  let startX = 200;
  for (const root of roots) {
    const w = subtreeWidth(root.id, 0);
    layout(root.id, startX + w / 2, 120);
    startX += w + H_GAP;
  }

  // Re-render positions
  _toState.units.forEach(u => {
    const el = document.querySelector(`.to-unit[data-id="${u.id}"]`);
    if (el) { el.style.left = u.x + "px"; el.style.top = u.y + "px"; }
  });
  // Defer edge rendering until after the browser has completed layout so
  // offsetHeight reads in getToUnitConnectorAnchors return accurate values.
  requestAnimationFrame(() => {
    renderToEdges();
    saveMapState();
  });
}

function toFitView() {
  if (!_toState.units.length) return;
  const canvas = document.getElementById("toCanvas");
  if (!canvas) return;
  const xs = _toState.units.map(u => u.x);
  const ys = _toState.units.map(u => u.y);
  const minX = Math.min(...xs) - 80;
  const maxX = Math.max(...xs) + 80;
  const minY = Math.min(...ys) - 80;
  const maxY = Math.max(...ys) + 80;
  const w = canvas.clientWidth;
  const h = canvas.clientHeight;
  const scaleX = w / (maxX - minX);
  const scaleY = h / (maxY - minY);
  _toState.zoom = Math.max(0.2, Math.min(2, Math.min(scaleX, scaleY) * 0.9));
  _toState.panX = w / 2 - ((minX + maxX) / 2) * _toState.zoom;
  _toState.panY = h / 2 - ((minY + maxY) / 2) * _toState.zoom;
  applyToTransform();
}

function buildPlanAiContext(options = {}) {
  const compact = options.compact !== false;
  const unitLimit = compact ? 24 : _toState.units.length;
  const linkLimit = compact ? 40 : _toState.links.length;
  return JSON.stringify({
    view: "plan",
    units: _toState.units.slice(0, unitLimit).map((unit) => serializePlanUnitForAi(unit)),
    links: _toState.links.slice(0, linkLimit).map((link) => ({
      parentId: link.parentId,
      childId: link.childId,
      parentName: getPlanUnitById(link.parentId)?.label || getPlanUnitById(link.parentId)?.designator || "",
      childName: getPlanUnitById(link.childId)?.label || getPlanUnitById(link.childId)?.designator || "",
    })),
  });
}

/* â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
   TOPOLOGY VIEW â€” Network Link Quality
â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â• */

function buildEmittersAiContext(options = {}) {
  const compact = options.compact !== false;
  const workspaceAssets = getEmitterWorkspaceAssets();
  const emitterLimit = compact ? 28 : workspaceAssets.length;
  const linkedCount = workspaceAssets.filter((asset) => Number.isFinite(Number(asset.toUnitId))).length;
  return JSON.stringify({
    view: "emitters",
    emitterCount: workspaceAssets.length,
    linkedCount,
    visibleCount: workspaceAssets.filter((asset) => !isContentEffectivelyHidden(`asset:${asset.id}`)).length,
    emitters: workspaceAssets.slice(0, emitterLimit).map((asset) => serializeAssetForAi(asset)),
  });
}

let _topoRefreshTimer = null;
function scheduleTopoRefresh(delayMs = 800) {
  clearTimeout(_topoRefreshTimer);
  _topoRefreshTimer = setTimeout(() => {
    if (state.ui?.currentView === "topology") renderTopologyView();
  }, delayMs);
}

async function renderTopologyView(options = {}) {
  try {
  _topoPendingFit = Boolean(options.fitView);
  const svg   = document.getElementById("topoSvg");
  const nodes = document.getElementById("topoNodes");
  const empty = document.getElementById("topoEmptyMsg");
  if (!svg || !nodes) return;

  syncTopologyToolbarUi();
  wireTopologyToolbarControls();

  // Only assets that have a frequencyMHz (i.e. are radio emitters)
  const radioEmitters = (state.assets || []).filter((a) => a.frequencyMHz > 0);
  const allEmitters = radioEmitters.filter((a) => isTopologyEmitterVisible(a));

  // Build a nameâ†’unitId lookup for fallback matching
  const unitByLabel = new Map(); // normalized label â†’ unit
  for (const u of (_toState.units || [])) {
    const key = (u.label || u.designator || "").trim().toUpperCase();
    if (key) unitByLabel.set(key, u);
  }

  // Build unitId â†’ [asset, asset, â€¦] (all emitters linked to that TO unit)
  // Falls back to name-based matching if toUnitId is not explicitly set.
  const unitEmittersMap = new Map(); // unitId â†’ asset[]
  function sortEmittersByFrequency(items = []) {
    return items.slice().sort((a, b) => {
      const freqDelta = (Number(a?.frequencyMHz) || 0) - (Number(b?.frequencyMHz) || 0);
      if (freqDelta !== 0) return freqDelta;
      const nameA = String(a?.emitterLabel || a?.name || "");
      const nameB = String(b?.emitterLabel || b?.name || "");
      return nameA.localeCompare(nameB);
    });
  }
  const resolvedEmitterRecords = [];
  for (const a of allEmitters) {
    let uid = Number.isFinite(Number(a?.toUnitId)) ? Number(a.toUnitId) : null;
    if (!uid) {
      // Try matching emitter name to a TO unit label
      const nameKey = (a.name || "").trim().toUpperCase();
      const matched = unitByLabel.get(nameKey);
      if (matched) uid = matched.id;
    }
    const unit = uid ? (_toState.units || []).find((u) => u.id === uid) || null : null;
    resolvedEmitterRecords.push({ asset: a, unitId: uid || null, unit });
    if (!uid) continue;
    if (!unitEmittersMap.has(uid)) unitEmittersMap.set(uid, []);
    unitEmittersMap.get(uid).push(a);
  }

  const linkedUnitIds = new Set(unitEmittersMap.keys());

  // â”€â”€ Hierarchy helpers â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  function getAncestors(unitId) {
    const ancestors = new Set();
    let cur = unitId;
    for (let depth = 0; depth < 20; depth++) {
      const link = _toState.links.find(l => l.childId === cur);
      if (!link) break;
      ancestors.add(link.parentId);
      cur = link.parentId;
    }
    return ancestors;
  }

  function getDescendants(unitId) {
    const desc = new Set();
    const queue = [unitId];
    while (queue.length) {
      const id = queue.shift();
      for (const l of _toState.links) {
        if (l.parentId === id && !desc.has(l.childId)) {
          desc.add(l.childId); queue.push(l.childId);
        }
      }
    }
    return desc;
  }

  function sameTree(idA, idB) {
    if (idA === idB) return true;
    if (getDescendants(idA).has(idB)) return true;
    if (getDescendants(idB).has(idA)) return true;
    const ancA = getAncestors(idA); ancA.add(idA);
    const ancB = getAncestors(idB); ancB.add(idB);
    for (const id of ancA) if (ancB.has(id)) return true;
    return false;
  }

  // â”€â”€ Nodes: unit cards or individual emitter cards â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  const displayMode = getTopologyDisplayMode();
  const toLinkedUnits = _toState.units.filter(u => linkedUnitIds.has(u.id));
  const standaloneEmitterEntries = resolvedEmitterRecords
    .filter((record) => !record.unitId)
    .map((record) => ({
      key: record.asset.id,
      kind: "emitter",
      unit: null,
      emitters: [record.asset],
      label: record.asset.emitterLabel || record.asset.name || "Emitter",
      sublabel: "Unlinked emitter",
    }));
  const posEntries = displayMode === "emitters"
    ? resolvedEmitterRecords
        .map((record) => ({
          key: record.asset.id,
          kind: "emitter",
          unit: record.unit,
          emitters: [record.asset],
          label: record.asset.emitterLabel || record.asset.name || "Emitter",
          sublabel: record.unit?.label || record.unit?.designator || "Unlinked emitter",
        }))
    : [
        ...toLinkedUnits.map((u) => ({
          key: u.id,
          kind: "unit",
          unit: u,
          label: u.label || u.designator || "Unit",
          emitters: sortEmittersByFrequency(unitEmittersMap.get(u.id) || []),
        })),
        ...standaloneEmitterEntries,
      ];

  if (!posEntries.length) {
    if (empty) {
      empty.innerHTML = radioEmitters.length && !allEmitters.length
        ? `<span>No emitters match this frequency filter.</span><span class="fine-print">Reset the band filter or enable another band to restore topology links.</span>`
        : `<span>No emitters placed on the map yet.</span><span class="fine-print">Place radio emitters in the MAP view to see topology links here.</span>`;
      empty.classList.remove("hidden");
    }
    svg.innerHTML = ""; nodes.innerHTML = "";
    return;
  }
  if (empty) empty.classList.add("hidden");

  // â”€â”€ Smart layout â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  // Card dimensions (approximate â€” cards are centered on their position point)
  const CARD_W = 184, CARD_H = 272, PAD_X = 240, PAD_Y = 180;
  const SLOT_W = CARD_W + PAD_X, SLOT_H = CARD_H + PAD_Y;
  const unitPos = new Map(); // key â†’ {x, y}  (visual center)
  const n = posEntries.length;

  function buildGridLayout(entries, startX = 260, startY = 220, colsHint = null) {
    const cols = colsHint || Math.max(1, Math.ceil(Math.sqrt(entries.length || 1)));
    entries.forEach((entry, index) => {
      const col = index % cols;
      const row = Math.floor(index / cols);
      unitPos.set(entry.key, {
        x: startX + col * SLOT_W,
        y: startY + row * SLOT_H,
      });
    });
  }

  if (n === 1) {
    // Single node â€” center of viewport
    unitPos.set(posEntries[0].key, { x: 400, y: 300 });

  } else if (n === 2) {
    // Side by side
    unitPos.set(posEntries[0].key, { x: 300, y: 300 });
    unitPos.set(posEntries[1].key, { x: 300 + SLOT_W, y: 300 });

  } else if (n <= 6) {
    // Circle arrangement â€” evenly spaced, top-first
    const R = Math.max(280, Math.max(SLOT_W, SLOT_H) * n / (2 * Math.PI) * 1.45);
    const cx = R + CARD_W, cy = R + CARD_H;
    posEntries.forEach((entry, i) => {
      const angle = (2 * Math.PI * i / n) - Math.PI / 2;
      unitPos.set(entry.key, { x: cx + R * Math.cos(angle), y: cy + R * Math.sin(angle) });
    });

  } else {
    // Grid layout â€” roughly square, left-to-right, top-to-bottom
    const cols = Math.ceil(Math.sqrt(n));
    posEntries.forEach((entry, i) => {
      const col = i % cols, row = Math.floor(i / cols);
      unitPos.set(entry.key, { x: CARD_W / 2 + PAD_X / 2 + col * SLOT_W, y: CARD_H / 2 + PAD_Y / 2 + row * SLOT_H });
    });
  }

  if (displayMode === "units") {
    unitPos.clear();
    const unitEntries = posEntries.filter((entry) => entry.kind === "unit");
    const standaloneEntries = posEntries.filter((entry) => entry.kind !== "unit");
    const visibleUnitIds = new Set(unitEntries.map((entry) => entry.key));
    const childSet = new Set();
    const childMap = new Map();

    for (const link of (_toState.links || [])) {
      if (!visibleUnitIds.has(link.parentId) || !visibleUnitIds.has(link.childId)) continue;
      childSet.add(link.childId);
      if (!childMap.has(link.parentId)) childMap.set(link.parentId, []);
      childMap.get(link.parentId).push(link.childId);
    }

    const roots = unitEntries
      .filter((entry) => !childSet.has(entry.key))
      .sort((a, b) => String(a.label || "").localeCompare(String(b.label || "")));

    if (unitEntries.length && roots.length && childSet.size) {
      const H_GAP = 420;
      const V_GAP = 340;
      const widthCache = new Map();

      function subtreeWidth(id) {
        if (widthCache.has(id)) return widthCache.get(id);
        const children = (childMap.get(id) || []).slice();
        if (!children.length) {
          widthCache.set(id, H_GAP);
          return H_GAP;
        }
        const width = Math.max(H_GAP, children.reduce((sum, childId) => sum + subtreeWidth(childId), 0));
        widthCache.set(id, width);
        return width;
      }

      function layoutSubtree(id, centerX, centerY) {
        unitPos.set(id, { x: centerX, y: centerY });
        const children = (childMap.get(id) || []).slice();
        if (!children.length) return;
        const totalWidth = children.reduce((sum, childId) => sum + subtreeWidth(childId), 0);
        let cursorX = centerX - totalWidth / 2;
        children.forEach((childId) => {
          const childWidth = subtreeWidth(childId);
          layoutSubtree(childId, cursorX + childWidth / 2, centerY + V_GAP);
          cursorX += childWidth;
        });
      }

      let cursorX = 260;
      const baseY = 180;
      roots.forEach((root) => {
        const rootWidth = subtreeWidth(root.key);
        layoutSubtree(root.key, cursorX + rootWidth / 2, baseY);
        cursorX += rootWidth;
      });
    } else if (unitEntries.length) {
      buildGridLayout(unitEntries, 300, 220, Math.min(3, Math.max(1, Math.ceil(Math.sqrt(unitEntries.length)))));
    }

    if (standaloneEntries.length) {
      const placedUnitPositions = [...unitPos.values()];
      const maxY = placedUnitPositions.length ? Math.max(...placedUnitPositions.map((pos) => pos.y)) : 0;
      const minX = placedUnitPositions.length ? Math.min(...placedUnitPositions.map((pos) => pos.x)) : 260;
      const standaloneStartY = maxY + CARD_H + 260;
      const standaloneColCount = Math.max(1, Math.ceil(Math.sqrt(standaloneEntries.length)));
      standaloneEntries.forEach((entry, index) => {
        const col = index % standaloneColCount;
        const row = Math.floor(index / standaloneColCount);
        unitPos.set(entry.key, {
          x: minX + col * SLOT_W,
          y: standaloneStartY + row * SLOT_H,
        });
      });
    }
  }
  if (options.resetLayout) {
    clearTopoStoredPositions(displayMode);
  }
  for (const entry of posEntries) {
    const stored = getTopoStoredPosition(displayMode, entry.key);
    if (stored) unitPos.set(entry.key, { x: stored.x, y: stored.y });
  }

  // â”€â”€ Candidate links: one per unique emitter-type pair between any two unit cards â”€â”€
  // Match on waveform bucket (waveform name, or frequency if no waveform).
  // SATCOM links match across any distance without freq equality requirement.
  const SATCOM_WF_SET = new Set(["MUOS","STARSHIELD","INMARSAT","VIASAT","BLOS","SATCOM","WGS","AEHF","LINK 182"]);
  function isSatcomEmitter(em) {
    return em.ext?.satcomEnabled ||
      SATCOM_WF_SET.has((em.ext?.waveform || "").toUpperCase());
  }
  function getEmitterChannelBandwidthKhz(em) {
    const explicitBandwidth = Number(em.bandwidthKHz ?? em.ext?.bandwidthKHz);
    if (Number.isFinite(explicitBandwidth) && explicitBandwidth > 0) {
      return explicitBandwidth;
    }
    const channelSpacing = Number(em.channelSpacingKHz ?? em.ext?.channelSpacingKHz);
    if (Number.isFinite(channelSpacing) && channelSpacing > 0) {
      return channelSpacing;
    }
    return 25;
  }
  function emittersChannelRangesOverlap(emA, emB) {
    const freqA = Number(emA.frequencyMHz);
    const freqB = Number(emB.frequencyMHz);
    if (!Number.isFinite(freqA) || !Number.isFinite(freqB) || freqA <= 0 || freqB <= 0) {
      return false;
    }
    const bwA = getEmitterChannelBandwidthKhz(emA) / 1000;
    const bwB = getEmitterChannelBandwidthKhz(emB) / 1000;
    const minA = freqA - (bwA / 2);
    const maxA = freqA + (bwA / 2);
    const minB = freqB - (bwB / 2);
    const maxB = freqB + (bwB / 2);
    return maxA >= minB && maxB >= minA;
  }
  function buildEmitterChannelBucket(em) {
    const freq = Number(em.frequencyMHz);
    const bw = getEmitterChannelBandwidthKhz(em);
    return `${Number.isFinite(freq) ? freq.toFixed(3) : "0.000"}:${bw.toFixed(3)}`;
  }

  const candidatePairs = []; // { a: entry, b: entry, emA: asset, emB: asset }
  const globalSeen = new Set(); // deduplicate across all pairs
  for (let i = 0; i < posEntries.length; i++) {
    for (let j = i + 1; j < posEntries.length; j++) {
      const nodeA = posEntries[i], nodeB = posEntries[j];
      for (const emA of nodeA.emitters) {
        for (const emB of nodeB.emitters) {
          const wfA = (emA.waveform || emA.ext?.waveform || "").toUpperCase();
          const wfB = (emB.waveform || emB.ext?.waveform || "").toUpperCase();
          const satA = isSatcomEmitter(emA), satB = isSatcomEmitter(emB);
          // Match by same radio model (emitterLabel) â€” strongest signal
          const labelA = (emA.emitterLabel || "").toUpperCase();
          const labelB = (emB.emitterLabel || "").toUpperCase();
          const sameModel = labelA && labelB && labelA === labelB;
          let bucket = null;
          if (satA !== satB) {
            continue;
          }
          if (satA && satB) {
            // SATCOM only matches SATCOM. Mixed SATCOM/LOS pairs are invalid.
            const wfCompat = !!wfA && !!wfB && wfA === wfB;
            if (!emittersChannelRangesOverlap(emA, emB)) {
              continue;
            }
            if (sameModel) bucket = `${labelA}@${buildEmitterChannelBucket(emA)}`;
            else if (wfCompat) bucket = `${wfA}@${buildEmitterChannelBucket(emA)}`;
          } else {
            // Non-SATCOM: require real channel overlap AND matching waveform.
            // Both must share the same waveform string (case-insensitive).
            // If both waveforms are empty (manual/custom), fall back to freq+model match.
            const waveformMatch = wfA && wfB ? wfA === wfB : (!wfA && !wfB);
            const channelOverlap = emittersChannelRangesOverlap(emA, emB);
            if (!channelOverlap || !waveformMatch) {
              continue;
            }
            if (sameModel) bucket = `${labelA}@${buildEmitterChannelBucket(emA)}`;
            else bucket = `${wfA || "freq"}@${buildEmitterChannelBucket(emA)}`;
          }
          if (!bucket) continue;
          const pairKey = `${nodeA.key}|${nodeB.key}|${emA.id || emA.name || "emA"}|${emB.id || emB.name || "emB"}|${bucket}`;
          if (globalSeen.has(pairKey)) continue;
          globalSeen.add(pairKey);
          candidatePairs.push({ a: nodeA, b: nodeB, emA, emB, pairKey });
        }
      }
    }
  }

  // Debug overlay
  { const dbg = ensureTopoDebugPanel()?.querySelector("#_topoDebug");
    if (dbg) {
    dbg.textContent = `Topo: ${posEntries.length} ${displayMode === "emitters" ? "emitters" : "units"}, ${candidatePairs.length} pairs\n` +
      posEntries.map(e => `  ${e.label || e.unit?.label || e.key}: ${e.emitters.map(em => `${em.emitterLabel||em.name}@${em.frequencyMHz}MHz wf=${em.ext?.waveform||"?"} satcom=${!!em.ext?.satcomEnabled}`).join(", ")}`).join("\n") +
      (candidatePairs.length ? "\nPairs:\n" + candidatePairs.map(p => `  ${(p.a.label || p.a.unit?.label || p.a.key)}â†”${(p.b.label || p.b.unit?.label || p.b.key)}: ${p.emA.emitterLabel||p.emA.name} / ${p.emB.emitterLabel||p.emB.name} [${p.pairKey.split("|")[2]}]`).join("\n") : "\n  NO PAIRS");
    }
  }

  // Assess link quality for all pairs in parallel
  const qualityResults = await Promise.all(
    candidatePairs.map((p) => {
      if (!hasAssetMapLocation(p.emA) || !hasAssetMapLocation(p.emB)) {
        return Promise.resolve(buildUnplacedLinkQuality(p.emA, p.emB));
      }
      return assessLinkQuality(p.emA, p.emB).catch(() => ({ score: 50, label: "Unknown", reasons: [], terrain: null }));
    })
  );
  const linkList = candidatePairs.map((p, idx) => ({ ...p, quality: qualityResults[idx] }));

  // â”€â”€ Populate position + descriptor maps â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  _topoNodePositions.clear();
  for (const [key, pos] of unitPos) _topoNodePositions.set(String(key), { ...pos });

  _topoLinkDescriptors = linkList.map(lnk => ({
    keyA: String(lnk.a.key),
    keyB: String(lnk.b.key),
    quality: lnk.quality,
    typeClass: linkTypeClass(lnk.emA, lnk.emB),
    nameA: lnk.a.label || lnk.a.unit?.label || lnk.emA.name || lnk.emA.id,
    nameB: lnk.b.label || lnk.b.unit?.label || lnk.emB.name || lnk.emB.id,
    emA: lnk.emA,
    emB: lnk.emB,
  }));

  // â”€â”€ Render node cards â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  const svgEl = nodes.querySelector(".topo-svg");
  nodes.innerHTML = "";
  if (svgEl) nodes.appendChild(svgEl);
  _topoNodeMeta.clear();

  for (const entry of posEntries) {
    const pos = unitPos.get(entry.key);
    if (!pos || !entry.emitters.length) continue;
    const unit = entry.unit;

    const nd = document.createElement("div");
    nd.className = "topo-node topo-node-card";
    nd.dataset.key = entry.key;
    nd.style.left = pos.x + "px";
    nd.style.top  = pos.y + "px";

    let iconHtml;
    if (entry.kind === "unit") {
      iconHtml = `<div class="topo-unit-icon-wrap">${renderToUnitIcon(unit)}</div>`;
    } else {
      const primaryAsset = entry.emitters[0];
      const graphicPath = resolveEmitterGraphicPath(primaryAsset);
      iconHtml = graphicPath
        ? `<div class="topo-generic-icon topo-graphic-icon"><img src="${graphicPath}" alt="${esc(primaryAsset.emitterLabel || primaryAsset.name || "Emitter")}"></div>`
        : `<div class="topo-generic-icon">${EMITTER_ICONS[primaryAsset.icon] || EMITTER_ICONS.radio}</div>`;
    }

    const unitNameHtml = `<div class="topo-unit-name">${esc(entry.label || unit?.label || unit?.designator || "Unit")}</div>`;
    const subLabelHtml = entry.kind === "emitter" && entry.sublabel
      ? `<div class="topo-unit-subname">${esc(entry.sublabel)}</div>`
      : "";

    // List each emitter sorted lowestâ†’highest freq: emitter label + waveform, then frequency
    const emitterListHtml = entry.emitters.map(em => {
      const radioName = em.emitterLabel || em.name || "Emitter";
      const wf = em.waveform || em.ext?.waveform || "";
      const freq = `${(em.frequencyMHz || 0).toFixed(3)} MHz`;
      const title = wf ? `${radioName} â€” ${wf}` : radioName;
      return `<div class="topo-em-row">
        <span class="topo-em-name">${esc(title)}</span>
        <span class="topo-em-detail">${esc(freq)}</span>
      </div>`;
    }).join("");

    nd.innerHTML = `
      <div class="topo-unit-card">
        ${iconHtml}
        ${unitNameHtml}
        ${subLabelHtml}
        <div class="topo-emitter-list">${emitterListHtml}</div>
      </div>
    `;

    _topoNodeMeta.set(String(entry.key), {
      type: entry.kind,
      unitId: unit?.id || null,
      label: entry.label || unit?.label || unit?.designator || "Node",
      emitters: entry.emitters.slice(),
    });
    nodes.appendChild(nd);
  }

  // â”€â”€ Draw links + wire interaction â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  wireTopoCanvasPanZoom();
  wireTopoNodeContextMenu();
  redrawTopoLinks();
  } catch (err) {
    console.error("[Topo] renderTopologyView error:", err);
  }
}

// â”€â”€ Topology node right-click context menu + radio popup â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
let _topoCtxAbort = null;

function wireTopoNodeContextMenu() {
  if (_topoCtxAbort) _topoCtxAbort.abort();
  _topoCtxAbort = new AbortController();
  const sig = _topoCtxAbort.signal;

  const ctxMenu   = document.getElementById("topoNodeCtxMenu");
  const ctxTitle  = document.getElementById("topoNodeCtxTitle");
  const ctxList   = document.getElementById("topoNodeCtxList");
  const radioPopup = document.getElementById("topoRadioPopup");
  const radioTitle = document.getElementById("topoRadioPopupTitle");
  const radioEditBtn = document.getElementById("topoRadioEditBtn");
  const radioAddNetBtn = document.getElementById("topoRadioAddNetBtn");
  const radioConfigureNetBtn = document.getElementById("topoRadioConfigureNetBtn");
  const radioDuplicateBtn = document.getElementById("topoRadioDuplicateBtn");
  const radioLinkBtn = document.getElementById("topoRadioLinkBtn");
  const radioUnlinkBtn = document.getElementById("topoRadioUnlinkBtn");
  const radioDeleteBtn = document.getElementById("topoRadioDeleteBtn");
  const radioLinkPanel = document.getElementById("topoRadioLinkPanel");
  const radioLinkList  = document.getElementById("topoRadioLinkList");
  if (!ctxMenu || !radioPopup) return;

  let _activeAsset = null;   // emitter asset the popup is for
  let _activeUnitId = null;  // unit the emitter belongs to

  function hideAll() {
    ctxMenu.classList.add("hidden");
    radioPopup.classList.add("hidden");
    radioLinkPanel.classList.add("hidden");
    radioLinkBtn.disabled = false;
    radioUnlinkBtn?.classList.add("hidden");
    _activeAsset = null;
    _activeUnitId = null;
  }

  function openRadioActionPopupForAsset(asset, unitId = null) {
    if (!asset) return;
    _activeAsset = asset;
    _activeUnitId = unitId;
    ctxMenu.classList.add("hidden");
    radioLinkPanel.classList.add("hidden");
    const label = _activeAsset.emitterLabel || _activeAsset.name || "Radio";
    const wf = _activeAsset.waveform || _activeAsset.ext?.waveform || "";
    radioTitle.textContent = wf ? `${label} â€” ${wf}` : label;
    radioLinkBtn.disabled = false;
    radioPopup.style.left = "50%";
    radioPopup.style.top = "50%";
    radioPopup.style.transform = "translate(-50%, -50%)";
    radioPopup.classList.remove("hidden");
  }

  function openTopoEmitterChooser(meta, clientX, clientY) {
    if (!meta?.emitters?.length) return;
    _activeUnitId = meta.unitId;
    const emitters = meta.emitters.slice();
    ctxTitle.textContent = meta.label || "Unit Emitters";
    ctxList.innerHTML = emitters.map((em, i) => {
      const label = em.emitterLabel || em.name || "Emitter";
      const wf = em.waveform || em.ext?.waveform || "";
      const freq = `${(em.frequencyMHz || 0).toFixed(3)} MHz`;
      const detail = [wf, freq].filter(Boolean).join(" · ");
      return `<div class="topo-node-ctx-item" data-idx="${i}">
        <div>
          <div class="topo-node-ctx-item-name">${esc(label)}</div>
          <div class="topo-node-ctx-item-detail">${esc(detail)}</div>
        </div>
      </div>`;
    }).join("");
    ctxList._emitters = emitters;
    ctxMenu.style.left = clientX + "px";
    ctxMenu.style.top = clientY + "px";
    ctxMenu.classList.remove("hidden");
    requestAnimationFrame(() => {
      const rect = ctxMenu.getBoundingClientRect();
      if (rect.right > window.innerWidth) ctxMenu.style.left = Math.max(8, clientX - rect.width) + "px";
      if (rect.bottom > window.innerHeight) ctxMenu.style.top = Math.max(8, clientY - rect.height) + "px";
    });
  }

  function handleTopoNodeContextMenu(e, nodeEl) {
    if (!nodeEl) {
      hideAll();
      return;
    }
    e.preventDefault();
    e.stopPropagation();
    hideAll();

    const meta = _topoNodeMeta.get(String(nodeEl.dataset.key));
    if (!meta?.emitters?.length) return;
    if (meta.type === "unit") {
      openTopoEmitterChooser(meta, e.clientX, e.clientY);
      return;
    }
    if (meta.emitters.length === 1) {
      openRadioActionPopupForAsset(meta.emitters[0], meta.unitId);
      return;
    }
    openTopoEmitterChooser(meta, e.clientX, e.clientY);
  }

  // Right-click on a topo node card
  document.getElementById("topoCanvas").addEventListener("contextmenu", (e) => {
    const nodeEl = e.target.closest(".topo-node");
    if (!nodeEl) { hideAll(); return; }
    e.preventDefault();
    e.stopPropagation();
    hideAll();

    const meta = _topoNodeMeta.get(String(nodeEl.dataset.key));
    if (!meta?.emitters?.length) return;
    if (meta.type === "unit") {
      openTopoEmitterChooser(meta, e.clientX, e.clientY);
      return;
    }
    _activeUnitId = meta.unitId;
    const emitters = meta.emitters.slice();

    if (emitters.length === 1) {
      openRadioActionPopupForAsset(emitters[0], meta.unitId);
      return;
    }

    ctxTitle.textContent = meta.label || "Unit Radios";
    ctxList.innerHTML = emitters.map((em, i) => {
      const label = em.emitterLabel || em.name || "Radio";
      const wf    = em.ext?.waveform || "";
      const freq  = `${(em.frequencyMHz || 0).toFixed(3)} MHz`;
      const detail = [wf, freq].filter(Boolean).join(" Â· ");
      return `<div class="topo-node-ctx-item" data-idx="${i}">
        <div>
          <div class="topo-node-ctx-item-name">${esc(label)}</div>
          <div class="topo-node-ctx-item-detail">${esc(detail)}</div>
        </div>
      </div>`;
    }).join("");

    // Store emitter array on the list for click handler
    ctxList._emitters = emitters;

    // Position near cursor but keep on screen
    ctxMenu.style.left = e.clientX + "px";
    ctxMenu.style.top  = e.clientY + "px";
    ctxMenu.classList.remove("hidden");
    requestAnimationFrame(() => {
      const rect = ctxMenu.getBoundingClientRect();
      if (rect.right > window.innerWidth)  ctxMenu.style.left = (e.clientX - rect.width)  + "px";
      if (rect.bottom > window.innerHeight) ctxMenu.style.top = (e.clientY - rect.height) + "px";
    });
  }, { signal: sig });

  // Click on an emitter row in context menu â†’ show radio popup
  document.querySelectorAll("#topoNodes .topo-node").forEach((nodeEl) => {
    nodeEl.addEventListener("contextmenu", (e) => {
      handleTopoNodeContextMenu(e, nodeEl);
    }, { signal: sig });
  });

  ctxList.addEventListener("click", (e) => {
    const item = e.target.closest(".topo-node-ctx-item");
    if (!item) return;
    const idx = parseInt(item.dataset.idx, 10);
    const asset = ctxList._emitters?.[idx];
    if (!asset) return;
    openRadioActionPopupForAsset(asset, _activeUnitId);
    return;

    ctxMenu.classList.add("hidden");
    radioLinkPanel.classList.add("hidden");

    const label = _activeAsset.emitterLabel || _activeAsset.name || "Radio";
    const wf    = _activeAsset.ext?.waveform || "";
      radioTitle.textContent = wf ? `${label} â€” ${wf}` : label;
      radioLinkBtn.disabled = false;

    // Position popup near center of screen
    radioPopup.style.left = "50%";
    radioPopup.style.top  = "50%";
    radioPopup.style.transform = "translate(-50%, -50%)";
    radioPopup.classList.remove("hidden");
  }, { signal: sig });

  // Close button
  document.getElementById("topoRadioPopupClose")?.addEventListener("click", hideAll, { signal: sig });

  // Edit Radio â†’ open the existing emitter modal
  radioEditBtn.addEventListener("click", () => {
    if (!_activeAsset) return;
    const assetId = _activeAsset.id;
    const assetName = _activeAsset.name || _activeAsset.emitterLabel || "Emitter";
    hideAll();
    setAssetPlacementMode(false);
    openEmitterEditorById(assetId);
    refreshActionButtons();
    setStatus(`Editing ${assetName}.`);
  }, { signal: sig });

  // Link to Unit Radio â†’ show unit/radio picker
  radioAddNetBtn?.addEventListener("click", () => {
    if (!_activeAsset) return;
    const assetId = _activeAsset.id;
    hideAll();
    openEmittersNetModal(assetId, "", { createNew: true });
  }, { signal: sig });

  radioConfigureNetBtn?.addEventListener("click", () => {
    if (!_activeAsset) return;
    const assetId = _activeAsset.id;
    const firstNet = getEmitterNets(_activeAsset)[0] || null;
    hideAll();
    openEmittersNetModal(assetId, firstNet?.id || "", { createNew: !firstNet });
  }, { signal: sig });

  radioDuplicateBtn?.addEventListener("click", () => {
    if (!_activeAsset) return;
    const assetId = _activeAsset.id;
    hideAll();
    duplicateEmitterAssetById(assetId);
  }, { signal: sig });

  radioUnlinkBtn?.addEventListener("click", () => {
    if (!_activeAsset) return;
    const assetId = _activeAsset.id;
    hideAll();
    unlinkEmitterAssetById(assetId);
  }, { signal: sig });

  radioDeleteBtn?.addEventListener("click", () => {
    if (!_activeAsset) return;
    const assetId = _activeAsset.id;
    const assetName = _activeAsset.name || _activeAsset.emitterLabel || "this emitter";
    if (!window.confirm(`Delete ${assetName}?`)) return;
    hideAll();
    deleteEmitterAssetById(assetId);
  }, { signal: sig });

  radioLinkBtn.addEventListener("click", () => {
    if (!_activeAsset) return;
    const assetId = _activeAsset.id;
    hideAll();
    openEmitterToUnitPickerById(assetId);
    return;

    // Collect all units in same TO hierarchy tree
    function getAncestors(uid) {
      const anc = new Set();
      let cur = uid;
      for (let d = 0; d < 20; d++) {
        const lnk = (_toState.links || []).find(l => l.childId === cur);
        if (!lnk) break;
        anc.add(lnk.parentId);
        cur = lnk.parentId;
      }
      return anc;
    }
    function getDescendants(uid) {
      const desc = new Set();
      const q = [uid];
      while (q.length) {
        const id = q.shift();
        for (const l of (_toState.links || [])) {
          if (l.parentId === id && !desc.has(l.childId)) { desc.add(l.childId); q.push(l.childId); }
        }
      }
      return desc;
    }
    const anc = getAncestors(_activeUnitId);
    anc.add(_activeUnitId);
    const desc = getDescendants(_activeUnitId);
    const treeIds = new Set([...anc, ...desc]);
    // Remove self â€” can't link to own unit
    treeIds.delete(_activeUnitId);

    // Build list of units + their emitters
    const treeUnits = (_toState.units || []).filter(u => treeIds.has(u.id));
    if (!treeUnits.length) {
      radioLinkList.innerHTML = `<div style="color:var(--text-muted);font-size:0.78rem;padding:4px 0">No other units in this hierarchy tree.</div>`;
      return;
    }

    treeUnits.forEach(unit => {
      const unitEmitters = (state.assets || []).filter(a => {
        if (a.toUnitId === unit.id) return true;
        const nk = (a.name || "").trim().toUpperCase();
        const uk = (unit.label || unit.designator || "").trim().toUpperCase();
        return nk === uk;
      });
      if (!unitEmitters.length) return;

      const unitHdr = document.createElement("div");
      unitHdr.className = "topo-radio-link-unit";
      unitHdr.textContent = unit.label || unit.designator || "Unit";
      radioLinkList.appendChild(unitHdr);

      unitEmitters.forEach(sourceEm => {
        const label = sourceEm.emitterLabel || sourceEm.name || "Radio";
        const wf    = sourceEm.ext?.waveform || "";
        const freq  = `${(sourceEm.frequencyMHz || 0).toFixed(3)} MHz`;
        const detail = [wf, freq].filter(Boolean).join(" Â· ");

        const row = document.createElement("div");
        row.className = "topo-radio-link-row";
        row.innerHTML = `<span class="topo-radio-link-row-name">${esc(label)}</span>
                         <span class="topo-radio-link-row-detail">${esc(detail)}</span>`;
        row.addEventListener("click", () => {
          cloneRadioConfig(sourceEm, _activeAsset);
          hideAll();
          scheduleTopoRefresh(200);
        });
        radioLinkList.appendChild(row);
      });
    });
  }, { signal: sig });

  // Click outside â†’ close everything
  document.addEventListener("click", (e) => {
    if (!ctxMenu.classList.contains("hidden") && !ctxMenu.contains(e.target)) ctxMenu.classList.add("hidden");
    if (!radioPopup.classList.contains("hidden") && !radioPopup.contains(e.target)) hideAll();
  }, { signal: sig });
}

// Clone RF config from sourceEmitter onto targetEmitter, preserving name/location
function cloneRadioConfig(source, target) {
  const preserve = {
    id: target.id,
    name: target.name,
    lat: target.lat,
    lon: target.lon,
    groundElevationM: target.groundElevationM,
    toUnitId: target.toUnitId,
    unit: target.unit,
    version: (target.version ?? 1) + 1,
    lastModified: (typeof nowIso === "function" ? nowIso() : new Date().toISOString()),
  };

  // Copy all RF fields from source
  Object.assign(target, {
    frequencyMHz: source.frequencyMHz,
    bandwidthKHz: source.bandwidthKHz,
    waveform: source.waveform,
    modulation: source.modulation,
    duplex: source.duplex,
    channelSpacingKHz: source.channelSpacingKHz,
    powerW: source.powerW,
    dutyCycle: source.dutyCycle,
    papr: source.papr,
    spectralEfficiency: source.spectralEfficiency,
    antennaHeightM: source.antennaHeightM,
    antennaGainDbi: source.antennaGainDbi,
    antennaType: source.antennaType,
    radPattern: source.radPattern,
    polarization: source.polarization,
    cableLossDb: source.cableLossDb,
    receiverSensitivityDbm: source.receiverSensitivityDbm,
    noiseFigDb: source.noiseFigDb,
    requiredSnrDb: source.requiredSnrDb,
    acrDb: source.acrDb,
    bdrDb: source.bdrDb,
    systemLossDb: source.systemLossDb,
    propModel: source.propModel,
    clutterType: source.clutterType,
    terrainEnabled: source.terrainEnabled,
    diffractionEnabled: source.diffractionEnabled,
    nvisEnabled: source.nvisEnabled,
    ionoModel: source.ionoModel,
    timeDayEffects: source.timeDayEffects,
    solarIndex: source.solarIndex,
    isManet: source.isManet,
    relayCapable: source.relayCapable,
    maxHops: source.maxHops,
    latencyMs: source.latencyMs,
    adaptiveDataRate: source.adaptiveDataRate,
    satcomEnabled: source.satcomEnabled,
    satType: source.satType,
    satUplinkMHz: source.satUplinkMHz,
    satDownlinkMHz: source.satDownlinkMHz,
    satGainDbi: source.satGainDbi,
    emitterLabel: source.emitterLabel,
    type: source.type,
    icon: source.icon,
    color: source.color,
    profileId: source.profileId || "",
    profileName: source.profileName || "",
    profileVersion: source.profileVersion || null,
    ext: source.ext ? JSON.parse(JSON.stringify(source.ext)) : {},
  });

  // Restore identity fields
  Object.assign(target, preserve);

  updateAssetMarker(target);
  saveMapState();
  setStatus(`Cloned ${source.emitterLabel || source.name} config onto ${target.name}.`);
}

async function assessLinkQualityLegacyOld(a, b) {
  let score = 100;
  const reasons = [];

  // Frequency band check (assets store frequencyMHz; convert to Hz for freqBand)
  const freqA = (a.frequencyMHz || 0) * 1e6;
  const freqB = (b.frequencyMHz || 0) * 1e6;
  const fMhz  = ((a.frequencyMHz || 0) + (b.frequencyMHz || 0)) / 2 || 100;
  const bandA = freqBand(freqA);
  const bandB = freqBand(freqB);
  if (bandA !== bandB) {
    score -= 60;
    reasons.push(`Different frequency bands (${bandA} vs ${bandB}) â€” cross-band communication requires bridging equipment.`);
  } else {
    reasons.push(`Same frequency band (${bandA}) â€” compatible radios.`);
  }

  // Net ID match
  const netA = a.netId || a.net_id || null;
  const netB = b.netId || b.net_id || null;
  if (netA && netB) {
    if (netA === netB) { score += 10; reasons.push(`Matching Net ID (${netA}) â€” same radio net.`); }
    else { score -= 20; reasons.push(`Different Net IDs (${netA} vs ${netB}) â€” separate nets.`); }
  }

  // Waveform match (stored in asset.ext.waveform)
  const wfA = (a.ext?.waveform || a.waveform || "").toUpperCase();
  const wfB = (b.ext?.waveform || b.waveform || "").toUpperCase();
  if (wfA && wfB) {
    if (wfA === wfB) reasons.push(`Matching waveform (${wfA}).`);
    else { score -= 25; reasons.push(`Waveform mismatch (${wfA} vs ${wfB}) â€” cannot communicate without a gateway.`); }
  }

  // SATCOM/BLOS waveforms bypass terrain and distance limits
  const SATCOM_WF = ["MUOS", "STARSHIELD", "INMARSAT", "VIASAT", "BLOS", "SATCOM", "WGS", "AEHF", "LINK 182"];
  const isSatcom = SATCOM_WF.includes(wfA) || SATCOM_WF.includes(wfB)
    || a.ext?.satcomEnabled || b.ext?.satcomEnabled;
  if (isSatcom) {
    reasons.push("SATCOM/BLOS waveform â€” range is not terrain-limited.");
    score = Math.max(0, Math.min(100, score));
    const label = score >= 80 ? "Excellent" : score >= 60 ? "Good" : score >= 40 ? "Fair" : score >= 20 ? "Poor" : "No Link";
    return { score, label, reasons, terrain: null };
  }

  // â”€â”€ Propagation + terrain (requires lat/lon) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  if (!(a.lat && a.lon && b.lat && b.lon)) {
    score = Math.max(0, Math.min(100, score));
    const label = score >= 80 ? "Excellent" : score >= 60 ? "Good" : score >= 40 ? "Fair" : score >= 20 ? "Poor" : "No Link";
    return { score, label, reasons, terrain: null };
  }

  const distKm = haversineKm(a.lat, a.lon, b.lat, b.lon);
  const distM  = distKm * 1000;

  // Free-space path loss (using fsplDb which expects MHz and meters)
  const fspl = fsplDb(fMhz, Math.max(distM, 1));

  // Transmitter link budget
  const txPowerW   = a.powerW || 5;
  const txGainDbi  = a.antennaGainDbi ?? 2.15;
  const sysLossDb  = (a.systemLossDb ?? 3) + (b.systemLossDb ?? 3);
  const rxSensDbm  = b.receiverSensitivityDbm || -107;
  const eirpDbm    = wattsToDbm(txPowerW) + txGainDbi;

  // â”€â”€ Terrain LOS via Cesium (async, cached) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  const h1 = a.antennaHeightM ?? 2;
  const h2 = b.antennaHeightM ?? 2;
  const los = await computeTerrainLosAsync(a.lat, a.lon, h1, b.lat, b.lon, h2);

  let diffractionDb = 0;
  if (los.hasTerrain) {
    if (los.blocked && los.minClearanceM < 0) {
      // Knife-edge diffraction penalty (ITU-R P.526)
      const obstrM = Math.abs(los.minClearanceM);
      const wavelengthM = 300 / Math.max(fMhz, 0.1);
      const v = obstrM * Math.sqrt((2 / wavelengthM) * (2 / Math.max(distM, 1)));
      diffractionDb = v <= -0.78 ? 0
        : 6.9 + 20 * Math.log10(Math.sqrt((v - 0.1) ** 2 + 1) + v - 0.1);
      diffractionDb = Math.min(diffractionDb, 40); // cap at 40 dB

      const src = los.source === "hybrid" ? "local terrain + Cesium" : los.source === "cesium" ? "Cesium terrain" : "DTED";
      score -= diffractionDb >= 30 ? 50 : diffractionDb >= 15 ? 30 : 15;
      reasons.push(
        `Terrain BLOCKED (${src}): LOS obstructed by ${obstrM.toFixed(0)} m. ` +
        `Knife-edge diffraction penalty: ${diffractionDb.toFixed(1)} dB. ` +
        (los.obstructionLat ? `Worst obstruction ~${(los.obstructionFrac * distKm).toFixed(1)} km from TX.` : "")
      );
    } else {
      const src = los.source === "hybrid" ? "local terrain + Cesium" : los.source === "cesium" ? "Cesium terrain" : "DTED";
      const clr = Number.isFinite(los.minClearanceM) ? `${los.minClearanceM.toFixed(0)} m clearance` : "clear";
      reasons.push(`Terrain LOS clear (${src}): ${clr}.`);
    }
  } else {
    reasons.push("No terrain data available â€” terrain effects not modelled.");
  }

  // RSSI estimate including diffraction
  const totalLossDb = fspl + diffractionDb + sysLossDb;
  const rssiDbm = eirpDbm - totalLossDb;
  const marginDb = rssiDbm - rxSensDbm;

  if (marginDb < 0) {
    score -= Math.min(50, Math.abs(marginDb) * 2);
    reasons.push(
      `Estimated RSSI ${rssiDbm.toFixed(0)} dBm at ${distKm.toFixed(1)} km â€” ` +
      `${Math.abs(marginDb).toFixed(0)} dB below receiver sensitivity (${rxSensDbm} dBm). Link likely unusable.`
    );
  } else if (marginDb < 10) {
    score -= 20;
    reasons.push(
      `Estimated RSSI ${rssiDbm.toFixed(0)} dBm at ${distKm.toFixed(1)} km â€” ` +
      `only ${marginDb.toFixed(0)} dB margin above sensitivity. Marginal reliability.`
    );
  } else if (marginDb < 20) {
    score -= 10;
    reasons.push(
      `Estimated RSSI ${rssiDbm.toFixed(0)} dBm at ${distKm.toFixed(1)} km â€” ` +
      `${marginDb.toFixed(0)} dB margin. Adequate but limited fade tolerance.`
    );
  } else {
    reasons.push(
      `Estimated RSSI ${rssiDbm.toFixed(0)} dBm at ${distKm.toFixed(1)} km â€” ` +
      `${marginDb.toFixed(0)} dB margin above sensitivity. Good link budget.`
    );
  }

  score = Math.max(0, Math.min(100, score));
  const label = score >= 80 ? "Excellent" : score >= 60 ? "Good" : score >= 40 ? "Fair" : score >= 20 ? "Poor" : "No Link";
  return { score, label, reasons, terrain: los.hasTerrain ? los : null, rssiDbm, marginDb, distKm };
}

function freqBand(hz) {
  const mhz = hz / 1e6;
  if (mhz < 3)    return "HF-Low";
  if (mhz < 30)   return "HF";
  if (mhz < 300)  return "VHF";
  if (mhz < 3000) return "UHF";
  if (mhz < 30000)return "SHF";
  return "EHF";
}

function linkQualityClassLegacy(score) {
  if (score >= 80) return "topo-link-excellent";
  if (score >= 60) return "topo-link-good";
  if (score >= 40) return "topo-link-fair";
  if (score >= 20) return "topo-link-poor";
  return "topo-link-none";
}

function linkQualityLabel(score) {
  if (score >= 85) return "Excellent";
  if (score >= 65) return "Good";
  if (score >= 45) return "Moderate";
  if (score >= 20) return "Poor";
  return "No Link";
}

function lerpColorHex(a, b, t) {
  const aa = a.replace("#", "");
  const bb = b.replace("#", "");
  const ar = parseInt(aa.slice(0, 2), 16);
  const ag = parseInt(aa.slice(2, 4), 16);
  const ab = parseInt(aa.slice(4, 6), 16);
  const br = parseInt(bb.slice(0, 2), 16);
  const bg = parseInt(bb.slice(2, 4), 16);
  const bbv = parseInt(bb.slice(4, 6), 16);
  const mix = (x, y) => Math.round(x + (y - x) * t).toString(16).padStart(2, "0");
  return `#${mix(ar, br)}${mix(ag, bg)}${mix(ab, bbv)}`;
}

function linkQualityColor(score) {
  const s = Math.max(0, Math.min(100, Number(score) || 0));
  if (s <= 20) return lerpColorHex("#ef4444", "#f97316", s / 20);
  if (s <= 45) return lerpColorHex("#f97316", "#facc15", (s - 20) / 25);
  return lerpColorHex("#facc15", "#22c55e", (s - 45) / 55);
}

function linkQualityClass(score) {
  if (score >= 85) return "topo-link-excellent";
  if (score >= 65) return "topo-link-good";
  if (score >= 45) return "topo-link-fair";
  if (score >= 20) return "topo-link-poor";
  return "topo-link-none";
}

function isUnplacedLinkQuality(quality) {
  return !!quality?.notPlaced;
}

function resolvedLinkQualityClass(quality) {
  if (isUnplacedLinkQuality(quality)) return "topo-link-unplaced";
  return linkQualityClass(quality?.score);
}

function resolvedLinkQualityColor(quality) {
  if (isUnplacedLinkQuality(quality)) return "#94a3b8";
  return linkQualityColor(quality?.score);
}

function buildUnplacedLinkQuality(a, b) {
  const reasons = [];
  const missing = [];
  if (!hasAssetMapLocation(a)) missing.push(a?.emitterLabel || a?.name || "Emitter A");
  if (!hasAssetMapLocation(b)) missing.push(b?.emitterLabel || b?.name || "Emitter B");
  reasons.push("RF settings align closely enough that these emitters would link once they are placed on the map.");
  if (missing.length === 1) {
    reasons.push(`${missing[0]} is not placed on the map yet, so terrain, distance, and line-of-sight cannot be assessed.`);
  } else {
    reasons.push("Neither emitter is placed on the map yet, so terrain, distance, and line-of-sight cannot be assessed.");
  }
  reasons.push("Place the emitter on the map to turn this into an assessed RF link.");
  return {
    score: 50,
    label: "Not Placed",
    reasons,
    terrain: null,
    distKm: null,
    rssiDbm: null,
    marginDb: null,
    forwardRssiDbm: null,
    reverseRssiDbm: null,
    forwardMarginDb: null,
    reverseMarginDb: null,
    notPlaced: true,
  };
}

function topologyAtmosphericAttenuation(freqMHz, weather, distanceKm) {
  const freqGHz = Math.max(Number(freqMHz) || 1, 1) / 1000;
  const humidity = clamp(Number(weather?.humidity) || 0, 0, 100) / 100;
  const pressureFactor = Math.max(Number(weather?.pressureHpa) || 1013.25, 850) / 1013.25;
  const tempK = Math.max((Number(weather?.temperatureC) || 20) + 273.15, 200);
  const tempFactor = 293.15 / tempK;
  const windNoise = Math.max(Number(weather?.windSpeedMps) || 0, 0) * 0.002;
  const oxygenLoss = freqGHz * 0.012 * pressureFactor;
  const waterVaporLoss = freqGHz * humidity * 0.18 * tempFactor;
  return Math.max(0, (oxygenLoss + waterVaporLoss + windNoise) * Math.max(Number(distanceKm) || 0, 0));
}

async function assessLinkQuality(a, b) {
  let score = 100;
  const reasons = [];
  const freqMHzA = Number(a.frequencyMHz) || 0;
  const freqMHzB = Number(b.frequencyMHz) || 0;
  const fMhz = (freqMHzA > 0 && freqMHzB > 0) ? (freqMHzA + freqMHzB) / 2 : Math.max(freqMHzA, freqMHzB, 100);
  const bandA = freqBand(freqMHzA * 1e6);
  const bandB = freqBand(freqMHzB * 1e6);
  const wfA = (a.ext?.waveform || a.waveform || "").toUpperCase();
  const wfB = (b.ext?.waveform || b.waveform || "").toUpperCase();
  const netA = a.netId || a.net_id || null;
  const netB = b.netId || b.net_id || null;
  const bwA = Number(a.bandwidthKHz ?? a.ext?.bandwidthKHz) || 25;
  const bwB = Number(b.bandwidthKHz ?? b.ext?.bandwidthKHz) || 25;
  const h1 = Number.isFinite(a.antennaHeightM) ? a.antennaHeightM : 2;
  const h2 = Number.isFinite(b.antennaHeightM) ? b.antennaHeightM : 2;
  const deltaMHz = Math.abs(freqMHzA - freqMHzB);
  const channelTolMHz = Math.max(0.025, Math.max(bwA, bwB) / 1000);
  const SATCOM_WF = ["MUOS", "STARSHIELD", "INMARSAT", "VIASAT", "BLOS", "SATCOM", "WGS", "AEHF", "LINK 182"];
  const MANET_WF = ["SRW", "ANW2", "WAVE", "MESH", "MANET", "WIFI", "802.11", "TRELLISWARE", "MN-MIMO"];
  const isSatcom = SATCOM_WF.some((wf) => wfA.includes(wf) || wfB.includes(wf))
    || a.ext?.satcomEnabled || b.ext?.satcomEnabled;
  const isMesh = MANET_WF.some((wf) => wfA.includes(wf) || wfB.includes(wf))
    || a.ext?.isManet || b.ext?.isManet || a.net?.isManet || b.net?.isManet;
  const isUhfLike = !isSatcom && fMhz >= 300;
  const isVhfLike = !isSatcom && fMhz >= 30 && fMhz < 300;
  const isHfLike = !isSatcom && fMhz >= 3 && fMhz < 30;

  if (bandA !== bandB) {
    score -= 55;
    reasons.push(`Different frequency bands (${bandA} vs ${bandB}) â€” direct comms are unlikely without a gateway.`);
  } else {
    reasons.push(`Same frequency band (${bandA}) â€” radios are operating in a compatible band.`);
  }

  if (wfA && wfB) {
    if (wfA === wfB) reasons.push(`Matching waveform (${wfA}).`);
    else {
      score -= 35;
      reasons.push(`Waveform mismatch (${wfA} vs ${wfB}) â€” incompatible air interface without a bridge.`);
    }
  }

  if (netA && netB) {
    if (netA === netB) {
      score += 6;
      reasons.push(`Matching Net ID (${netA}) â€” same logical net.`);
    } else {
      score -= 12;
      reasons.push(`Different Net IDs (${netA} vs ${netB}) â€” separate configured nets.`);
    }
  }

  if (!isSatcom) {
    if (deltaMHz > channelTolMHz) {
      score -= 45;
      reasons.push(`Frequency separation ${deltaMHz.toFixed(3)} MHz exceeds channel tolerance (${channelTolMHz.toFixed(3)} MHz).`);
    } else if (deltaMHz > 0.001) {
      score -= 4;
      reasons.push(`Small frequency offset (${deltaMHz.toFixed(3)} MHz) reduces tuning overlap.`);
    } else {
      reasons.push(`Frequency alignment is tight (${freqMHzA.toFixed(3)} / ${freqMHzB.toFixed(3)} MHz).`);
    }
  } else {
    reasons.push("SATCOM/BLOS path detected â€” surface distance and horizontal terrain mask are not the primary limiters.");
  }

  if (!(a.lat && a.lon && b.lat && b.lon)) {
    score = Math.max(0, Math.min(100, score));
    return {
      score,
      label: linkQualityLabel(score),
      reasons,
      terrain: null,
      isSatcom,
      forwardRssiDbm: null,
      reverseRssiDbm: null,
      forwardMarginDb: null,
      reverseMarginDb: null,
    };
  }

  const distKm = haversineKm(a.lat, a.lon, b.lat, b.lon);
  const distM = Math.max(distKm * 1000, 1);
  const fspl = fsplDb(fMhz, distM);
  const radioHorizonKm = 3.57 * (Math.sqrt(Math.max(h1, 0)) + Math.sqrt(Math.max(h2, 0)));
  let los = { hasTerrain: false };
  let terrainPenaltyDb = 0;
  let horizonPenaltyDb = 0;
  let severeBlockedLos = false;
  const weatherDistanceKm = isSatcom ? Math.max(8, Math.min(25, distKm)) : distKm;
  const weatherLossDb = topologyAtmosphericAttenuation(fMhz, state.weather, weatherDistanceKm);

  if (!isSatcom) {
    los = await computeTerrainLosAsync(a.lat, a.lon, h1, b.lat, b.lon, h2);
    if (los.hasTerrain) {
      if (los.blocked && los.minClearanceM < 0) {
        const obstructionM = Math.abs(los.minClearanceM);
        const obstructionFrac = clamp(Number(los.obstructionFrac) || 0.5, 0.05, 0.95);
        const d1 = Math.max(distM * obstructionFrac, 1);
        const d2 = Math.max(distM - d1, 1);
        const wavelengthM = 300 / Math.max(fMhz, 0.1);
        const fresnelRadiusM = Math.sqrt(Math.max((wavelengthM * d1 * d2) / (d1 + d2), 0));
        const fresnelIntrusion = fresnelRadiusM > 0 ? obstructionM / fresnelRadiusM : 0;
        const v = obstructionM * Math.sqrt((2 * (d1 + d2)) / Math.max(wavelengthM * d1 * d2, 1e-9));
        const knifeEdgeLossDb = v <= -0.78 ? 0 : 6.9 + 20 * Math.log10(Math.sqrt((v - 0.1) ** 2 + 1) + v - 0.1);
        let blockedExtraLossDb = 0;
        let blockedScorePenalty = 0;
        if (isMesh) {
          blockedExtraLossDb = 24 + Math.max(0, fresnelIntrusion - 0.15) * 18;
          blockedScorePenalty = 40;
        } else if (isUhfLike) {
          blockedExtraLossDb = 18 + Math.max(0, fresnelIntrusion - 0.2) * 14;
          blockedScorePenalty = 32;
        } else if (isVhfLike) {
          blockedExtraLossDb = 10 + Math.max(0, fresnelIntrusion - 0.3) * 10;
          blockedScorePenalty = 24;
        } else if (isHfLike) {
          blockedExtraLossDb = 3 + Math.max(0, fresnelIntrusion - 0.5) * 4;
          blockedScorePenalty = 8;
        } else {
          blockedExtraLossDb = 8 + Math.max(0, fresnelIntrusion - 0.3) * 8;
          blockedScorePenalty = 16;
        }
        terrainPenaltyDb = Math.min(knifeEdgeLossDb + blockedExtraLossDb, isMesh ? 90 : isUhfLike ? 78 : isVhfLike ? 62 : 45);
        score -= blockedScorePenalty + (fresnelIntrusion >= 1 ? 14 : fresnelIntrusion >= 0.6 ? 9 : 5);
        severeBlockedLos = (isMesh && (obstructionM >= 25 || fresnelIntrusion >= 1.0 || terrainPenaltyDb >= 40))
          || (isUhfLike && (obstructionM >= 60 || fresnelIntrusion >= 1.15 || terrainPenaltyDb >= 36))
          || (isVhfLike && (obstructionM >= 120 || fresnelIntrusion >= 1.6 || terrainPenaltyDb >= 32));
        if (severeBlockedLos) {
          terrainPenaltyDb = Math.max(terrainPenaltyDb, isMesh ? 110 : isUhfLike ? 95 : 82);
          score = Math.min(score, 6);
          reasons.push("Terrain blockage is severe enough that this ground link should be treated as effectively non-viable, not merely degraded.");
        }
        reasons.push(`Terrain blocked (${los.source === "hybrid" ? "local terrain + Cesium" : los.source === "cesium" ? "Cesium terrain" : "DTED"}): ${obstructionM.toFixed(0)} m obstruction, ${fresnelRadiusM.toFixed(1)} m Fresnel radius, ~${terrainPenaltyDb.toFixed(1)} dB excess loss.`);
      } else {
        const clr = Number.isFinite(los.minClearanceM) ? `${los.minClearanceM.toFixed(0)} m clearance` : "clear";
        reasons.push(`Terrain LOS clear (${los.source === "hybrid" ? "local terrain + Cesium" : los.source === "cesium" ? "Cesium terrain" : "DTED"}): ${clr}.`);
      }
    } else {
      reasons.push("No terrain data available â€” terrain effects omitted from the estimate.");
    }

    if (distKm > radioHorizonKm) {
      const overHorizonKm = distKm - radioHorizonKm;
      const horizonScale = isMesh ? 4 : isUhfLike ? 3 : isVhfLike ? 2.1 : 1.2;
      const horizonCap = isMesh ? 58 : isUhfLike ? 48 : isVhfLike ? 38 : 26;
      const scorePenalty = Math.min(horizonCap, (isMesh ? 18 : isUhfLike ? 14 : isVhfLike ? 10 : 8) + overHorizonKm * horizonScale);
      horizonPenaltyDb = Math.min(horizonCap, (isMesh ? 12 : isUhfLike ? 9 : isVhfLike ? 6 : 3) + overHorizonKm * (horizonScale * 0.8));
      score -= scorePenalty;
      reasons.push(`Path length ${distKm.toFixed(1)} km exceeds radio horizon ${radioHorizonKm.toFixed(1)} km by ${overHorizonKm.toFixed(1)} km.`);
    } else {
      reasons.push(`Path length ${distKm.toFixed(1)} km remains inside the nominal radio horizon (${radioHorizonKm.toFixed(1)} km).`);
    }
  }

  if (weatherLossDb > 0.2) {
    score -= Math.min(12, weatherLossDb * (isSatcom ? 0.75 : 1.2));
    reasons.push(`Weather profile (${state.weather.source === "open-meteo" ? "live stream" : "manual"}) adds ~${weatherLossDb.toFixed(1)} dB atmospheric loss.`);
  } else {
    reasons.push(`Weather profile (${state.weather.source === "open-meteo" ? "live stream" : "manual"}) adds negligible atmospheric loss.`);
  }

  function estimateOneWayBudget(tx, rx) {
    const txPowerW = Math.max(Number(tx.powerW) || 0, 0.1);
    const txGainDbi = Number.isFinite(tx.antennaGainDbi) ? tx.antennaGainDbi : 2.15;
    const rxGainDbi = Number.isFinite(rx.antennaGainDbi) ? rx.antennaGainDbi : 2.15;
    const txLossDb = Number.isFinite(tx.systemLossDb) ? tx.systemLossDb : 3;
    const rxLossDb = Number.isFinite(rx.systemLossDb) ? rx.systemLossDb : 3;
    const rxSensDbm = Number.isFinite(rx.receiverSensitivityDbm) ? rx.receiverSensitivityDbm : -107;
    const eirpDbm = wattsToDbm(txPowerW) + txGainDbi - txLossDb;
    const pathLossDb = (isSatcom ? 0 : fspl + terrainPenaltyDb + horizonPenaltyDb) + weatherLossDb;
    const rssiDbm = eirpDbm + rxGainDbi - pathLossDb - rxLossDb;
    const marginDb = rssiDbm - rxSensDbm;
    return { eirpDbm, rssiDbm, marginDb, rxSensDbm, pathLossDb };
  }

  const ab = estimateOneWayBudget(a, b);
  const ba = estimateOneWayBudget(b, a);
  const worst = ab.marginDb <= ba.marginDb ? ab : ba;
  const asymmetryDb = Math.abs(ab.marginDb - ba.marginDb);

  if (worst.marginDb < 0) {
    score -= Math.min(60, 18 + Math.abs(worst.marginDb) * 1.8);
    reasons.push(`Worst-case receive margin is ${worst.marginDb.toFixed(1)} dB â€” below receiver sensitivity, so the link is effectively down.`);
  } else if (worst.marginDb < 8) {
    score -= 28;
    reasons.push(`Worst-case receive margin is only ${worst.marginDb.toFixed(1)} dB â€” poor fade tolerance and intermittent performance.`);
  } else if (worst.marginDb < 18) {
    score -= 14;
    reasons.push(`Worst-case receive margin is ${worst.marginDb.toFixed(1)} dB â€” usable but only moderate reliability.`);
  } else {
    reasons.push(`Worst-case receive margin is ${worst.marginDb.toFixed(1)} dB â€” strong bidirectional link budget.`);
  }

  if (asymmetryDb > 12) {
    score -= 8;
    reasons.push(`Link budget asymmetry is ${asymmetryDb.toFixed(1)} dB between directions, which can hurt duplex reliability.`);
  }

  if (severeBlockedLos) {
    score = Math.min(score, 3);
  }

  score = Math.max(0, Math.min(100, score));
  return {
    score,
    label: linkQualityLabel(score),
    reasons,
    terrain: los.hasTerrain ? los : null,
    distKm,
    pathLossDb: isSatcom ? null : worst.pathLossDb,
    rssiDbm: worst.rssiDbm,
    marginDb: worst.marginDb,
    forwardRssiDbm: ab.rssiDbm,
    reverseRssiDbm: ba.rssiDbm,
    forwardMarginDb: ab.marginDb,
    reverseMarginDb: ba.marginDb,
    isSatcom,
  };
}

// Returns a CSS class encoding the link medium type (dash pattern)
function linkTypeClass(emA, emB) {
  const wfA = (emA?.ext?.waveform || emA?.waveform || "").toUpperCase();
  const wfB = (emB?.ext?.waveform || emB?.waveform || "").toUpperCase();
  const SATCOM_WF = ["MUOS", "STARSHIELD", "INMARSAT", "VIASAT", "BLOS", "SATCOM", "WGS", "AEHF", "LINK 182"];
  const MANET_WF  = ["SRW", "ANW2", "WAVE", "MESH", "MANET", "WIFI", "802.11", "TRELLISWARE"];
  const satA = emA?.ext?.satcomEnabled || SATCOM_WF.some(w => wfA.includes(w));
  const satB = emB?.ext?.satcomEnabled || SATCOM_WF.some(w => wfB.includes(w));
  if (satA && satB) return "topo-link-type-satcom";
  if (MANET_WF.some(w => wfA.includes(w) || wfB.includes(w))
      || emA?.ext?.isManet || emB?.ext?.isManet) return "topo-link-type-mesh";
  const fMhz = ((emA?.frequencyMHz || 0) + (emB?.frequencyMHz || 0)) / 2;
  if (fMhz >= 300)  return "topo-link-type-uhf";
  if (fMhz >= 30)   return "topo-link-type-vhf";
  if (fMhz >= 3)    return "topo-link-type-hf";
  return "topo-link-type-vhf"; // fallback
}

